/* AUTO-GENERATED — Washington Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["WA"] = {"code":"WA","name":"Washington","agency":"Washington DOL","agencyShort":"DOL","handbook":"https://dol.wa.gov/driver-licenses-and-permits/commercial-driver-licenses-cdl/cdl-training-and-testing/commercial-driver-guides","links":{},"en":[{"q":"What is the maximum legal outside width of a vehicle or its load on Washington public highways, without a special permit?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"answer":1,"explanation":"RCW 46.44.010 limits the total outside width of a vehicle or its load to 8 feet 6 inches (102 inches), excluding certain safety devices and mirrors. This is also the federal standard. Source: RCW 46.44.010; WSDOT Commercial Vehicle Guide.","handbook":"","hbref":""},{"q":"What is the maximum legal height, including load, for a vehicle on Washington highways without a special permit?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"answer":1,"explanation":"RCW 46.44.020 makes it unlawful for a vehicle, unladen or with load, to exceed a height of 14 feet above the surface on which it stands. Source: RCW 46.44.020.","handbook":"","hbref":""},{"q":"What is the maximum legal length of a single vehicle (not a combination) on Washington highways without a permit?","options":["35 feet","40 feet","45 feet","48 feet"],"answer":1,"explanation":"RCW 46.44.030 sets the general maximum length of a single vehicle at 40 feet, with exceptions allowing buses, motor homes, and travel trailers up to 46 feet. Source: RCW 46.44.030.","handbook":"","hbref":""},{"q":"In a tractor-semitrailer combination on Washington highways, what is the maximum allowable length of the semitrailer alone (no permit)?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"RCW 46.44.030 prohibits operating a tractor-semitrailer with a semitrailer length exceeding 53 feet. Source: RCW 46.44.030.","handbook":"","hbref":""},{"q":"What is the maximum gross load Washington allows on any single axle without a special permit?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":1,"explanation":"RCW 46.44.041 prohibits a gross load on any single axle in excess of 20,000 pounds. Source: RCW 46.44.041; WSDOT 'Legal vehicle weight'.","handbook":"","hbref":""},{"q":"What is the standard maximum gross load on a tandem axle group in Washington (no permit)?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"Under RCW 46.44.041 and the federal standard adopted in Washington, a tandem axle group is limited to 34,000 pounds. Source: RCW 46.44.041.","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight permitted on the Interstate highway system in Washington without a permit?","options":["80,000 pounds","90,000 pounds","100,000 pounds","105,500 pounds"],"answer":0,"explanation":"On the Interstate system, federal law adopted by Washington caps gross weight at 80,000 pounds. Higher figures apply only on certain non-Interstate state highways. Source: RCW 46.44.041; 23 CFR 658.17; WSDOT.","handbook":"","hbref":""},{"q":"Under Washington's weight table, what is the maximum total gross vehicle weight that can be legally carried on non-Interstate state highways with sufficient axles and wheelbase (no overweight permit)?","options":["80,000 pounds","98,000 pounds","105,500 pounds","120,000 pounds"],"answer":2,"explanation":"RCW 46.44.041's wheelbase/axle weight table permits up to 105,500 pounds gross on non-Interstate highways when the axle spacing and count qualify. The Interstate system remains capped at 80,000 pounds. Source: RCW 46.44.041; WSDOT.","handbook":"","hbref":""},{"q":"Which formula does Washington use to determine the maximum weight allowed on a group of consecutive axles?","options":["W = 500[LN/(N-1) + 12N + 36]","W = 1000(L + N + 12)","W = 700[LN/(N+1) + 10N]","W = 250[LN + 24N + 40]"],"answer":0,"explanation":"RCW 46.44.041 incorporates the federal bridge formula W = 500[LN/(N-1) + 12N + 36], where L is the distance between the extreme axles of the group and N is the number of axles. Source: RCW 46.44.041; FHWA Bridge Formula.","handbook":"","hbref":""},{"q":"In the Washington bridge formula W = 500[LN/(N-1) + 12N + 36], what does 'N' represent?","options":["The number of axles in the group","The distance in feet between the extreme axles","The net weight of the load in tons","The number of tires on the drive axle"],"answer":0,"explanation":"In the bridge formula adopted by RCW 46.44.041, N is the number of axles in the group being considered and L is the spacing in feet between the extreme axles of that group. Source: RCW 46.44.041; FHWA.","handbook":"","hbref":""},{"q":"In Washington, the gross weight allowed on a single axle is also limited by tire width. What is the maximum weight per inch of tire width?","options":["500 pounds per inch","550 pounds per inch","600 pounds per inch","700 pounds per inch"],"answer":2,"explanation":"RCW 46.44.042 limits axle weight to 600 pounds per inch of tire width. Gross axle weight is governed by the most restrictive of tire size, axle weight, and the weight table. Source: RCW 46.44.042; WSDOT.","handbook":"","hbref":""},{"q":"Two consecutive sets of tandem axles may each carry 34,000 pounds in Washington only if the distance between the first and last axles of the two sets is at least how far apart?","options":["30 feet","34 feet","36 feet","40 feet"],"answer":2,"explanation":"RCW 46.44.041 allows two consecutive sets of tandem axles to carry 34,000 pounds each only when the overall distance between the first and last axles of the sets is 36 feet or more. Source: RCW 46.44.041.","handbook":"","hbref":""},{"q":"A carrier needs to move a load that exceeds Washington's legal size or weight limits. Who issues the special permit for movement on state highways?","options":["The Washington State Patrol","The Department of Licensing","The Washington State Department of Transportation (WSDOT)","The county sheriff's office"],"answer":2,"explanation":"RCW 46.44.090 authorizes WSDOT to issue special oversize/overweight permits for state highways; local authorities issue them for roads under their jurisdiction. Source: RCW 46.44.090; WSDOT Commercial Vehicle Permits.","handbook":"","hbref":""},{"q":"Under RCW 46.44.090, what must an applicant generally demonstrate to obtain a special oversize or overweight permit in Washington?","options":["A written application and good cause shown","A federal exemption letter","Proof of $1 million in cargo insurance","A clean driving record for five years"],"answer":0,"explanation":"RCW 46.44.090 provides that WSDOT or local authorities may issue a special permit upon written (or electronic) application and good cause being shown. Source: RCW 46.44.090.","handbook":"","hbref":""},{"q":"When is a Washington oversize/overweight special permit required?","options":["Only when the vehicle is empty","Whenever the vehicle or load exceeds the legal limits in RCW 46.44.010 through 46.44.041","Only on toll roads","Only for vehicles over 53 feet long"],"answer":1,"explanation":"RCW 46.44.090 requires a special permit to move a vehicle or load exceeding the maximums set in RCW 46.44.010, .020, .030, .034, and .041. A non-divisible load that cannot be reduced is required to be permitted rather than split. Source: RCW 46.44.090.","handbook":"","hbref":""},{"q":"Washington allows logging trucks to obtain a special 'log tolerance' permit. How much extra gross weight does this permit allow over the otherwise legal maximum?","options":["Up to 4,000 pounds","Up to 6,800 pounds","Up to 10,000 pounds","Up to 12,500 pounds"],"answer":1,"explanation":"RCW 46.44.047 permits logging trucks hauling logs to exceed the maximum legal gross weight (68,000 pounds when fully licensed) by not more than 6,800 pounds under a special log tolerance permit. Source: RCW 46.44.047.","handbook":"","hbref":""},{"q":"What is the annual fee for a Washington log tolerance special permit when issued for the full 12-month period?","options":["$25","$50","$100","$120"],"answer":1,"explanation":"RCW 46.44.047 sets the log tolerance special permit fee at $50 for the 12-month period beginning April 1, with reduced prorated fees if issued later in the permit year. Source: RCW 46.44.047.","handbook":"","hbref":""},{"q":"In a Washington combination of a tractor and two trailers (a 'double'), what is the maximum combined length of the two trailers without a permit?","options":["56 feet","61 feet","65 feet","68 feet"],"answer":1,"explanation":"RCW 46.44.030 limits a tractor with two trailers so that the combined length of the trailers does not exceed 61 feet. Source: RCW 46.44.030.","handbook":"","hbref":""},{"q":"A WSDOT self-issued single-trip oversize permit allows movement up to which maximum dimensions and weight before a more specialized permit is needed?","options":["12 ft wide, 14 ft high, 100,000 lb","14 ft wide, 15 ft high, 150,000 lb","16 ft wide, 16 ft high, 200,000 lb","20 ft wide, 18 ft high, 250,000 lb"],"answer":2,"explanation":"WSDOT's self-issue permit system covers loads up to 16 feet wide, 16 feet high, 125 feet of load length, and 200,000 pounds; larger moves require a permit issued directly by the WSDOT permit office. Source: WSDOT Commercial Vehicle Permits, 'Self-issue a permit.'","handbook":"","hbref":""},{"q":"Which agency's regulations cap the gross weight at 80,000 pounds on the Interstate system, a limit Washington must follow to keep federal highway funding?","options":["The Environmental Protection Agency","The Federal Highway Administration (FHWA) under 23 CFR Part 658","The Federal Motor Carrier Safety Administration medical division","The Interstate Commerce Commission"],"answer":1,"explanation":"The 80,000-pound Interstate gross weight cap and the bridge formula come from FHWA regulations at 23 CFR Part 658, which Washington adopts in RCW 46.44.041 for the Interstate system. Higher non-Interstate limits reflect Washington's grandfather rights. Source: 23 CFR 658.17; RCW 46.44.041.","handbook":"","hbref":""},{"q":"In Washington, which CDL class is required to drive a combination vehicle with a gross combination weight rating (GCWR) of 26,001 pounds or more, where the towed unit(s) exceed 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Washington requires a Class A CDL for a combination vehicle with a GCWR of 26,001 pounds or more when the vehicle(s) being towed have a GVWR over 10,000 pounds. Source: WA DOL, Types of CDLs / Washington State Commercial Driver Guide.","handbook":"","hbref":""},{"q":"Under Washington rules, a Class B CDL covers which type of vehicle?","options":["Any single vehicle with a GVWR of 26,001 pounds or more (and towing a unit 10,000 lbs or less)","A combination vehicle towing a trailer over 10,000 pounds","Only vehicles carrying 16 or more passengers","Only vehicles placarded for hazardous materials"],"answer":0,"explanation":"A Class B CDL in Washington covers any single vehicle with a GVWR of 26,001 pounds or more, including such a vehicle towing a trailer rated at 10,000 pounds or less. Combinations with a heavier towed unit require Class A. Source: WA DOL, Types of CDLs.","handbook":"","hbref":""},{"q":"A Washington Class C CDL is required when a vehicle does not meet Class A or B weight thresholds but is designed to transport at least how many people (including the driver), or transports hazardous materials requiring placards?","options":["16 or more","12 or more","20 or more","10 or more"],"answer":0,"explanation":"A Class C CDL applies to vehicles that carry 16 or more occupants including the driver, or that transport hazardous materials requiring placards, when the vehicle is too light for Class A or B. Source: WA DOL, Types of CDLs.","handbook":"","hbref":""},{"q":"Which endorsement does Washington require for a driver pulling sets of double or triple trailers?","options":["T endorsement","N endorsement","H endorsement","X endorsement"],"answer":0,"explanation":"The T (Doubles/Triples) endorsement is required in Washington for drivers pulling sets of double or triple trailers, and is obtained by passing a knowledge test only. Source: WA DOL, Endorsements and restrictions.","handbook":"","hbref":""},{"q":"In Washington, the N (Tank Vehicle) endorsement is required for a CMV designed to transport liquid or gaseous materials in a tank with an individual rated capacity of more than 119 gallons and an aggregate rated capacity of at least how many gallons?","options":["1,000 gallons","500 gallons","750 gallons","1,500 gallons"],"answer":0,"explanation":"Washington requires the N endorsement for any CMV designed to haul liquid/gaseous materials in a tank with an individual rated capacity over 119 gallons and an aggregate rated capacity of 1,000 gallons or more. Source: WA DOL, Endorsements and restrictions.","handbook":"","hbref":""},{"q":"Which Washington CDL endorsement is required to drive a passenger vehicle designed to carry 16 or more people (including the driver)?","options":["P endorsement","S endorsement","T endorsement","N endorsement"],"answer":0,"explanation":"The P (Passenger) endorsement is required in Washington for drivers of passenger vehicles designed to carry 16 or more people including the driver. Source: WA DOL, Endorsements and restrictions.","handbook":"","hbref":""},{"q":"In Washington, the S (School Bus) endorsement is required to drive what?","options":["Any size school bus used to transport children to/from school or school activities","Only school buses carrying 16 or more children","Only diesel-powered school buses","Only school buses operated across county lines"],"answer":0,"explanation":"Washington requires the S endorsement to drive any size school bus regularly used to transport children to and from school or in connection with school activities. Source: WA DOL, Endorsements and restrictions.","handbook":"","hbref":""},{"q":"Before obtaining a HazMat (H) endorsement in Washington, a driver must complete a federal security threat assessment administered by which agency, including fingerprinting?","options":["Transportation Security Administration (TSA)","Washington State Patrol (WSP)","Federal Motor Carrier Safety Administration (FMCSA)","Department of Licensing (DOL) only"],"answer":0,"explanation":"Washington requires HazMat applicants to be fingerprinted and pass a TSA Hazardous Materials Endorsement Threat Assessment before the H endorsement is issued. Source: WA DOL, Hazardous materials endorsement (hazmat); TSA HTAP.","handbook":"","hbref":""},{"q":"A HazMat (H) endorsement on a Washington CDL must be renewed, with a new TSA threat assessment, at least how often?","options":["Every 5 years","Every 2 years","Every 8 years","Every 10 years"],"answer":0,"explanation":"Federal rules applied in Washington require renewal of the HazMat endorsement, including new fingerprints and a new TSA background check, at least every 5 years. Source: WA DOL, Hazmat endorsement; TSA HTAP.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Washington CDL for INTRASTATE (within-state) driving only?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"Washington allows a driver who is at least 18 to obtain a CDL for intrastate commerce; interstate operation requires age 21. Source: WA DOL, Getting a commercial driver license (CDL).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Washington CDL that allows driving in INTERSTATE commerce (across state lines)?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"A driver must be at least 21 years old to operate a commercial motor vehicle across state lines under Washington and federal rules. Source: WA DOL, Getting a commercial driver license (CDL).","handbook":"","hbref":""},{"q":"In Washington, how long is a Commercial Learner's Permit (CLP) valid from the date it is issued?","options":["180 days","90 days","1 year","60 days"],"answer":0,"explanation":"A Washington CLP is valid for 180 days from the date of issue, and may be renewed once within 30 days of expiration for an additional 180 days. Source: WA DOL, Commercial learner's permit (CLP).","handbook":"","hbref":""},{"q":"After being issued an original Washington CLP, how long must a driver wait before taking the CDL skills test?","options":["14 calendar days","7 calendar days","30 calendar days","10 business days"],"answer":0,"explanation":"Federal rules adopted by Washington require a 14-calendar-day hold after an original or upgraded CLP is issued before the driver may take the skills test. Source: WA DOL, Commercial learner's permit (CLP).","handbook":"","hbref":""},{"q":"While driving on a Washington CLP, the supervising CDL holder seated next to the permit holder must hold a valid CDL with the proper class/endorsements and have at least how much experience?","options":["2 years in that vehicle type and 5 total years of driving","1 year of CDL driving","6 months in that vehicle type","10 total years of driving"],"answer":0,"explanation":"Washington requires the accompanying CDL holder to have the proper endorsements, at least 2 years of experience in that type of vehicle, and at least 5 total years of driving experience. Source: WA DOL, Commercial learner's permit (CLP).","handbook":"","hbref":""},{"q":"Which document category is NOT separately required when applying for a Washington CDL?","options":["Proof you own a commercial vehicle","Proof of identity / date of birth","Social Security number","Proof of U.S. citizenship or lawful permanent residency"],"answer":0,"explanation":"Washington requires proof of identity, a Social Security number, proof of residency, and proof of U.S. citizenship or lawful permanent residence (lawful presence); ownership of a commercial vehicle is not required. Source: WA DOL, CDL-approved documents.","handbook":"","hbref":""},{"q":"To prove lawful presence for a Washington CDL, an applicant must present which of the following?","options":["One federally approved document such as a U.S. passport, birth certificate, or Permanent Resident Card (original, not a photocopy)","Any two utility bills","A notarized statement of citizenship","A voter registration card only"],"answer":0,"explanation":"Washington requires one acceptable original document proving U.S. citizenship or lawful permanent residency, such as a U.S. passport, government-issued birth certificate, or Permanent Resident Card; photocopies are not accepted. Source: WA DOL, CDL-approved documents.","handbook":"","hbref":""},{"q":"Entry-Level Driver Training (ELDT) became mandatory in Washington for applicants who obtain a CLP on or after which date?","options":["February 7, 2022","January 1, 2020","September 1, 2021","July 1, 2023"],"answer":0,"explanation":"Federal ELDT rules, applied in Washington, require training from a registered provider for applicants who obtain a CLP on or after February 7, 2022. Source: FMCSA Entry-Level Driver Training; WA DOL, CDL training requirements.","handbook":"","hbref":""},{"q":"Under ELDT rules in Washington, a driver seeking which credential must complete training from a provider listed on the FMCSA Training Provider Registry before testing?","options":["First-time Class A or Class B CDL, or a first-time P, S, or H endorsement","Only the T (doubles/triples) endorsement","Only the N (tank) endorsement","Renewal of an existing CDL with no class change"],"answer":0,"explanation":"ELDT applies to first-time Class A and Class B CDL applicants (and B-to-A upgrades) and to first-time passenger (P), school bus (S), and HazMat (H) endorsement applicants; the provider must be on the FMCSA Training Provider Registry. Source: FMCSA ELDT Applicability.","handbook":"","hbref":""},{"q":"When applying for a Washington CDL, the medical self-certification category 'Non-Excepted Interstate' means the driver:","options":["Operates in interstate commerce and must maintain a valid DOT medical examiner's certificate","Operates only within Washington and is exempt from all medical requirements","Operates in interstate commerce but is exempt from the medical certificate","Drives only on private property and needs no certificate"],"answer":0,"explanation":"Of the four self-certification categories, Non-Excepted Interstate means the driver operates across state lines and must hold and maintain a valid DOT medical examiner's certificate. Source: FMCSA medical self-certification categories; WA DOL, Getting a CDL.","handbook":"","hbref":""},{"q":"Which of the following is one of the four CDL medical self-certification categories a Washington applicant must choose from?","options":["Excepted Intrastate","Provisional Interstate","Conditional Intrastate","Restricted Interstate"],"answer":0,"explanation":"The four FMCSA self-certification categories used in Washington are Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate. Source: FMCSA medical self-certification; WA DOL, Getting a CDL.","handbook":"","hbref":""},{"q":"In Washington, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.04","0.08","0.02","0.10"],"answer":0,"explanation":"Washington law (and the Washington CDL Guide, following 49 CFR 383.51/392.5) makes it illegal to operate a CMV with a BAC of 0.04 or more — half the 0.08 limit for non-commercial drivers. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Washington's implied consent law, by holding a CDL and operating a vehicle a driver is deemed to have agreed to do what if a law enforcement officer has reasonable grounds to suspect impairment?","options":["Submit to a breath or blood test for alcohol or drugs","Pay a fixed cash bond at the roadside","Surrender the CDL permanently on the spot","Complete a 12-hour alcohol education class first"],"answer":0,"explanation":"Washington's implied-consent statute (RCW 46.20.308) means anyone driving in the state has consented to chemical testing (breath or blood) when an officer has reasonable grounds to suspect impaired driving. Source: RCW 46.20.308; Washington DOL CDL Guide.","handbook":"","hbref":""},{"q":"A Washington CDL holder is convicted of a first DUI while driving a non-placarded commercial vehicle. What is the disqualification period for this first major offense?","options":["1 year","3 years","60 days","6 months"],"answer":0,"explanation":"A first major offense (including DUI, BAC 0.04+, or test refusal) disqualifies a CDL for 1 year. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"In Washington, how long is the CDL disqualification for a first major offense (such as DUI or BAC 0.04+) if the driver was transporting placarded hazardous materials at the time?","options":["3 years","1 year","5 years","120 days"],"answer":0,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Washington for a second major offense (for example, a second DUI or second BAC 0.04+ conviction)?","options":["Lifetime (life)","10 years","5 years","3 years"],"answer":0,"explanation":"A second major offense results in a lifetime CDL disqualification; Washington notes you cannot re-qualify from a lifetime disqualification. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A Washington CDL holder refuses to submit to a breath or blood test when lawfully requested by an officer while operating a non-placarded vehicle. What is the disqualification period for this first refusal?","options":["1 year","90 days","3 years","60 days"],"answer":0,"explanation":"Refusing the chemical test is treated as a major offense, disqualifying the CDL for 1 year on a first refusal (3 years if placarded with hazardous materials). Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"In Washington, refusing a breath or blood test is a major offense that counts toward lifetime disqualification. A test refusal followed later by a separate DUI conviction would result in what disqualification?","options":["Lifetime disqualification (two major offenses)","Only a 1-year disqualification total","A 120-day disqualification","No additional disqualification beyond the first"],"answer":0,"explanation":"Both a test refusal and a DUI are major offenses; two major offenses from separate incidents trigger a lifetime CDL disqualification. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period (in separate incidents) trigger the shortest serious-violation CDL disqualification in Washington?","options":["2 serious violations","3 serious violations","1 serious violation","4 serious violations"],"answer":0,"explanation":"Two serious traffic violations arising from separate incidents within 3 years trigger a 60-day disqualification; the first single serious violation alone does not disqualify. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Washington for two serious traffic violations committed in separate incidents within a 3-year period?","options":["60 days","120 days","30 days","90 days"],"answer":0,"explanation":"Two serious traffic violations within 3 years (separate incidents) result in a 60-day CDL disqualification. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Washington for three serious traffic violations committed in separate incidents within a 3-year period?","options":["120 days","60 days","1 year","180 days"],"answer":0,"explanation":"Three serious traffic violations within 3 years (separate incidents) result in a 120-day CDL disqualification. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"How far above the posted speed limit must a Washington CDL holder be cited to have it count as a 'serious traffic violation'?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","25 mph or more over the limit"],"answer":0,"explanation":"Speeding 15 mph or more above the posted limit is listed as a serious traffic violation for CDL purposes in Washington. Source: Washington DOL serious traffic offenses page; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a Washington CDL holder?","options":["Following too closely (tailgating)","Parking in a no-parking zone","A burned-out license plate light","Failure to display a registration tab"],"answer":0,"explanation":"Following too closely is on Washington's serious-traffic-violation list (along with reckless driving, improper lane change, speeding 15+ over, and texting/phone use in a CMV). Equipment and parking infractions are not. Source: Washington DOL serious traffic offenses page; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Washington's rule, how is texting while driving a commercial motor vehicle classified for CDL disqualification purposes?","options":["A serious traffic violation","A major offense","An out-of-service order violation","A non-reportable equipment violation"],"answer":0,"explanation":"Texting while driving a CMV (and using a handheld phone while driving a CMV) is a serious traffic violation, so two within 3 years bring a 60-day disqualification. Source: Washington DOL serious traffic offenses page; FMCSA 392.80/392.82.","handbook":"","hbref":""},{"q":"Federal rules adopted in Washington prohibit a CMV driver from using a handheld mobile phone while driving. What is the approximate maximum driver civil penalty for violating this handheld/texting restriction?","options":["Up to about $2,750","Up to about $250","Up to about $500","Up to about $1,000"],"answer":0,"explanation":"The federal restriction on handheld phone use and texting by CMV drivers (FMCSA 392.80/392.82), enforced in Washington, carries driver civil penalties of up to roughly $2,750. Source: FMCSA 392.82; Washington DOL CDL Guide.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification period in Washington for a first conviction of a railroad-highway grade crossing violation while operating a CMV?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation in a CMV disqualifies the CDL for no less than 60 days. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification period in Washington for a second railroad-highway grade crossing violation within a 3-year period?","options":["120 days","60 days","1 year","180 days"],"answer":0,"explanation":"A second railroad-grade-crossing violation within 3 years disqualifies the CDL for no less than 120 days. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification period in Washington for a third railroad-highway grade crossing violation within a 3-year period?","options":["1 year","120 days","60 days","3 years"],"answer":0,"explanation":"A third railroad-grade-crossing violation within 3 years disqualifies the CDL for no less than 1 year. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the disqualification period in Washington for a first violation of an out-of-service (OOS) order while operating a non-hazmat CMV?","options":["No less than 180 days and no more than 1 year","No less than 60 days and no more than 120 days","No less than 30 days and no more than 90 days","Lifetime disqualification"],"answer":0,"explanation":"A first OOS-order violation disqualifies the CDL for no less than 180 days and no more than 1 year for a non-hazmat vehicle. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"A Washington driver commits a first out-of-service order violation while hauling placarded hazardous materials or carrying 16 or more passengers. What is the disqualification range?","options":["No less than 180 days and no more than 2 years","No less than 180 days and no more than 1 year","No less than 60 days and no more than 120 days","No less than 1 year and no more than 5 years"],"answer":0,"explanation":"A first OOS-order violation while hauling placarded hazmat or carrying 16+ passengers disqualifies the CDL for no less than 180 days and no more than 2 years. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"What is the disqualification period in Washington for a second out-of-service order violation (non-hazmat) within a 10-year period, arising from separate incidents?","options":["No less than 2 years and no more than 5 years","No less than 180 days and no more than 1 year","No less than 1 year and no more than 3 years","Lifetime disqualification"],"answer":0,"explanation":"A second OOS-order violation (non-hazmat) in separate incidents within 10 years disqualifies the CDL for no less than 2 years and no more than 5 years. Source: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"In Washington, what is the maximum speed limit for a vehicle over 10,000 pounds gross weight (or any combination vehicle) on a highway, even where cars may legally travel faster?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":1,"explanation":"Washington caps the speed for vehicles over 10,000 lbs gross weight and all vehicle combinations (except auto stages) at 60 mph, regardless of a higher posted limit for cars. Source: RCW 46.61.410.","handbook":"","hbref":""},{"q":"On a limited-access Washington freeway with three or more lanes in your direction, where may a truck or combination over 10,000 pounds NOT be driven (except when preparing for a legal left turn)?","options":["The far right lane","Any center lane","The left-hand lane","A high-occupancy vehicle (HOV) lane"],"answer":2,"explanation":"No vehicle towing a trailer and no vehicle or combination over 10,000 lbs may be driven in the left-hand lane of a limited-access roadway with three or more lanes in one direction, except to prepare for a legal left turn. An HOV lane is not counted as the left-hand lane. Source: RCW 46.61.100.","handbook":"","hbref":""},{"q":"Approaching a Washington railroad grade crossing, a driver of a school bus or a placarded hazardous-materials vehicle must stop within how many feet of the nearest rail?","options":["Within 50 feet but not less than 15 feet","Within 75 feet but not less than 25 feet","Within 40 feet but not less than 10 feet","Within 100 feet but not less than 30 feet"],"answer":0,"explanation":"Washington requires the driver of a school/passenger bus, passenger-carrying commercial vehicle, or hazmat cargo tank to stop before the stop line, otherwise within 50 feet but not less than 15 feet from the nearest rail. Source: RCW 46.61.350.","handbook":"","hbref":""},{"q":"After stopping at a railroad crossing, what does Washington law require of a bus or placarded HazMat driver while crossing the tracks?","options":["Cross in a gear that requires no gear change while on the tracks, and not shift gears while crossing","Downshift to the lowest gear at the midpoint of the tracks","Engage the differential lock before crossing the tracks","Cross only after sounding the horn three times on the tracks"],"answer":0,"explanation":"Washington law states the driver must cross only in a gear that will not require changing gears while traversing the crossing and may not shift gears while crossing the tracks. Source: RCW 46.61.350.","handbook":"","hbref":""},{"q":"Under Washington's Move Over law, an 'emergency or work zone' is defined as the adjacent lanes of the roadway extending how far before and after a stationary emergency or work vehicle displaying warning signals?","options":["100 feet","150 feet","200 feet","300 feet"],"answer":2,"explanation":"Washington defines the emergency or work zone as the adjacent lanes 200 feet before and after a stationary authorized emergency vehicle, tow truck, police, utility, or highway maintenance vehicle using its warning signals. Source: RCW 46.61.212.","handbook":"","hbref":""},{"q":"On a Washington highway with fewer than four lanes, if a driver cannot safely change lanes away from a stopped emergency/work vehicle, the driver must reduce speed to at least how much below the posted speed limit (where the limit is 60 mph or less)?","options":["5 mph below the posted limit","10 mph below the posted limit","15 mph below the posted limit","20 mph below the posted limit"],"answer":1,"explanation":"When a lane change is unsafe, Washington's Move Over law requires reducing speed to at least 10 mph below the posted limit; where the posted limit exceeds 60 mph, the driver must instead slow to no more than 50 mph. Source: RCW 46.61.212.","handbook":"","hbref":""},{"q":"Meeting a stopped school bus that is displaying red flashing lights while traveling in the OPPOSITE direction, on which Washington roadway are you NOT required to stop?","options":["A two-lane undivided highway","A highway divided into separate roadways by a median or barrier","Any city street with a posted speed of 25 mph","A two-lane road with a center two-way left-turn lane"],"answer":1,"explanation":"On a highway divided into separate roadways (per RCW 46.61.150), or one with three or more marked lanes, a driver meeting a school bus going the opposite direction need not stop. On undivided two-lane roads you must stop. Source: RCW 46.61.370.","handbook":"","hbref":""},{"q":"In addition to the divided-highway exception, on what other type of Washington roadway may you continue past an oncoming, stopped school bus (going the opposite direction) without stopping?","options":["A roadway with three or more marked traffic lanes","Any roadway posted at 45 mph or higher","A roadway with paved shoulders at least 8 feet wide","A roadway with a single center turn lane only"],"answer":0,"explanation":"Washington's school-bus law adds that drivers meeting a bus proceeding in the opposite direction on a highway with three or more marked traffic lanes need not stop. Source: RCW 46.61.370.","handbook":"","hbref":""},{"q":"A Washington truck driver stops on the shoulder of a two-lane, two-way road. After putting on the four-way flashers, within how many minutes must the required warning devices (triangles) be placed?","options":["5 minutes","10 minutes","15 minutes","30 minutes"],"answer":1,"explanation":"A CMV stopped on a roadway or shoulder must place emergency warning devices within 10 minutes, after first activating the hazard flashers. Source: Washington CDL Manual; 49 CFR 392.22 (adopted in Washington).","handbook":"","hbref":""},{"q":"On a two-lane, two-way Washington road, where should the three reflective triangles be placed for a stopped CMV?","options":["All three behind the vehicle at 10, 50, and 100 feet","Within 10 ft on the traffic side, 100 ft to the rear, and 100 ft to the front","At 10, 100, and 200 feet, all toward approaching traffic","One on the roof and two at 50 feet front and rear"],"answer":1,"explanation":"On a two-way road, place one triangle within 10 ft of the vehicle on the traffic side, one about 100 ft behind, and one about 100 ft ahead, so traffic from both directions is warned. Source: Washington CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a Washington divided or one-way highway, where should a stopped CMV's three warning triangles be placed?","options":["At 10, 100, and 200 feet toward the approaching traffic behind the vehicle","At 10, 50, and 100 feet toward approaching traffic","One at the front and two at 100 feet to the rear","All three at 200 feet behind the vehicle"],"answer":0,"explanation":"On a divided or one-way highway, place the triangles toward approaching traffic at 10 feet, 100 feet, and 200 feet from the vehicle. Source: Washington CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Washington requires vehicles and combinations over 10,000 pounds GVWR to carry tire chains on designated mountain-pass routes during which period each year?","options":["October 1 to March 1","November 1 to April 1","December 1 to March 31","November 15 to March 15"],"answer":1,"explanation":"From November 1 to April 1, vehicles and combinations over 10,000 lbs GVWR must carry chains on designated chain routes (e.g., I-90, US 2 Stevens Pass, US 12 White Pass), regardless of current conditions. Source: WSDOT commercial-vehicle chain requirements; WAC 204-24-050.","handbook":"","hbref":""},{"q":"How many extra tire chains must a Washington commercial vehicle over 10,000 pounds GVWR carry on designated chain routes during the chain-carry season?","options":["At least one extra chain","At least two extra chains","At least four extra chains","No extras if drive tires are already chained"],"answer":1,"explanation":"Washington requires these vehicles to carry at least two extra tire chains during the November 1 to April 1 period so a broken or additional-axle chain can be replaced. Source: WSDOT chain requirements; WAC 204-24-050.","handbook":"","hbref":""},{"q":"On a multilane Washington roadway, what does state law say about a slower vehicle that continuously occupies the left lane?","options":["It is permitted if the vehicle is at the speed limit","It is a traffic infraction to drive continuously in the left lane when it impedes other traffic","It is allowed only for vehicles under 10,000 pounds","It is allowed if the right lane is occupied by trucks"],"answer":1,"explanation":"Washington's keep-right law makes it a traffic infraction to drive continuously in the left lane of a multilane roadway when doing so impedes the flow of other traffic. Source: RCW 46.61.100.","handbook":"","hbref":""},{"q":"The penalty for illegally passing a stopped Washington school bus that is displaying its red lights and stop paddle is described in statute as:","options":["A fixed $250 fine that may be reduced by the court","Twice the base penalty, which may not be waived, reduced, or suspended","A written warning for a first offense","License suspension only, with no monetary penalty"],"answer":1,"explanation":"A driver who unlawfully passes a stopped school bus is assessed a monetary penalty equal to twice the base penalty under RCW 46.63.110, and it may not be waived, reduced, or suspended. Source: RCW 46.61.370.","handbook":"","hbref":""},{"q":"When the Washington State Patrol posts 'Chains Required' for vehicles over 10,000 pounds, do studded tires satisfy the requirement?","options":["Yes, studded tires count as chains","Yes, but only on the drive axle","No; chains must be installed even over studded tires","Only all-wheel-drive vehicles are exempt"],"answer":2,"explanation":"Studded tires do not satisfy a posted chain requirement in Washington; drivers must install chains (over studded tires if equipped) to proceed past a posted chain-up point. Source: WSDOT/WSP winter chain requirements.","handbook":"","hbref":""},{"q":"In Washington, a single oversize/overweight permit is generally required once a vehicle or load exceeds which of these legal dimension limits?","options":["8 feet 6 inches wide, 14 feet high, or applicable length limits","10 feet wide, 13 feet 6 inches high, or 48 feet long","9 feet wide, 15 feet high, or 60 feet long","8 feet wide, 12 feet high, or 35 feet long"],"answer":0,"explanation":"Washington's legal limits are generally 8 ft 6 in wide and 14 ft high; exceeding width, height, or the applicable length limits requires a WSDOT oversize permit. Source: WSDOT Commercial Vehicle Services oversize/overweight permits.","handbook":"","hbref":""},{"q":"Which mountain highway is a designated chain/traction route in Washington where commercial-vehicle chain requirements are commonly enforced?","options":["I-90 over Snoqualmie Pass","I-5 through downtown Seattle","I-405 around Bellevue","SR 520 floating bridge"],"answer":0,"explanation":"I-90 over Snoqualmie Pass (North Bend to Ellensburg) is a primary designated chain route, along with US 2 Stevens Pass and US 12 White Pass; urban interstates like I-5, I-405, and SR 520 are not mountain chain routes. Source: WSDOT mountain pass chain requirements.","handbook":"","hbref":""},{"q":"A Washington runaway truck escape ramp on a steep grade is typically constructed to stop a heavy vehicle by:","options":["A loose-gravel or soft-sand bed, sometimes on an upgrade, that increases resistance the farther you travel","A steel guardrail net stretched across the lane","A downhill paved chute that lets the truck coast to a stop","A water-filled trough that floats the tires"],"answer":0,"explanation":"Washington escape ramps use loose gravel or soft sand, sometimes with an uphill grade; resistance increases the farther the truck travels in, helping bring it to a stop. Source: Washington CDL Manual, mountain driving / escape ramps.","handbook":"","hbref":""},{"q":"Under Washington's Move Over law on a highway with four or more lanes, the driver's FIRST duty when approaching a stopped emergency/work vehicle with flashing lights is to:","options":["Stop completely in the lane until the vehicle clears","Proceed with caution, reduce speed, and change lanes away from it if it is safe to do so","Sound the horn and maintain the posted speed","Move onto the shoulder and pass on the right"],"answer":1,"explanation":"On highways of four or more lanes, drivers must proceed with caution, reduce speed, and yield by moving over a lane away from the zone when it is safe; only if a lane change is unsafe do they slow to the required reduced speed. Source: RCW 46.61.212.","handbook":"","hbref":""},{"q":"Which agency issues commercial driver licenses (CDLs) in Washington?","options":["The Washington State Department of Licensing (DOL)","The Washington State Patrol (WSP)","The Washington State Department of Transportation (WSDOT)","The federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"In Washington the Department of Licensing (DOL) issues CDLs and administers CDL testing. Source: WA DOL, 'Getting a commercial driver license (CDL).'","handbook":"","hbref":""},{"q":"Where can a Washington CDL applicant take the required skills test?","options":["With a DOL examiner or a DOL-authorized third-party examiner (TPE)","Only at the Washington State Patrol commercial vehicle division","Only online through the DOL website","At any FMCSA Training Provider Registry school of your choice"],"answer":0,"explanation":"Washington's CDL skills test is given either by a DOL examiner or by a DOL-authorized third-party examiner (TPE). Source: WA DOL, 'CDL skills test.'","handbook":"","hbref":""},{"q":"How many parts make up the Washington CDL skills test?","options":["Three: vehicle (pre-trip) inspection, basic vehicle control, and the on-road driving test","Two: a written exam and a road test","Four: written, vision, inspection, and road test","One combined road test that includes everything"],"answer":0,"explanation":"The Washington CDL skills test has three parts taken in sequence: the vehicle (pre-trip) inspection, basic vehicle control skills, and the on-road driving test. Source: WA DOL, 'CDL skills test.'","handbook":"","hbref":""},{"q":"How long is a Washington Commercial Learner's Permit (CLP) valid from the date it is issued?","options":["180 days","30 days","1 year","60 days"],"answer":0,"explanation":"A Washington CLP is valid for 180 days from the date issued. Source: WA DOL, 'Commercial learner's permit (CLP).'","handbook":"","hbref":""},{"q":"After a Washington CLP is issued, how long must the holder wait before taking the CDL skills test?","options":["14 calendar days","30 calendar days","7 calendar days","No waiting period is required"],"answer":0,"explanation":"Washington requires a 14-calendar-day wait after an original or upgraded CLP is issued before the holder may take the skills test, mirroring the federal CLP rule. Source: WA DOL, 'Commercial learner's permit (CLP)' / 'CDL skills test.'","handbook":"","hbref":""},{"q":"Before taking the CDL skills test in Washington, a first-time Class A or Class B applicant must complete which requirement?","options":["Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry","A four-year apprenticeship logged with the DOL","A defensive-driving course approved by the Washington State Patrol","A road-rage prevention seminar offered by WSDOT"],"answer":0,"explanation":"Since February 7, 2022, first-time Class A/B applicants must complete ELDT from a provider listed on the FMCSA Training Provider Registry before testing, and Washington cannot administer the test until completion is verified. Source: FMCSA ELDT rule; WA DOL, 'CDL skills test.'","handbook":"","hbref":""},{"q":"How many self-certification categories must a Washington CDL applicant choose from when declaring the type of driving they do?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification categories: non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. Source: WA DOL, 'Medical certificates and self-certification'; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which Washington self-certification category does NOT require a driver to have a medical examiner's certificate on file?","options":["Excepted intrastate","Non-excepted interstate","Excepted interstate","Non-excepted intrastate"],"answer":0,"explanation":"Three of the four categories require a medical examiner's certificate; only excepted intrastate drivers have 'no documents required.' Source: WA DOL, 'Medical certificates and self-certification.'","handbook":"","hbref":""},{"q":"Under current Washington/federal rules, how does a driver's DOT medical examiner's certificate normally reach the DOL?","options":["The medical examiner uploads it to the National Registry, which transmits it to the DOL","The driver always mails a paper copy to FMCSA in Washington, D.C.","The employer faxes it to the Washington State Patrol","The certificate is automatically generated when the CLP is issued"],"answer":0,"explanation":"The certified medical examiner uploads the certificate to the FMCSA National Registry, and the result is transmitted to the DOL to update the driver's record. Source: WA DOL, 'Medical certificates and self-certification.'","handbook":"","hbref":""},{"q":"After the DOL receives a driver's CDL medical documents, how long does it generally take to update the driver's record?","options":["7 to 10 business days","1 to 2 business days","30 to 45 business days","The same business day"],"answer":0,"explanation":"The DOL states it can take 7-10 business days to update a record after the medical documents are received. Source: WA DOL, 'Medical certificates and self-certification.'","handbook":"","hbref":""},{"q":"What study guide does the Washington DOL direct CDL applicants to use to prepare for the knowledge tests?","options":["The Washington Commercial Driver Guide","The Washington Driver Guide (non-commercial)","The FMCSA Hazardous Materials Compliance Pocketbook","The Washington Trucker's Almanac"],"answer":0,"explanation":"The DOL directs CDL applicants to study the Washington Commercial Driver Guide, which it says contains all the information needed to pass the test. Source: WA DOL, 'CDL knowledge test.'","handbook":"","hbref":""},{"q":"In which languages does the Washington DOL offer the CDL knowledge test?","options":["English, Spanish, Russian, and Serbo-Croatian","English only","English and Spanish only","Any language, with an interpreter the applicant provides"],"answer":0,"explanation":"Washington offers the CDL knowledge test in English, Spanish, Russian, and Serbo-Croatian, and language interpreters are not allowed. Source: WA DOL, 'CDL knowledge test.'","handbook":"","hbref":""},{"q":"A Washington CDL knowledge test fee covers one attempt at each knowledge test taken within what time period after it is paid?","options":["90 days","30 days","180 days","1 year"],"answer":0,"explanation":"The knowledge test fee covers one attempt at each knowledge test taken within 90 days of receipt. Source: WA DOL, 'CDL knowledge test.'","handbook":"","hbref":""},{"q":"Which documents must a Washington applicant bring to apply for a CLP?","options":["A valid WA driver license, proof of Social Security number, and proof of U.S. citizenship or lawful permanent residency","Only a birth certificate","A passport and two utility bills","A vehicle registration and proof of insurance"],"answer":0,"explanation":"To apply for a CLP the DOL requires a current Washington driver license, Social Security number, and proof of U.S. citizenship or lawful permanent residency. Source: WA DOL, 'Commercial learner's permit (CLP).'","handbook":"","hbref":""},{"q":"Before being tested for a hazardous materials (H) endorsement in Washington, an applicant must complete what kind of ELDT?","options":["Theory (knowledge) training from an FMCSA Training Provider Registry provider, taken before the H knowledge test","A full behind-the-wheel range and road course","No training at all, only the background check","On-road training supervised by the Washington State Patrol"],"answer":0,"explanation":"For the hazmat (H) endorsement, ELDT is theory-only and must be completed with a Training Provider Registry provider before taking the state H knowledge test. Source: FMCSA ELDT rule; FMCSA Training Provider Registry, 'ELDT Applicability.'","handbook":"","hbref":""},{"q":"How is the standard non-enhanced Washington CDL renewal cycle structured?","options":["It must be renewed every 6 years","It must be renewed every 4 years","It must be renewed every 10 years","It never expires once issued"],"answer":0,"explanation":"A standard Washington CDL is issued on a 6-year cycle. Source: WA DOL, 'Renew your CDL.'","handbook":"","hbref":""},{"q":"How early may a Washington driver renew a CDL before it expires?","options":["Up to 1 year before it expires","Up to 6 months before it expires","Only on the exact expiration date","Up to 90 days before it expires"],"answer":0,"explanation":"The DOL allows CDL renewal up to 1 year before the license expires. Source: WA DOL, 'Renew your CDL.'","handbook":"","hbref":""},{"q":"What happens if a Washington CDL has been expired for more than 8 years?","options":["The driver cannot renew and must start the CDL process over","The driver can still renew online with a small late fee","The license is automatically reinstated after a vision test","The driver may keep driving on the expired card for one more year"],"answer":0,"explanation":"If a Washington CDL has been expired more than 8 years, it cannot be renewed and the driver must start the licensing process over. Source: WA DOL, 'Renew your CDL.'","handbook":"","hbref":""},{"q":"How many times may a Washington CLP be renewed, and on what condition?","options":["Once, if renewed within 30 days of its expiration, extending it another 180 days","Unlimited times, as long as the holder keeps studying","Twice per calendar year regardless of timing","It can never be renewed; a new one must be issued"],"answer":0,"explanation":"A Washington CLP may be renewed only once, within 30 days of expiration, which extends it for another 180 days. Source: WA DOL, 'Commercial learner's permit (CLP).'","handbook":"","hbref":""},{"q":"In Washington, which CDL events require Entry-Level Driver Training (ELDT) from a Training Provider Registry provider?","options":["Obtaining a first Class A or Class B CDL, upgrading Class B to Class A, and getting a first H, P, or S endorsement","Only obtaining a first Class C CDL","Only renewing an existing CDL","Every knowledge-test retake after a failure"],"answer":0,"explanation":"ELDT applies to first-time Class A or Class B applicants, Class B-to-Class A upgrades, and first-time hazardous materials (H), passenger (P), or school bus (S) endorsements; Washington verifies completion before testing. Source: FMCSA Training Provider Registry, 'ELDT Applicability.'","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимально допустимая по закону внешняя ширина транспортного средства или его груза на дорогах общего пользования штата Вашингтон без специального разрешения?","options":["8 футов (96 inches)","8 футов 6 дюймов (102 inches)","9 футов (108 inches)","10 футов (120 inches)"],"explanation":"RCW 46.44.010 ограничивает общую внешнюю ширину транспортного средства или его груза до 8 футов 6 дюймов (102 inches), за исключением некоторых устройств безопасности и зеркал. Это также федеральный стандарт. Источник: RCW 46.44.010; WSDOT Commercial Vehicle Guide."},"1":{"q":"Какова максимально допустимая по закону высота, включая груз, для транспортного средства на дорогах штата Вашингтон без специального разрешения?","options":["13 футов 6 дюймов","14 футов","14 футов 6 дюймов","15 футов"],"explanation":"RCW 46.44.020 устанавливает, что транспортному средству, как порожнему, так и с грузом, запрещено превышать высоту 14 футов над поверхностью, на которой оно стоит. Источник: RCW 46.44.020."},"2":{"q":"Какова максимально допустимая по закону длина одиночного транспортного средства (не автопоезда) на дорогах штата Вашингтон без разрешения?","options":["35 футов","40 футов","45 футов","48 футов"],"explanation":"RCW 46.44.030 устанавливает общую максимальную длину одиночного транспортного средства в 40 футов, с исключениями, позволяющими автобусам, домам на колёсах и трейлерам для путешествий иметь длину до 46 футов. Источник: RCW 46.44.030."},"3":{"q":"В составе тягача с полуприцепом на дорогах штата Вашингтон какова максимально допустимая длина одного полуприцепа (без разрешения)?","options":["48 футов","53 фута","57 футов","60 футов"],"explanation":"RCW 46.44.030 запрещает эксплуатацию тягача с полуприцепом, длина полуприцепа которого превышает 53 фута. Источник: RCW 46.44.030."},"4":{"q":"Какую максимальную полную нагрузку штат Вашингтон допускает на любую одиночную ось без специального разрешения?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"RCW 46.44.041 запрещает полную нагрузку на любую одиночную ось, превышающую 20,000 pounds. Источник: RCW 46.44.041; WSDOT 'Legal vehicle weight'."},"5":{"q":"Какова стандартная максимальная полная нагрузка на группу сдвоенных осей (тандем) в штате Вашингтон (без разрешения)?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Согласно RCW 46.44.041 и федеральному стандарту, принятому в штате Вашингтон, группа сдвоенных осей (тандем) ограничена 34,000 pounds. Источник: RCW 46.44.041."},"6":{"q":"Какова максимальная полная масса транспортного средства, разрешённая на системе межштатных автомагистралей (Interstate) в штате Вашингтон без разрешения?","options":["80,000 pounds","90,000 pounds","100,000 pounds","105,500 pounds"],"explanation":"На системе межштатных автомагистралей (Interstate) федеральный закон, принятый штатом Вашингтон, ограничивает полную массу до 80,000 pounds. Более высокие значения применяются только на некоторых автомагистралях штата, не входящих в систему Interstate. Источник: RCW 46.44.041; 23 CFR 658.17; WSDOT."},"7":{"q":"Согласно весовой таблице штата Вашингтон, какова максимальная общая полная масса транспортного средства, которую можно законно перевозить на автомагистралях штата, не входящих в систему Interstate, при достаточном числе осей и колёсной базе (без разрешения на перегруз)?","options":["80,000 pounds","98,000 pounds","105,500 pounds","120,000 pounds"],"explanation":"Таблица веса по колёсной базе и осям из RCW 46.44.041 допускает полную массу до 105,500 pounds на автомагистралях, не входящих в систему Interstate, когда расстояние между осями и их количество соответствуют требованиям. Система Interstate остаётся ограниченной 80,000 pounds. Источник: RCW 46.44.041; WSDOT."},"8":{"q":"Какую формулу использует штат Вашингтон для определения максимально допустимого веса на группе последовательных осей?","options":["W = 500[LN/(N-1) + 12N + 36]","W = 1000(L + N + 12)","W = 700[LN/(N+1) + 10N]","W = 250[LN + 24N + 40]"],"explanation":"RCW 46.44.041 включает федеральную мостовую формулу W = 500[LN/(N-1) + 12N + 36], где L — это расстояние между крайними осями группы, а N — количество осей. Источник: RCW 46.44.041; FHWA Bridge Formula."},"9":{"q":"В мостовой формуле штата Вашингтон W = 500[LN/(N-1) + 12N + 36] что обозначает 'N'?","options":["Количество осей в группе","Расстояние в футах между крайними осями","Чистый вес груза в тоннах","Количество шин на ведущей оси"],"explanation":"В мостовой формуле, принятой RCW 46.44.041, N — это количество осей в рассматриваемой группе, а L — расстояние в футах между крайними осями этой группы. Источник: RCW 46.44.041; FHWA."},"10":{"q":"В штате Вашингтон полная нагрузка, допустимая на одиночную ось, также ограничена шириной шины. Каков максимальный вес на дюйм ширины шины?","options":["500 pounds per inch","550 pounds per inch","600 pounds per inch","700 pounds per inch"],"explanation":"RCW 46.44.042 ограничивает нагрузку на ось до 600 pounds per inch ширины шины. Полная нагрузка на ось определяется наиболее ограничивающим из факторов: размером шины, нагрузкой на ось и весовой таблицей. Источник: RCW 46.44.042; WSDOT."},"11":{"q":"Две последовательные группы сдвоенных осей могут каждая нести 34,000 pounds в штате Вашингтон только если расстояние между первой и последней осями этих двух групп составляет не менее скольки?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"RCW 46.44.041 позволяет двум последовательным группам сдвоенных осей нести по 34,000 pounds каждая только тогда, когда общее расстояние между первой и последней осями этих групп составляет 36 feet или более. Источник: RCW 46.44.041."},"12":{"q":"Перевозчику нужно переместить груз, превышающий установленные в штате Вашингтон законные ограничения по размерам или весу. Кто выдаёт специальное разрешение на перемещение по автомагистралям штата?","options":["Патруль штата Вашингтон (Washington State Patrol)","Департамент лицензирования (Department of Licensing)","Департамент транспорта штата Вашингтон (WSDOT)","Управление шерифа округа"],"explanation":"RCW 46.44.090 уполномочивает WSDOT выдавать специальные разрешения на негабаритные/тяжеловесные перевозки по автомагистралям штата; местные органы власти выдают их для дорог, находящихся в их юрисдикции. Источник: RCW 46.44.090; WSDOT Commercial Vehicle Permits."},"13":{"q":"Согласно RCW 46.44.090, что обычно должен подтвердить заявитель, чтобы получить специальное разрешение на негабаритную или тяжеловесную перевозку в штате Вашингтон?","options":["Письменное заявление и обоснованную причину","Письмо о федеральном освобождении","Подтверждение страхования груза на $1 million","Безупречную историю вождения за пять лет"],"explanation":"RCW 46.44.090 предусматривает, что WSDOT или местные органы власти могут выдать специальное разрешение по письменному (или электронному) заявлению и при наличии обоснованной причины. Источник: RCW 46.44.090."},"14":{"q":"Когда требуется специальное разрешение штата Вашингтон на негабаритную/тяжеловесную перевозку?","options":["Только когда транспортное средство пустое","Всякий раз, когда транспортное средство или груз превышает законные ограничения, установленные в RCW 46.44.010–46.44.041","Только на платных дорогах","Только для транспортных средств длиннее 53 футов"],"explanation":"RCW 46.44.090 требует специального разрешения для перемещения транспортного средства или груза, превышающего максимумы, установленные в RCW 46.44.010, .020, .030, .034 и .041. Для неделимого груза, который невозможно уменьшить, требуется получить разрешение, а не разделять его. Источник: RCW 46.44.090."},"15":{"q":"Штат Вашингтон позволяет лесовозам получать специальное разрешение на 'допуск для лесовозов' (log tolerance). На сколько дополнительной полной массы сверх обычного законного максимума позволяет это разрешение?","options":["До 4,000 pounds","До 6,800 pounds","До 10,000 pounds","До 12,500 pounds"],"explanation":"RCW 46.44.047 позволяет лесовозам, перевозящим брёвна, превышать максимальную законную полную массу (68,000 pounds при полной регистрации) не более чем на 6,800 pounds по специальному разрешению log tolerance. Источник: RCW 46.44.047."},"16":{"q":"Каков годовой сбор за специальное разрешение log tolerance штата Вашингтон при выдаче на полный 12-месячный период?","options":["$25","$50","$100","$120"],"explanation":"RCW 46.44.047 устанавливает сбор за специальное разрешение log tolerance в размере $50 за 12-месячный период, начинающийся 1 апреля, с пониженными пропорциональными сборами при выдаче позже в течение года действия разрешения. Источник: RCW 46.44.047."},"17":{"q":"В составе с тягачом и двумя прицепами ('двойник', double) в штате Вашингтон какова максимальная суммарная длина двух прицепов без разрешения?","options":["56 футов","61 фут","65 футов","68 футов"],"explanation":"RCW 46.44.030 ограничивает состав тягача с двумя прицепами так, что суммарная длина прицепов не превышает 61 фут. Источник: RCW 46.44.030."},"18":{"q":"Самостоятельно оформляемое разрешение WSDOT на одиночную негабаритную перевозку допускает перемещение до каких максимальных размеров и веса, прежде чем потребуется более специализированное разрешение?","options":["12 ft wide, 14 ft high, 100,000 lb","14 ft wide, 15 ft high, 150,000 lb","16 ft wide, 16 ft high, 200,000 lb","20 ft wide, 18 ft high, 250,000 lb"],"explanation":"Система самостоятельного оформления разрешений WSDOT охватывает грузы до 16 feet шириной, 16 feet высотой, 125 feet длины груза и 200,000 pounds; для более крупных перемещений требуется разрешение, выдаваемое непосредственно офисом разрешений WSDOT. Источник: WSDOT Commercial Vehicle Permits, 'Self-issue a permit.'"},"19":{"q":"Регламенты какого ведомства ограничивают полную массу до 80,000 pounds на системе Interstate — лимит, которому штат Вашингтон обязан следовать, чтобы сохранить федеральное финансирование автодорог?","options":["Агентство по охране окружающей среды (Environmental Protection Agency)","Федеральное управление автомобильных дорог (FHWA) согласно 23 CFR Part 658","Медицинское подразделение Федерального управления безопасности автоперевозчиков (FMCSA)","Комиссия по торговле между штатами (Interstate Commerce Commission)"],"explanation":"Ограничение полной массы в 80,000 pounds на системе Interstate и мостовая формула исходят из регламентов FHWA в 23 CFR Part 658, которые штат Вашингтон принимает в RCW 46.44.041 для системы Interstate. Более высокие лимиты вне Interstate отражают \"дедушкины права\" (grandfather rights) штата Вашингтон. Источник: 23 CFR 658.17; RCW 46.44.041."},"20":{"q":"В штате Вашингтон какой класс CDL требуется для управления составным транспортным средством с полной массой автопоезда (GCWR) 26,001 pounds или более, где буксируемый(ые) элемент(ы) превышает 10,000 pounds GVWR?","options":["Class A","Class B","Class C","Class D"],"explanation":"Штат Вашингтон требует CDL класса Class A для составного транспортного средства с GCWR 26,001 pounds или более, когда буксируемое(ые) транспортное(ые) средство(а) имеет GVWR более 10,000 pounds. Источник: WA DOL, Types of CDLs / Washington State Commercial Driver Guide."},"21":{"q":"Согласно правилам штата Вашингтон, CDL класса Class B охватывает какой тип транспортного средства?","options":["Любое одиночное транспортное средство с GVWR 26,001 pounds или более (и буксирующее элемент весом 10,000 lbs или менее)","Составное транспортное средство, буксирующее прицеп тяжелее 10,000 pounds","Только транспортные средства, перевозящие 16 или более пассажиров","Только транспортные средства с табличками опасных грузов"],"explanation":"CDL класса Class B в штате Вашингтон охватывает любое одиночное транспортное средство с GVWR 26,001 pounds или более, включая такое транспортное средство, буксирующее прицеп с номинальным весом 10,000 pounds или менее. Составы с более тяжёлым буксируемым элементом требуют класса Class A. Источник: WA DOL, Types of CDLs."},"22":{"q":"CDL класса Class C штата Вашингтон требуется, когда транспортное средство не достигает весовых порогов классов Class A или Class B, но предназначено для перевозки не менее скольки человек (включая водителя), либо перевозит опасные грузы, требующие табличек?","options":["16 или более","12 или более","20 или более","10 или более"],"explanation":"CDL класса Class C применяется к транспортным средствам, перевозящим 16 или более человек, включая водителя, или перевозящим опасные грузы, требующие табличек, когда транспортное средство слишком лёгкое для классов Class A или Class B. Источник: WA DOL, Types of CDLs."},"23":{"q":"Какое дополнение (endorsement) требует штат Вашингтон для водителя, буксирующего составы из двойных или тройных прицепов?","options":["Дополнение T","Дополнение N","Дополнение H","Дополнение X"],"explanation":"Дополнение T (Doubles/Triples) требуется в штате Вашингтон для водителей, буксирующих составы из двойных или тройных прицепов, и получается путём сдачи только теоретического экзамена. Источник: WA DOL, Endorsements and restrictions."},"24":{"q":"В штате Вашингтон дополнение N (Tank Vehicle) требуется для CMV, предназначенного для перевозки жидких или газообразных материалов в цистерне с индивидуальной номинальной ёмкостью более 119 gallons и совокупной номинальной ёмкостью не менее скольки галлонов?","options":["1,000 gallons","500 gallons","750 gallons","1,500 gallons"],"explanation":"Штат Вашингтон требует дополнение N для любого CMV, предназначенного для перевозки жидких/газообразных материалов в цистерне с индивидуальной номинальной ёмкостью более 119 gallons и совокупной номинальной ёмкостью 1,000 gallons или более. Источник: WA DOL, Endorsements and restrictions."},"25":{"q":"Какое дополнение CDL штата Вашингтон требуется для управления пассажирским транспортным средством, предназначенным для перевозки 16 или более человек (включая водителя)?","options":["Дополнение P","Дополнение S","Дополнение T","Дополнение N"],"explanation":"Дополнение P (Passenger) требуется в штате Вашингтон для водителей пассажирских транспортных средств, предназначенных для перевозки 16 или более человек, включая водителя. Источник: WA DOL, Endorsements and restrictions."},"26":{"q":"В штате Вашингтон дополнение S (School Bus) требуется для управления чем?","options":["Школьным автобусом любого размера, используемым для перевозки детей в школу/из школы или на школьные мероприятия","Только школьными автобусами, перевозящими 16 или более детей","Только дизельными школьными автобусами","Только школьными автобусами, эксплуатируемыми за пределами округа"],"explanation":"Штат Вашингтон требует дополнение S для управления школьным автобусом любого размера, регулярно используемым для перевозки детей в школу и из школы или в связи со школьными мероприятиями. Источник: WA DOL, Endorsements and restrictions."},"27":{"q":"Перед получением дополнения HazMat (H) в штате Вашингтон водитель должен пройти федеральную оценку угрозы безопасности, проводимую каким ведомством, включая снятие отпечатков пальцев?","options":["Управление транспортной безопасности (TSA)","Патруль штата Вашингтон (WSP)","Федеральное управление безопасности автоперевозчиков (FMCSA)","Только Департамент лицензирования (DOL)"],"explanation":"Штат Вашингтон требует, чтобы заявители на HazMat прошли снятие отпечатков пальцев и оценку угрозы для дополнения по опасным материалам TSA (TSA Hazardous Materials Endorsement Threat Assessment) до выдачи дополнения H. Источник: WA DOL, Hazardous materials endorsement (hazmat); TSA HTAP."},"28":{"q":"Дополнение HazMat (H) на CDL штата Вашингтон должно обновляться, с новой оценкой угрозы TSA, не реже чем как часто?","options":["Каждые 5 лет","Каждые 2 года","Каждые 8 лет","Каждые 10 лет"],"explanation":"Федеральные правила, применяемые в штате Вашингтон, требуют обновления дополнения HazMat, включая новые отпечатки пальцев и новую проверку TSA, не реже чем каждые 5 лет. Источник: WA DOL, Hazmat endorsement; TSA HTAP."},"29":{"q":"Каков минимальный возраст для получения CDL штата Вашингтон только для ВНУТРИШТАТНОГО (INTRASTATE) вождения?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Штат Вашингтон позволяет водителю в возрасте не менее 18 лет получить CDL для внутриштатной коммерции; эксплуатация между штатами требует возраста 21 года. Источник: WA DOL, Getting a commercial driver license (CDL)."},"30":{"q":"Каков минимальный возраст для получения CDL штата Вашингтон, позволяющего вождение в МЕЖШТАТНОЙ (INTERSTATE) коммерции (через границы штатов)?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Водитель должен быть в возрасте не менее 21 года для управления коммерческим транспортным средством через границы штатов согласно правилам штата Вашингтон и федеральным правилам. Источник: WA DOL, Getting a commercial driver license (CDL)."},"31":{"q":"В штате Вашингтон как долго действует коммерческое ученическое разрешение (CLP) с даты его выдачи?","options":["180 days","90 days","1 год","60 days"],"explanation":"CLP штата Вашингтон действует 180 days с даты выдачи и может быть продлено один раз в течение 30 days до истечения срока на дополнительные 180 days. Источник: WA DOL, Commercial learner's permit (CLP)."},"32":{"q":"После выдачи первоначального CLP штата Вашингтон сколько времени водитель должен подождать, прежде чем сдавать практический экзамен CDL?","options":["14 calendar days","7 calendar days","30 calendar days","10 business days"],"explanation":"Федеральные правила, принятые штатом Вашингтон, требуют выдержки в 14 calendar days после выдачи первоначального или повышенного CLP, прежде чем водитель сможет сдавать практический экзамен. Источник: WA DOL, Commercial learner's permit (CLP)."},"33":{"q":"При вождении по CLP штата Вашингтон сопровождающий держатель CDL, сидящий рядом с держателем разрешения, должен иметь действительный CDL надлежащего класса/с надлежащими дополнениями и иметь стаж не менее какого?","options":["2 года на данном типе транспортного средства и 5 лет общего стажа вождения","1 год вождения с CDL","6 месяцев на данном типе транспортного средства","10 лет общего стажа вождения"],"explanation":"Штат Вашингтон требует, чтобы сопровождающий держатель CDL имел надлежащие дополнения, не менее 2 лет опыта на данном типе транспортного средства и не менее 5 лет общего стажа вождения. Источник: WA DOL, Commercial learner's permit (CLP)."},"34":{"q":"Какая категория документов НЕ требуется отдельно при подаче заявления на CDL штата Вашингтон?","options":["Подтверждение того, что вы владеете коммерческим транспортным средством","Подтверждение личности / даты рождения","Номер социального страхования (Social Security number)","Подтверждение гражданства США или законного постоянного проживания"],"explanation":"Штат Вашингтон требует подтверждение личности, номер социального страхования, подтверждение проживания и подтверждение гражданства США или законного постоянного проживания (законного присутствия); владение коммерческим транспортным средством не требуется. Источник: WA DOL, CDL-approved documents."},"35":{"q":"Чтобы подтвердить законное присутствие для CDL штата Вашингтон, заявитель должен предъявить что из следующего?","options":["Один одобренный на федеральном уровне документ, такой как паспорт США, свидетельство о рождении или карта постоянного жителя (Permanent Resident Card) (оригинал, не фотокопия)","Любые два счёта за коммунальные услуги","Нотариально заверенное заявление о гражданстве","Только карточку регистрации избирателя"],"explanation":"Штат Вашингтон требует один приемлемый оригинальный документ, подтверждающий гражданство США или законное постоянное проживание, такой как паспорт США, выданное государством свидетельство о рождении или карта постоянного жителя (Permanent Resident Card); фотокопии не принимаются. Источник: WA DOL, CDL-approved documents."},"36":{"q":"Обучение водителей начального уровня (ELDT) стало обязательным в штате Вашингтон для заявителей, получающих CLP начиная с какой даты?","options":["February 7, 2022","January 1, 2020","September 1, 2021","July 1, 2023"],"explanation":"Федеральные правила ELDT, применяемые в штате Вашингтон, требуют обучения у зарегистрированного провайдера для заявителей, получающих CLP начиная с February 7, 2022. Источник: FMCSA Entry-Level Driver Training; WA DOL, CDL training requirements."},"37":{"q":"Согласно правилам ELDT в штате Вашингтон, водитель, желающий получить какой документ, должен пройти обучение у провайдера, указанного в реестре провайдеров обучения FMCSA (FMCSA Training Provider Registry), перед экзаменом?","options":["Впервые получаемый CDL класса Class A или Class B, либо впервые получаемое дополнение P, S или H","Только дополнение T (doubles/triples)","Только дополнение N (tank)","Продление существующего CDL без изменения класса"],"explanation":"ELDT применяется к заявителям, впервые получающим CDL классов Class A и Class B (и при повышении с B на A), а также к заявителям, впервые получающим дополнения для пассажирских перевозок (P), школьного автобуса (S) и HazMat (H); провайдер должен быть в реестре провайдеров обучения FMCSA (FMCSA Training Provider Registry). Источник: FMCSA ELDT Applicability."},"38":{"q":"При подаче заявления на CDL штата Вашингтон категория медицинской самосертификации 'Non-Excepted Interstate' означает, что водитель:","options":["Работает в межштатной коммерции и должен поддерживать действительный медицинский сертификат эксперта DOT","Работает только в пределах штата Вашингтон и освобождён от всех медицинских требований","Работает в межштатной коммерции, но освобождён от медицинского сертификата","Ездит только по частной территории и не нуждается в сертификате"],"explanation":"Из четырёх категорий самосертификации Non-Excepted Interstate означает, что водитель работает через границы штатов и должен иметь и поддерживать действительный медицинский сертификат эксперта DOT. Источник: FMCSA medical self-certification categories; WA DOL, Getting a CDL."},"39":{"q":"Что из следующего является одной из четырёх категорий медицинской самосертификации CDL, из которых заявитель штата Вашингтон должен выбрать?","options":["Excepted Intrastate","Provisional Interstate","Conditional Intrastate","Restricted Interstate"],"explanation":"Четыре категории самосертификации FMCSA, используемые в штате Вашингтон, — это Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate и Excepted Intrastate. Источник: FMCSA medical self-certification; WA DOL, Getting a CDL."},"40":{"q":"В штате Вашингтон какова максимальная концентрация алкоголя в крови (BAC), при которой человек может законно управлять коммерческим транспортным средством (CMV)?","options":["0.04","0.08","0.02","0.10"],"explanation":"Закон штата Вашингтон (и Washington CDL Guide, следующий 49 CFR 383.51/392.5) делает незаконным управление CMV с BAC 0.04 или выше — половина лимита 0.08 для некоммерческих водителей. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51."},"41":{"q":"Согласно закону о подразумеваемом согласии штата Вашингтон, имея CDL и управляя транспортным средством, водитель считается согласившимся сделать что, если у сотрудника правоохранительных органов есть разумные основания подозревать состояние опьянения?","options":["Пройти тест дыхания или крови на алкоголь или наркотики","Оплатить фиксированный денежный залог на месте","Сдать CDL навсегда прямо на месте","Сначала пройти 12-часовой курс алкогольного просвещения"],"explanation":"Закон о подразумеваемом согласии штата Вашингтон (RCW 46.20.308) означает, что любой управляющий транспортным средством в штате согласился на химическое тестирование (дыхания или крови), когда у сотрудника есть разумные основания подозревать вождение в состоянии опьянения. Источник: RCW 46.20.308; Washington DOL CDL Guide."},"42":{"q":"Держатель CDL штата Вашингтон осуждён за первое вождение в нетрезвом виде (DUI) при управлении коммерческим транспортным средством без табличек опасных грузов. Каков срок дисквалификации за это первое серьёзное нарушение (major offense)?","options":["1 год","3 года","60 days","6 месяцев"],"explanation":"Первое серьёзное нарушение (major offense), включая DUI, BAC 0.04+ или отказ от теста, дисквалифицирует CDL на 1 год. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1."},"43":{"q":"В штате Вашингтон каков срок дисквалификации CDL за первое серьёзное нарушение (например, DUI или BAC 0.04+), если водитель в момент нарушения перевозил опасные грузы с табличками?","options":["3 года","1 год","5 лет","120 days"],"explanation":"Первое серьёзное нарушение, совершённое при перевозке опасных грузов с табличками, увеличивает дисквалификацию с 1 года до 3 лет. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1."},"44":{"q":"Каков срок дисквалификации CDL в штате Вашингтон за второе серьёзное нарушение (major offense) (например, второе осуждение за DUI или второе за BAC 0.04+)?","options":["Пожизненно (life)","10 лет","5 лет","3 года"],"explanation":"Второе серьёзное нарушение влечёт пожизненную дисквалификацию CDL; штат Вашингтон отмечает, что восстановиться после пожизненной дисквалификации нельзя. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1."},"45":{"q":"Держатель CDL штата Вашингтон отказывается пройти тест дыхания или крови по законному требованию сотрудника при управлении транспортным средством без табличек опасных грузов. Каков срок дисквалификации за этот первый отказ?","options":["1 год","90 days","3 года","60 days"],"explanation":"Отказ от химического теста рассматривается как серьёзное нарушение (major offense), дисквалифицируя CDL на 1 год при первом отказе (3 года, если с табличками опасных грузов). Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1."},"46":{"q":"В штате Вашингтон отказ от теста дыхания или крови является серьёзным нарушением (major offense), которое засчитывается к пожизненной дисквалификации. Отказ от теста, за которым позже следует отдельное осуждение за DUI, приведёт к какой дисквалификации?","options":["Пожизненная дисквалификация (два серьёзных нарушения)","Только дисквалификация на 1 год в общей сложности","Дисквалификация на 120 days","Никакой дополнительной дисквалификации помимо первой"],"explanation":"И отказ от теста, и DUI являются серьёзными нарушениями (major offenses); два серьёзных нарушения из отдельных инцидентов влекут пожизненную дисквалификацию CDL. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1."},"47":{"q":"Сколько серьёзных нарушений ПДД (serious traffic violations) в течение 3-летнего периода (в отдельных инцидентах) влечёт самую короткую дисквалификацию CDL за серьёзные нарушения в штате Вашингтон?","options":["2 серьёзных нарушения","3 серьёзных нарушения","1 серьёзное нарушение","4 серьёзных нарушения"],"explanation":"Два серьёзных нарушения ПДД, возникших из отдельных инцидентов в течение 3 лет, влекут дисквалификацию на 60 days; первое одиночное серьёзное нарушение само по себе не дисквалифицирует. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2."},"48":{"q":"Каков срок дисквалификации CDL в штате Вашингтон за два серьёзных нарушения ПДД, совершённых в отдельных инцидентах в течение 3-летнего периода?","options":["60 days","120 days","30 days","90 days"],"explanation":"Два серьёзных нарушения ПДД в течение 3 лет (отдельные инциденты) влекут дисквалификацию CDL на 60 days. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2."},"49":{"q":"Каков срок дисквалификации CDL в штате Вашингтон за три серьёзных нарушения ПДД, совершённых в отдельных инцидентах в течение 3-летнего периода?","options":["120 days","60 days","1 год","180 days"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет (отдельные инциденты) влекут дисквалификацию CDL на 120 days. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2."},"50":{"q":"Насколько выше установленного ограничения скорости должен быть оштрафован держатель CDL штата Вашингтон, чтобы это засчиталось как 'серьёзное нарушение ПДД' (serious traffic violation)?","options":["На 15 mph или более сверх лимита","На 10 mph или более сверх лимита","На 20 mph или более сверх лимита","На 25 mph или более сверх лимита"],"explanation":"Превышение скорости на 15 mph или более сверх установленного лимита указано как серьёзное нарушение ПДД для целей CDL в штате Вашингтон. Источник: Washington DOL serious traffic offenses page; 49 CFR 383.51 Table 2."},"51":{"q":"Что из следующего классифицируется как 'серьёзное нарушение ПДД' (serious traffic violation) для держателя CDL штата Вашингтон?","options":["Слишком близкое следование за другим транспортным средством (tailgating)","Парковка в зоне, где парковка запрещена","Перегоревшая лампа подсветки номерного знака","Отсутствие отображения регистрационной наклейки"],"explanation":"Слишком близкое следование входит в список серьёзных нарушений ПДД штата Вашингтон (наряду с безрассудным вождением, неправильной сменой полосы, превышением скорости на 15+ и набором текста/использованием телефона в CMV). Нарушения, связанные с оборудованием и парковкой, не входят. Источник: Washington DOL serious traffic offenses page; 49 CFR 383.51."},"52":{"q":"Согласно правилу штата Вашингтон, как классифицируется набор текстовых сообщений при управлении коммерческим транспортным средством для целей дисквалификации CDL?","options":["Серьёзное нарушение ПДД (serious traffic violation)","Серьёзное нарушение (major offense)","Нарушение предписания о выводе из эксплуатации (out-of-service order)","Не подлежащее отчётности нарушение по оборудованию"],"explanation":"Набор текста при управлении CMV (и использование портативного телефона при управлении CMV) является серьёзным нарушением ПДД, поэтому два таких нарушения в течение 3 лет влекут дисквалификацию на 60 days. Источник: Washington DOL serious traffic offenses page; FMCSA 392.80/392.82."},"53":{"q":"Федеральные правила, принятые в штате Вашингтон, запрещают водителю CMV использовать портативный мобильный телефон при вождении. Каков приблизительный максимальный гражданский штраф для водителя за нарушение этого ограничения на использование портативного телефона/набор текста?","options":["До примерно $2,750","До примерно $250","До примерно $500","До примерно $1,000"],"explanation":"Федеральное ограничение на использование портативного телефона и набор текста водителями CMV (FMCSA 392.80/392.82), применяемое в штате Вашингтон, влечёт гражданские штрафы для водителя до примерно $2,750. Источник: FMCSA 392.82; Washington DOL CDL Guide."},"54":{"q":"Каков минимальный срок дисквалификации CDL в штате Вашингтон за первое осуждение за нарушение на железнодорожном переезде при управлении CMV?","options":["60 days","30 days","120 days","1 год"],"explanation":"Первое нарушение на железнодорожном переезде в CMV дисквалифицирует CDL не менее чем на 60 days. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3."},"55":{"q":"Каков минимальный срок дисквалификации CDL в штате Вашингтон за второе нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["120 days","60 days","1 год","180 days"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет дисквалифицирует CDL не менее чем на 120 days. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3."},"56":{"q":"Каков минимальный срок дисквалификации CDL в штате Вашингтон за третье нарушение на железнодорожном переезде в течение 3-летнего периода?","options":["1 год","120 days","60 days","3 года"],"explanation":"Третье нарушение на железнодорожном переезде в течение 3 лет дисквалифицирует CDL не менее чем на 1 год. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3."},"57":{"q":"Каков срок дисквалификации в штате Вашингтон за первое нарушение предписания о выводе из эксплуатации (OOS) при управлении CMV без опасных грузов?","options":["Не менее 180 days и не более 1 года","Не менее 60 days и не более 120 days","Не менее 30 days и не более 90 days","Пожизненная дисквалификация"],"explanation":"Первое нарушение предписания OOS дисквалифицирует CDL не менее чем на 180 days и не более чем на 1 год для транспортного средства без опасных грузов. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4."},"58":{"q":"Водитель штата Вашингтон совершает первое нарушение предписания о выводе из эксплуатации при перевозке опасных грузов с табличками или 16 или более пассажиров. Каков диапазон дисквалификации?","options":["Не менее 180 days и не более 2 лет","Не менее 180 days и не более 1 года","Не менее 60 days и не более 120 days","Не менее 1 года и не более 5 лет"],"explanation":"Первое нарушение предписания OOS при перевозке опасных грузов с табличками или 16+ пассажиров дисквалифицирует CDL не менее чем на 180 days и не более чем на 2 года. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4."},"59":{"q":"Каков срок дисквалификации в штате Вашингтон за второе нарушение предписания о выводе из эксплуатации (без опасных грузов) в течение 10-летнего периода, возникшее из отдельных инцидентов?","options":["Не менее 2 лет и не более 5 лет","Не менее 180 days и не более 1 года","Не менее 1 года и не более 3 лет","Пожизненная дисквалификация"],"explanation":"Второе нарушение предписания OOS (без опасных грузов) в отдельных инцидентах в течение 10 лет дисквалифицирует CDL не менее чем на 2 года и не более чем на 5 лет. Источник: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4."},"60":{"q":"Какое максимальное ограничение скорости установлено в штате Вашингтон для транспортного средства с полной массой свыше 10,000 фунтов (или любого автопоезда) на автомагистрали, даже там, где легковым автомобилям разрешено двигаться быстрее?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"В штате Вашингтон скорость для транспортных средств с полной массой свыше 10,000 lbs и всех автопоездов (кроме маршрутных автобусов) ограничена 60 mph, независимо от более высокого установленного предела для легковых автомобилей. Источник: RCW 46.61.410."},"61":{"q":"На вашингтонской автомагистрали с ограниченным доступом, имеющей три или более полосы в вашем направлении, по какой полосе НЕ разрешается двигаться грузовику или автопоезду массой свыше 10,000 фунтов (за исключением подготовки к разрешённому левому повороту)?","options":["Крайняя правая полоса","Любая центральная полоса","Крайняя левая полоса","Полоса для транспорта с высокой заполняемостью (HOV)"],"explanation":"Ни одно транспортное средство с прицепом, ни одно транспортное средство или автопоезд массой свыше 10,000 lbs не может двигаться по крайней левой полосе дороги с ограниченным доступом, имеющей три или более полосы в одном направлении, кроме как при подготовке к разрешённому левому повороту. Полоса HOV не считается крайней левой полосой. Источник: RCW 46.61.100."},"62":{"q":"Приближаясь к железнодорожному переезду в штате Вашингтон, водитель школьного автобуса или транспортного средства с табличками об опасных грузах должен остановиться на каком расстоянии от ближайшего рельса?","options":["В пределах 50 feet, но не ближе 15 feet","В пределах 75 feet, но не ближе 25 feet","В пределах 40 feet, но не ближе 10 feet","В пределах 100 feet, но не ближе 30 feet"],"explanation":"В штате Вашингтон водитель школьного/пассажирского автобуса, коммерческого транспортного средства, перевозящего пассажиров, или цистерны с опасным грузом обязан остановиться перед стоп-линией, в противном случае в пределах 50 feet, но не ближе 15 feet от ближайшего рельса. Источник: RCW 46.61.350."},"63":{"q":"После остановки на железнодорожном переезде что требует закон штата Вашингтон от водителя автобуса или транспортного средства с табличками HazMat при пересечении путей?","options":["Пересекать на передаче, которая не требует переключения, пока находишься на путях, и не переключать передачи при проезде","Понизить передачу до самой низкой в середине путей","Включить блокировку дифференциала перед пересечением путей","Пересекать только после трёх сигналов клаксона на путях"],"explanation":"Закон штата Вашингтон гласит, что водитель должен пересекать переезд только на передаче, которая не потребует переключения во время проезда, и не может переключать передачи при пересечении путей. Источник: RCW 46.61.350."},"64":{"q":"Согласно вашингтонскому закону «Move Over», «зона аварийных работ» определяется как соседние полосы дороги, простирающиеся на какое расстояние до и после неподвижного аварийного или рабочего транспортного средства с включёнными предупреждающими сигналами?","options":["100 feet","150 feet","200 feet","300 feet"],"explanation":"В штате Вашингтон зона аварийных или дорожных работ определяется как соседние полосы на протяжении 200 feet до и после неподвижного уполномоченного аварийного транспортного средства, эвакуатора, полицейской, коммунальной или дорожно-ремонтной машины с включёнными предупреждающими сигналами. Источник: RCW 46.61.212."},"65":{"q":"На вашингтонской дороге, имеющей менее четырёх полос, если водитель не может безопасно перестроиться в сторону от остановленного аварийного/рабочего транспортного средства, он должен снизить скорость как минимум на сколько ниже установленного ограничения (где предел составляет 60 mph или менее)?","options":["На 5 mph ниже установленного предела","На 10 mph ниже установленного предела","На 15 mph ниже установленного предела","На 20 mph ниже установленного предела"],"explanation":"Когда перестроение небезопасно, вашингтонский закон «Move Over» требует снизить скорость как минимум на 10 mph ниже установленного предела; там, где установленный предел превышает 60 mph, водитель должен вместо этого замедлиться до не более чем 50 mph. Источник: RCW 46.61.212."},"66":{"q":"При встрече остановившегося школьного автобуса с включёнными красными мигающими огнями, двигаясь в ПРОТИВОПОЛОЖНОМ направлении, на какой вашингтонской дороге вы НЕ обязаны останавливаться?","options":["Двухполосная неразделённая дорога","Дорога, разделённая на отдельные проезжие части разделительной полосой или барьером","Любая городская улица с установленной скоростью 25 mph","Двухполосная дорога с центральной двусторонней полосой для левого поворота"],"explanation":"На дороге, разделённой на отдельные проезжие части (согласно RCW 46.61.150), или имеющей три или более размеченные полосы, водитель, встречающий школьный автобус, движущийся в противоположном направлении, не обязан останавливаться. На неразделённых двухполосных дорогах вы обязаны остановиться. Источник: RCW 46.61.370."},"67":{"q":"Помимо исключения для разделённых дорог, на каком ещё типе вашингтонской дороги вы можете продолжать движение мимо встречного остановившегося школьного автобуса (движущегося в противоположном направлении) без остановки?","options":["Дорога с тремя или более размеченными полосами движения","Любая дорога с установленной скоростью 45 mph или выше","Дорога с мощёными обочинами шириной не менее 8 feet","Дорога только с одной центральной полосой для поворота"],"explanation":"Вашингтонский закон о школьных автобусах добавляет, что водители, встречающие автобус, движущийся в противоположном направлении по дороге с тремя или более размеченными полосами движения, не обязаны останавливаться. Источник: RCW 46.61.370."},"68":{"q":"Вашингтонский водитель грузовика останавливается на обочине двухполосной дороги с двусторонним движением. После включения аварийной сигнализации в течение скольких минут должны быть установлены требуемые предупреждающие устройства (треугольники)?","options":["5 минут","10 минут","15 минут","30 минут"],"explanation":"Коммерческое транспортное средство, остановившееся на проезжей части или обочине, должно установить аварийные предупреждающие устройства в течение 10 минут, предварительно включив аварийную сигнализацию. Источник: Washington CDL Manual; 49 CFR 392.22 (принят в штате Вашингтон)."},"69":{"q":"На двухполосной вашингтонской дороге с двусторонним движением, где следует расставить три светоотражающих треугольника для остановившегося коммерческого транспортного средства?","options":["Все три позади транспортного средства на расстоянии 10, 50 и 100 feet","В пределах 10 ft со стороны движения, 100 ft сзади и 100 ft спереди","На расстоянии 10, 100 и 200 feet, все в сторону приближающегося транспорта","Один на крыше и два на расстоянии 50 feet спереди и сзади"],"explanation":"На дороге с двусторонним движением установите один треугольник в пределах 10 ft от транспортного средства со стороны движения, один примерно в 100 ft сзади и один примерно в 100 ft спереди, чтобы предупредить транспорт с обоих направлений. Источник: Washington CDL Manual; 49 CFR 392.22."},"70":{"q":"На вашингтонской разделённой дороге или дороге с односторонним движением, где следует расставить три предупреждающих треугольника остановившегося коммерческого транспортного средства?","options":["На расстоянии 10, 100 и 200 feet в сторону приближающегося транспорта позади транспортного средства","На расстоянии 10, 50 и 100 feet в сторону приближающегося транспорта","Один спереди и два на расстоянии 100 feet сзади","Все три на расстоянии 200 feet позади транспортного средства"],"explanation":"На разделённой дороге или дороге с односторонним движением расставьте треугольники в сторону приближающегося транспорта на расстоянии 10 feet, 100 feet и 200 feet от транспортного средства. Источник: Washington CDL Manual; 49 CFR 392.22."},"71":{"q":"В штате Вашингтон транспортные средства и автопоезда с полной разрешённой массой свыше 10,000 фунтов обязаны иметь при себе цепи противоскольжения на установленных горноперевальных маршрутах в течение какого периода каждый год?","options":["С 1 октября по 1 марта","С 1 ноября по 1 апреля","С 1 декабря по 31 марта","С 15 ноября по 15 марта"],"explanation":"С 1 ноября по 1 апреля транспортные средства и автопоезда с GVWR свыше 10,000 lbs обязаны иметь при себе цепи на установленных маршрутах с цепями (например, I-90, US 2 Stevens Pass, US 12 White Pass), независимо от текущих условий. Источник: требования WSDOT к цепям для коммерческого транспорта; WAC 204-24-050."},"72":{"q":"Сколько запасных цепей противоскольжения должно иметь при себе вашингтонское коммерческое транспортное средство с GVWR свыше 10,000 фунтов на установленных маршрутах с цепями в сезон обязательного наличия цепей?","options":["Минимум одну запасную цепь","Минимум две запасные цепи","Минимум четыре запасные цепи","Никаких запасных, если ведущие колёса уже с цепями"],"explanation":"Штат Вашингтон требует, чтобы такие транспортные средства имели при себе минимум две запасные цепи противоскольжения в период с 1 ноября по 1 апреля, чтобы можно было заменить порванную цепь или зацепить дополнительную ось. Источник: требования WSDOT к цепям; WAC 204-24-050."},"73":{"q":"На многополосной вашингтонской дороге что говорит закон штата о медленном транспортном средстве, постоянно занимающем левую полосу?","options":["Это разрешено, если транспортное средство движется с разрешённой скоростью","Постоянное движение по левой полосе является нарушением ПДД, если оно затрудняет движение другого транспорта","Это разрешено только для транспортных средств массой менее 10,000 фунтов","Это разрешено, если правая полоса занята грузовиками"],"explanation":"Вашингтонский закон «держись правее» делает нарушением ПДД постоянное движение по левой полосе многополосной дороги, если это затрудняет поток другого транспорта. Источник: RCW 46.61.100."},"74":{"q":"Наказание за незаконный объезд остановившегося вашингтонского школьного автобуса с включёнными красными огнями и выдвинутым знаком «стоп» описано в законе как:","options":["Фиксированный штраф $250, который может быть снижен судом","Двойной размер базового штрафа, который не может быть отменён, снижен или приостановлен","Письменное предупреждение за первое нарушение","Только приостановление действия прав, без денежного штрафа"],"explanation":"Водителю, незаконно объехавшему остановившийся школьный автобус, назначается денежный штраф, равный двойному размеру базового штрафа согласно RCW 46.63.110, и он не может быть отменён, снижен или приостановлен. Источник: RCW 46.61.370."},"75":{"q":"Когда Washington State Patrol объявляет «Chains Required» (требуются цепи) для транспортных средств массой свыше 10,000 фунтов, удовлетворяют ли это требование шипованные шины?","options":["Да, шипованные шины засчитываются как цепи","Да, но только на ведущей оси","Нет; цепи должны быть установлены даже поверх шипованных шин","Освобождены только полноприводные транспортные средства"],"explanation":"Шипованные шины не удовлетворяют объявленному требованию о цепях в штате Вашингтон; водители должны установить цепи (поверх шипованных шин, если они есть), чтобы проехать пункт обязательной установки цепей. Источник: зимние требования к цепям WSDOT/WSP."},"76":{"q":"В штате Вашингтон единичное разрешение на перевозку негабаритного/тяжеловесного груза обычно требуется, как только транспортное средство или груз превышает какой из этих установленных пределов габаритов?","options":["Ширина 8 feet 6 inches, высота 14 feet или применимые ограничения длины","Ширина 10 feet, высота 13 feet 6 inches или длина 48 feet","Ширина 9 feet, высота 15 feet или длина 60 feet","Ширина 8 feet, высота 12 feet или длина 35 feet"],"explanation":"Установленные в штате Вашингтон пределы обычно составляют 8 ft 6 in в ширину и 14 ft в высоту; превышение ширины, высоты или применимых ограничений длины требует разрешения WSDOT на негабаритный груз. Источник: разрешения на негабаритные/тяжеловесные грузы WSDOT Commercial Vehicle Services."},"77":{"q":"Какая горная дорога является установленным маршрутом с цепями/тяговым контролем в штате Вашингтон, где обычно применяются требования к цепям для коммерческого транспорта?","options":["I-90 через Snoqualmie Pass","I-5 через центр Seattle","I-405 вокруг Bellevue","Плавучий мост SR 520"],"explanation":"I-90 через Snoqualmie Pass (от North Bend до Ellensburg) является основным установленным маршрутом с цепями, наряду с US 2 Stevens Pass и US 12 White Pass; городские межштатные магистрали, такие как I-5, I-405 и SR 520, не являются горными маршрутами с цепями. Источник: требования WSDOT к цепям на горных перевалах."},"78":{"q":"Вашингтонская аварийная улавливающая полоса для неуправляемых грузовиков на крутом спуске обычно построена так, чтобы остановить тяжёлое транспортное средство с помощью:","options":["Слоя рыхлого гравия или мягкого песка, иногда на подъёме, который увеличивает сопротивление по мере продвижения вглубь","Стальной сетки-отбойника, натянутой поперёк полосы","Мощёного спуска под уклон, позволяющего грузовику катиться до остановки","Наполненного водой жёлоба, поднимающего шины на плаву"],"explanation":"Вашингтонские улавливающие полосы используют рыхлый гравий или мягкий песок, иногда с подъёмом; сопротивление возрастает по мере продвижения грузовика вглубь, помогая привести его к остановке. Источник: Washington CDL Manual, вождение в горах / улавливающие полосы."},"79":{"q":"Согласно вашингтонскому закону «Move Over» на дороге с четырьмя или более полосами, ПЕРВАЯ обязанность водителя при приближении к остановившемуся аварийному/рабочему транспортному средству с мигающими огнями:","options":["Полностью остановиться в полосе, пока транспортное средство не уедет","Продолжать движение с осторожностью, снизить скорость и перестроиться в сторону от него, если это безопасно","Подать сигнал клаксоном и сохранять установленную скорость","Выехать на обочину и объехать справа"],"explanation":"На дорогах с четырьмя или более полосами водители должны продолжать движение с осторожностью, снизить скорость и уступить дорогу, перестроившись на полосу в сторону от зоны, когда это безопасно; только если перестроение небезопасно, они снижают скорость до требуемой пониженной. Источник: RCW 46.61.212."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские права (CDL) в штате Вашингтон?","options":["Washington State Department of Licensing (DOL)","Washington State Patrol (WSP)","Washington State Department of Transportation (WSDOT)","Федеральное Motor Carrier Safety Administration (FMCSA)"],"explanation":"В штате Вашингтон Department of Licensing (DOL) выдаёт CDL и проводит тестирование на CDL. Источник: WA DOL, «Getting a commercial driver license (CDL).»"},"81":{"q":"Где соискатель вашингтонского CDL может сдать обязательный экзамен по навыкам вождения?","options":["У экзаменатора DOL или у авторизованного DOL стороннего экзаменатора (TPE)","Только в отделе коммерческого транспорта Washington State Patrol","Только онлайн через веб-сайт DOL","В любой школе из FMCSA Training Provider Registry по вашему выбору"],"explanation":"Вашингтонский экзамен по навыкам вождения CDL принимается либо экзаменатором DOL, либо авторизованным DOL сторонним экзаменатором (TPE). Источник: WA DOL, «CDL skills test.»"},"82":{"q":"Из скольких частей состоит вашингтонский экзамен по навыкам вождения CDL?","options":["Из трёх: осмотр транспортного средства (предрейсовый), базовое управление транспортным средством и экзамен по вождению на дороге","Из двух: письменный экзамен и экзамен по вождению","Из четырёх: письменный, проверка зрения, осмотр и экзамен по вождению","Из одного объединённого экзамена по вождению, включающего всё"],"explanation":"Вашингтонский экзамен по навыкам вождения CDL состоит из трёх частей, сдаваемых последовательно: осмотр транспортного средства (предрейсовый), базовые навыки управления транспортным средством и экзамен по вождению на дороге. Источник: WA DOL, «CDL skills test.»"},"83":{"q":"Сколько действует вашингтонское ученическое коммерческое разрешение (CLP) с даты его выдачи?","options":["180 дней","30 дней","1 год","60 дней"],"explanation":"Вашингтонское CLP действительно в течение 180 дней с даты выдачи. Источник: WA DOL, «Commercial learner's permit (CLP).»"},"84":{"q":"После выдачи вашингтонского CLP сколько времени его обладатель должен ждать, прежде чем сдавать экзамен по навыкам вождения CDL?","options":["14 календарных дней","30 календарных дней","7 календарных дней","Период ожидания не требуется"],"explanation":"Штат Вашингтон требует 14-дневного ожидания (календарных дней) после выдачи первоначального или обновлённого CLP, прежде чем обладатель сможет сдавать экзамен по навыкам вождения, что соответствует федеральному правилу о CLP. Источник: WA DOL, «Commercial learner's permit (CLP)» / «CDL skills test.»"},"85":{"q":"Перед сдачей экзамена по навыкам вождения CDL в штате Вашингтон впервые подающий заявление на класс A или класс B должен выполнить какое требование?","options":["Пройти Entry-Level Driver Training (ELDT) у провайдера из FMCSA Training Provider Registry","Пройти четырёхлетнее ученичество, зарегистрированное в DOL","Пройти курс безопасного вождения, одобренный Washington State Patrol","Посетить семинар по предотвращению агрессивного вождения, проводимый WSDOT"],"explanation":"С 7 февраля 2022 года впервые подающие заявление на класс A/B должны пройти ELDT у провайдера, указанного в FMCSA Training Provider Registry, перед тестированием, и штат Вашингтон не может проводить экзамен, пока не подтверждено прохождение. Источник: правило FMCSA об ELDT; WA DOL, «CDL skills test.»"},"86":{"q":"Из скольких категорий самосертификации должен выбрать соискатель вашингтонского CDL при декларировании типа выполняемого им вождения?","options":["Из четырёх","Из двух","Из трёх","Из пяти"],"explanation":"Существует четыре категории самосертификации: межштатные перевозки без исключений, межштатные перевозки с исключениями, внутриштатные перевозки без исключений и внутриштатные перевозки с исключениями. Источник: WA DOL, «Medical certificates and self-certification»; 49 CFR 383.71."},"87":{"q":"Какая вашингтонская категория самосертификации НЕ требует наличия у водителя справки от медицинского эксперта в деле?","options":["Внутриштатные перевозки с исключениями","Межштатные перевозки без исключений","Межштатные перевозки с исключениями","Внутриштатные перевозки без исключений"],"explanation":"Три из четырёх категорий требуют справки от медицинского эксперта; только для водителей внутриштатных перевозок с исключениями «документы не требуются». Источник: WA DOL, «Medical certificates and self-certification.»"},"88":{"q":"Согласно действующим вашингтонским/федеральным правилам, как справка водителя от медицинского эксперта DOT обычно попадает в DOL?","options":["Медицинский эксперт загружает её в National Registry, который передаёт её в DOL","Водитель всегда отправляет бумажную копию по почте в FMCSA в Washington, D.C.","Работодатель отправляет её по факсу в Washington State Patrol","Справка автоматически создаётся при выдаче CLP"],"explanation":"Сертифицированный медицинский эксперт загружает справку в FMCSA National Registry, и результат передаётся в DOL для обновления записи водителя. Источник: WA DOL, «Medical certificates and self-certification.»"},"89":{"q":"После того как DOL получает медицинские документы водителя CDL, сколько времени обычно занимает обновление записи водителя?","options":["От 7 до 10 рабочих дней","От 1 до 2 рабочих дней","От 30 до 45 рабочих дней","В тот же рабочий день"],"explanation":"DOL указывает, что обновление записи может занять 7-10 рабочих дней после получения медицинских документов. Источник: WA DOL, «Medical certificates and self-certification.»"},"90":{"q":"Какое учебное пособие Washington DOL рекомендует соискателям CDL использовать для подготовки к экзаменам на знание?","options":["Washington Commercial Driver Guide","Washington Driver Guide (некоммерческое)","FMCSA Hazardous Materials Compliance Pocketbook","Washington Trucker's Almanac"],"explanation":"DOL рекомендует соискателям CDL изучать Washington Commercial Driver Guide, который, по его словам, содержит всю информацию, необходимую для сдачи экзамена. Источник: WA DOL, «CDL knowledge test.»"},"91":{"q":"На каких языках Washington DOL предлагает экзамен на знание CDL?","options":["Английский, испанский, русский и сербохорватский","Только английский","Только английский и испанский","Любой язык, с переводчиком, которого предоставляет соискатель"],"explanation":"Штат Вашингтон предлагает экзамен на знание CDL на английском, испанском, русском и сербохорватском языках, и переводчики не допускаются. Источник: WA DOL, «CDL knowledge test.»"},"92":{"q":"Плата за вашингтонский экзамен на знание CDL покрывает одну попытку по каждому сдаваемому экзамену на знание в течение какого периода после её оплаты?","options":["90 дней","30 дней","180 дней","1 год"],"explanation":"Плата за экзамен на знание покрывает одну попытку по каждому экзамену на знание, сдаваемому в течение 90 дней с момента получения оплаты. Источник: WA DOL, «CDL knowledge test.»"},"93":{"q":"Какие документы должен принести вашингтонский соискатель для подачи заявления на CLP?","options":["Действующие водительские права WA, подтверждение номера Social Security и подтверждение гражданства США или законного постоянного проживания","Только свидетельство о рождении","Паспорт и два счёта за коммунальные услуги","Регистрацию транспортного средства и подтверждение страховки"],"explanation":"Для подачи заявления на CLP DOL требует действующие водительские права штата Вашингтон, номер Social Security и подтверждение гражданства США или законного постоянного проживания. Источник: WA DOL, «Commercial learner's permit (CLP).»"},"94":{"q":"Перед тестированием на получение разрешения по опасным грузам (H) в штате Вашингтон соискатель должен пройти какой вид ELDT?","options":["Теоретическую (на знание) подготовку у провайдера из FMCSA Training Provider Registry, проходимую до экзамена на знание H","Полный курс практического вождения на площадке и дороге","Никакой подготовки вообще, только проверку анкетных данных","Дорожную подготовку под надзором Washington State Patrol"],"explanation":"Для разрешения по опасным грузам (H) ELDT является только теоретической и должна быть пройдена у провайдера из Training Provider Registry перед сдачей государственного экзамена на знание H. Источник: правило FMCSA об ELDT; FMCSA Training Provider Registry, «ELDT Applicability.»"},"95":{"q":"Как устроен стандартный цикл продления неулучшенного вашингтонского CDL?","options":["Его необходимо продлевать каждые 6 лет","Его необходимо продлевать каждые 4 года","Его необходимо продлевать каждые 10 лет","После выдачи он никогда не истекает"],"explanation":"Стандартный вашингтонский CDL выдаётся на 6-летний цикл. Источник: WA DOL, «Renew your CDL.»"},"96":{"q":"За какое время до истечения срока вашингтонский водитель может продлить CDL?","options":["До 1 года до истечения срока","До 6 месяцев до истечения срока","Только в точную дату истечения срока","До 90 дней до истечения срока"],"explanation":"DOL разрешает продление CDL за срок до 1 года до истечения срока действия прав. Источник: WA DOL, «Renew your CDL.»"},"97":{"q":"Что происходит, если вашингтонский CDL просрочен более чем на 8 лет?","options":["Водитель не может продлить и должен начать процесс получения CDL заново","Водитель всё ещё может продлить онлайн с небольшим штрафом за просрочку","Права автоматически восстанавливаются после проверки зрения","Водитель может продолжать ездить по просроченной карте ещё один год"],"explanation":"Если вашингтонский CDL просрочен более чем на 8 лет, его нельзя продлить, и водитель должен начать процесс лицензирования заново. Источник: WA DOL, «Renew your CDL.»"},"98":{"q":"Сколько раз можно продлить вашингтонский CLP и при каком условии?","options":["Один раз, если продлить в течение 30 дней с момента истечения срока, что продлевает его ещё на 180 дней","Неограниченное число раз, пока обладатель продолжает учиться","Дважды за календарный год независимо от сроков","Его нельзя продлить никогда; должно быть выдано новое"],"explanation":"Вашингтонский CLP может быть продлён только один раз, в течение 30 дней с момента истечения срока, что продлевает его ещё на 180 дней. Источник: WA DOL, «Commercial learner's permit (CLP).»"},"99":{"q":"В штате Вашингтон какие события, связанные с CDL, требуют Entry-Level Driver Training (ELDT) у провайдера из Training Provider Registry?","options":["Получение первого CDL класса A или класса B, повышение с класса B до класса A и получение первого разрешения H, P или S","Только получение первого CDL класса C","Только продление существующего CDL","Каждая повторная сдача экзамена на знание после провала"],"explanation":"ELDT применяется к впервые подающим заявление на класс A или класс B, при повышении с класса B до класса A и при получении первого разрешения по опасным грузам (H), пассажирского (P) или школьного автобуса (S); штат Вашингтон проверяет прохождение перед тестированием. Источник: FMCSA Training Provider Registry, «ELDT Applicability.»"}},"tr":{"0":{"q":"Özel bir izin olmadan, Washington kamu karayollarında bir aracın veya yükünün izin verilen azami dış genişliği nedir?","options":["8 feet (96 inch)","8 feet 6 inch (102 inch)","9 feet (108 inch)","10 feet (120 inch)"],"explanation":"RCW 46.44.010, belirli güvenlik cihazları ve aynalar hariç olmak üzere, bir aracın veya yükünün toplam dış genişliğini 8 feet 6 inch (102 inch) ile sınırlar. Bu aynı zamanda federal standarttır. Kaynak: RCW 46.44.010; WSDOT Ticari Araç Kılavuzu."},"1":{"q":"Özel bir izin olmadan Washington karayollarında bir araç için, yük dahil, izin verilen azami yasal yükseklik nedir?","options":["13 feet 6 inch","14 feet","14 feet 6 inch","15 feet"],"explanation":"RCW 46.44.020, bir aracın yüklü ya da yüksüz olarak, üzerinde durduğu zeminden itibaren 14 feet yüksekliği aşmasını yasa dışı kılar. Kaynak: RCW 46.44.020."},"2":{"q":"İzin olmadan Washington karayollarında tek bir aracın (kombinasyon değil) izin verilen azami yasal uzunluğu nedir?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"RCW 46.44.030, tek bir aracın genel azami uzunluğunu 40 feet olarak belirler; otobüslere, karavanlara ve seyahat römorklarına 46 feet'e kadar izin veren istisnalar vardır. Kaynak: RCW 46.44.030."},"3":{"q":"Washington karayollarında bir çekici-yarı römork kombinasyonunda, yarı römorkun tek başına izin verilen azami uzunluğu nedir (izinsiz)?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"RCW 46.44.030, yarı römork uzunluğu 53 feet'i aşan bir çekici-yarı römorkun kullanılmasını yasaklar. Kaynak: RCW 46.44.030."},"4":{"q":"Washington'ın özel bir izin olmadan herhangi bir tek aksta izin verdiği azami brüt yük nedir?","options":["18.000 pound","20.000 pound","22.400 pound","24.000 pound"],"explanation":"RCW 46.44.041, herhangi bir tek akstaki brüt yükün 20.000 pound'u aşmasını yasaklar. Kaynak: RCW 46.44.041; WSDOT 'Yasal araç ağırlığı'."},"5":{"q":"Washington'da bir tandem aks grubunda izin verilen standart azami brüt yük nedir (izinsiz)?","options":["32.000 pound","34.000 pound","36.000 pound","40.000 pound"],"explanation":"RCW 46.44.041 ve Washington'da kabul edilen federal standart uyarınca, bir tandem aks grubu 34.000 pound ile sınırlıdır. Kaynak: RCW 46.44.041."},"6":{"q":"Washington'da Interstate karayolu sisteminde izin olmadan izin verilen azami brüt araç ağırlığı nedir?","options":["80.000 pound","90.000 pound","100.000 pound","105.500 pound"],"explanation":"Interstate sisteminde, Washington tarafından kabul edilen federal yasa brüt ağırlığı 80.000 pound ile sınırlar. Daha yüksek değerler yalnızca belirli Interstate dışı eyalet karayollarında geçerlidir. Kaynak: RCW 46.44.041; 23 CFR 658.17; WSDOT."},"7":{"q":"Washington'ın ağırlık tablosuna göre, yeterli aks ve dingil mesafesiyle Interstate dışı eyalet karayollarında yasal olarak taşınabilecek azami toplam brüt araç ağırlığı nedir (fazla ağırlık izni olmadan)?","options":["80.000 pound","98.000 pound","105.500 pound","120.000 pound"],"explanation":"RCW 46.44.041'in dingil mesafesi/aks ağırlığı tablosu, aks aralığı ve sayısı uygun olduğunda Interstate dışı karayollarında 105.500 pound'a kadar brüt ağırlığa izin verir. Interstate sistemi 80.000 pound ile sınırlı kalır. Kaynak: RCW 46.44.041; WSDOT."},"8":{"q":"Washington, ardışık akslardan oluşan bir grupta izin verilen azami ağırlığı belirlemek için hangi formülü kullanır?","options":["W = 500[LN/(N-1) + 12N + 36]","W = 1000(L + N + 12)","W = 700[LN/(N+1) + 10N]","W = 250[LN + 24N + 40]"],"explanation":"RCW 46.44.041, federal köprü formülü W = 500[LN/(N-1) + 12N + 36]'yı içerir; burada L grubun en uçtaki aksları arasındaki mesafe ve N aks sayısıdır. Kaynak: RCW 46.44.041; FHWA Köprü Formülü."},"9":{"q":"Washington köprü formülü W = 500[LN/(N-1) + 12N + 36]'da 'N' neyi temsil eder?","options":["Gruptaki aks sayısını","En uçtaki akslar arasındaki feet cinsinden mesafeyi","Yükün ton cinsinden net ağırlığını","Çekiş aksındaki lastik sayısını"],"explanation":"RCW 46.44.041 tarafından kabul edilen köprü formülünde N, dikkate alınan gruptaki aks sayısı ve L o grubun en uçtaki aksları arasındaki feet cinsinden aralıktır. Kaynak: RCW 46.44.041; FHWA."},"10":{"q":"Washington'da bir tek aksta izin verilen brüt ağırlık, lastik genişliği ile de sınırlanır. Lastik genişliğinin her bir inch'i başına azami ağırlık nedir?","options":["inch başına 500 pound","inch başına 550 pound","inch başına 600 pound","inch başına 700 pound"],"explanation":"RCW 46.44.042, aks ağırlığını lastik genişliğinin inch'i başına 600 pound ile sınırlar. Brüt aks ağırlığı; lastik boyutu, aks ağırlığı ve ağırlık tablosundan en kısıtlayıcı olan tarafından belirlenir. Kaynak: RCW 46.44.042; WSDOT."},"11":{"q":"Washington'da iki ardışık tandem aks grubunun her biri 34.000 pound taşıyabilir; ancak yalnızca iki grubun ilk ve son aksları arasındaki mesafe en az ne kadar olduğunda?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"RCW 46.44.041, iki ardışık tandem aks grubunun her birinin 34.000 pound taşımasına yalnızca grupların ilk ve son aksları arasındaki toplam mesafe 36 feet veya daha fazla olduğunda izin verir. Kaynak: RCW 46.44.041."},"12":{"q":"Bir taşıyıcının Washington'ın yasal boyut veya ağırlık sınırlarını aşan bir yükü taşıması gerekir. Eyalet karayollarında hareket için özel izni kim verir?","options":["Washington Eyalet Polisi","Department of Licensing (DOL)","Washington Eyalet Ulaştırma Departmanı (WSDOT)","İlçe şerif ofisi"],"explanation":"RCW 46.44.090, WSDOT'a eyalet karayolları için özel boyut/ağırlık aşımı izinleri verme yetkisi tanır; kendi yetki alanlarındaki yollar için bunları yerel makamlar verir. Kaynak: RCW 46.44.090; WSDOT Ticari Araç İzinleri."},"13":{"q":"RCW 46.44.090 uyarınca, Washington'da özel bir boyut veya ağırlık aşımı izni almak için bir başvuru sahibinin genel olarak neyi göstermesi gerekir?","options":["Yazılı bir başvuru ve gösterilen haklı bir gerekçe","Federal bir muafiyet mektubu","1 milyon dolarlık kargo sigortası kanıtı","Beş yıl boyunca temiz bir sürüş sicili"],"explanation":"RCW 46.44.090, WSDOT veya yerel makamların yazılı (veya elektronik) başvuru ve haklı bir gerekçe gösterilmesi üzerine özel bir izin verebileceğini öngörür. Kaynak: RCW 46.44.090."},"14":{"q":"Washington'da boyut/ağırlık aşımı özel izni ne zaman gereklidir?","options":["Yalnızca araç boş olduğunda","Araç veya yük, RCW 46.44.010 ile 46.44.041 arasındaki yasal sınırları her aştığında","Yalnızca paralı yollarda","Yalnızca 53 feet'ten uzun araçlar için"],"explanation":"RCW 46.44.090, RCW 46.44.010, .020, .030, .034 ve .041'de belirlenen azami değerleri aşan bir aracı veya yükü hareket ettirmek için özel bir izin gerektirir. Küçültülemeyen, bölünemez bir yükün bölünmesi yerine izne tabi tutulması gerekir. Kaynak: RCW 46.44.090."},"15":{"q":"Washington, tomruk kamyonlarının özel bir 'tomruk toleransı' izni almasına olanak tanır. Bu izin, aksi takdirde yasal olan azaminin üzerinde ne kadar ek brüt ağırlığa izin verir?","options":["4.000 pound'a kadar","6.800 pound'a kadar","10.000 pound'a kadar","12.500 pound'a kadar"],"explanation":"RCW 46.44.047, tomruk taşıyan tomruk kamyonlarının, özel bir tomruk toleransı izni kapsamında azami yasal brüt ağırlığı (tam ruhsatlı olduğunda 68.000 pound) 6.800 pound'dan fazla olmamak kaydıyla aşmasına izin verir. Kaynak: RCW 46.44.047."},"16":{"q":"Tam 12 aylık dönem için verildiğinde, Washington tomruk toleransı özel izninin yıllık ücreti nedir?","options":["25 dolar","50 dolar","100 dolar","120 dolar"],"explanation":"RCW 46.44.047, tomruk toleransı özel izin ücretini 1 Nisan'da başlayan 12 aylık dönem için 50 dolar olarak belirler; izin yılının ilerleyen döneminde verilmesi halinde indirimli orantılı ücretler uygulanır. Kaynak: RCW 46.44.047."},"17":{"q":"Washington'da bir çekici ve iki römorktan oluşan bir kombinasyonda ('double'), izinsiz olarak iki römorkun azami birleşik uzunluğu nedir?","options":["56 feet","61 feet","65 feet","68 feet"],"explanation":"RCW 46.44.030, iki römorklu bir çekiciyi römorkların birleşik uzunluğu 61 feet'i aşmayacak şekilde sınırlar. Kaynak: RCW 46.44.030."},"18":{"q":"WSDOT tarafından öz-düzenlenen tek seferlik bir boyut aşımı izni, daha özel bir izin gerekmeden önce hangi azami boyutlara ve ağırlığa kadar harekete olanak tanır?","options":["12 ft genişlik, 14 ft yükseklik, 100.000 lb","14 ft genişlik, 15 ft yükseklik, 150.000 lb","16 ft genişlik, 16 ft yükseklik, 200.000 lb","20 ft genişlik, 18 ft yükseklik, 250.000 lb"],"explanation":"WSDOT'un öz-düzenleme izin sistemi, 16 feet genişliğe, 16 feet yüksekliğe, 125 feet yük uzunluğuna ve 200.000 pound'a kadar olan yükleri kapsar; daha büyük taşımalar doğrudan WSDOT izin ofisi tarafından verilen bir izin gerektirir. Kaynak: WSDOT Ticari Araç İzinleri, 'Bir izni öz-düzenleyin.'"},"19":{"q":"Hangi kurumun düzenlemeleri, Washington'ın federal karayolu finansmanını sürdürmek için uymak zorunda olduğu bir sınır olan Interstate sisteminde brüt ağırlığı 80.000 pound ile sınırlar?","options":["Çevre Koruma Ajansı","23 CFR Part 658 kapsamında Federal Karayolu İdaresi (FHWA)","Federal Motorlu Taşıyıcı Güvenlik İdaresi tıbbi bölümü","Eyaletlerarası Ticaret Komisyonu"],"explanation":"80.000 pound'luk Interstate brüt ağırlık sınırı ve köprü formülü, Washington'ın Interstate sistemi için RCW 46.44.041'de kabul ettiği 23 CFR Part 658'deki FHWA düzenlemelerinden gelir. Daha yüksek Interstate dışı sınırlar Washington'ın kazanılmış haklarını yansıtır. Kaynak: 23 CFR 658.17; RCW 46.44.041."},"20":{"q":"Washington'da, brüt kombinasyon ağırlık derecesi (GCWR) 26.001 pound veya daha fazla olan ve çekilen ünite(ler)in 10.000 pound GVWR'yi aştığı bir kombinasyon aracı kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Washington, GCWR'si 26.001 pound veya daha fazla olan ve çekilen araç(lar)ın GVWR'si 10.000 pound'un üzerinde olan bir kombinasyon aracı için Class A CDL gerektirir. Kaynak: WA DOL, CDL Türleri / Washington Eyaleti Ticari Sürücü Kılavuzu."},"21":{"q":"Washington kurallarına göre, bir Class B CDL hangi tür aracı kapsar?","options":["GVWR'si 26.001 pound veya daha fazla olan herhangi bir tek araç (ve 10.000 lb veya daha az bir ünite çeken)","10.000 pound'un üzerinde bir römork çeken bir kombinasyon aracı","Yalnızca 16 veya daha fazla yolcu taşıyan araçlar","Yalnızca tehlikeli maddeler için plakartlanmış araçlar"],"explanation":"Washington'da bir Class B CDL, GVWR'si 26.001 pound veya daha fazla olan herhangi bir tek aracı kapsar; buna 10.000 pound veya daha az dereceli bir römork çeken böyle bir araç da dahildir. Daha ağır bir çekilen üniteye sahip kombinasyonlar Class A gerektirir. Kaynak: WA DOL, CDL Türleri."},"22":{"q":"Bir araç Class A veya B ağırlık eşiklerini karşılamadığında ancak en az kaç kişi (sürücü dahil) taşıyacak şekilde tasarlandığında ya da plakart gerektiren tehlikeli maddeler taşıdığında bir Washington Class C CDL gereklidir?","options":["16 veya daha fazla","12 veya daha fazla","20 veya daha fazla","10 veya daha fazla"],"explanation":"Bir Class C CDL, araç Class A veya B için çok hafif olduğunda, sürücü dahil 16 veya daha fazla kişi taşıyan ya da plakart gerektiren tehlikeli madde taşıyan araçlar için geçerlidir. Kaynak: WA DOL, CDL Türleri."},"23":{"q":"Washington, double veya triple römork setleri çeken bir sürücü için hangi onayı (endorsement) gerektirir?","options":["T onayı","N onayı","H onayı","X onayı"],"explanation":"T (Double/Triple) onayı, Washington'da double veya triple römork setleri çeken sürücüler için gereklidir ve yalnızca bir bilgi testini geçerek alınır. Kaynak: WA DOL, Onaylar ve kısıtlamalar."},"24":{"q":"Washington'da, N (Tank Aracı) onayı; bireysel dereceli kapasitesi 119 galondan fazla olan bir tankta sıvı veya gaz halindeki maddeleri taşımak üzere tasarlanmış ve toplam dereceli kapasitesi en az kaç galon olan bir CMV için gereklidir?","options":["1.000 galon","500 galon","750 galon","1.500 galon"],"explanation":"Washington, bireysel dereceli kapasitesi 119 galonun üzerinde ve toplam dereceli kapasitesi 1.000 galon veya daha fazla olan bir tankta sıvı/gaz halindeki maddeleri taşımak üzere tasarlanmış herhangi bir CMV için N onayını gerektirir. Kaynak: WA DOL, Onaylar ve kısıtlamalar."},"25":{"q":"16 veya daha fazla kişi (sürücü dahil) taşımak üzere tasarlanmış bir yolcu aracını kullanmak için hangi Washington CDL onayı gereklidir?","options":["P onayı","S onayı","T onayı","N onayı"],"explanation":"P (Yolcu) onayı, Washington'da sürücü dahil 16 veya daha fazla kişi taşımak üzere tasarlanmış yolcu araçlarının sürücüleri için gereklidir. Kaynak: WA DOL, Onaylar ve kısıtlamalar."},"26":{"q":"Washington'da, S (Okul Otobüsü) onayı neyi kullanmak için gereklidir?","options":["Çocukları okula gidiş-gelişte veya okul etkinliklerinde taşımak için kullanılan her boyuttaki okul otobüsü","Yalnızca 16 veya daha fazla çocuk taşıyan okul otobüsleri","Yalnızca dizel motorlu okul otobüsleri","Yalnızca ilçe sınırları ötesinde işletilen okul otobüsleri"],"explanation":"Washington, çocukları okula gidiş-gelişte veya okul etkinlikleriyle bağlantılı olarak taşımak için düzenli olarak kullanılan her boyuttaki okul otobüsünü kullanmak için S onayını gerektirir. Kaynak: WA DOL, Onaylar ve kısıtlamalar."},"27":{"q":"Washington'da bir HazMat (H) onayı almadan önce, bir sürücünün parmak izi alımı dahil olmak üzere hangi kurum tarafından yürütülen federal bir güvenlik tehdit değerlendirmesini tamamlaması gerekir?","options":["Ulaştırma Güvenliği İdaresi (TSA)","Washington Eyalet Polisi (WSP)","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)","Yalnızca Department of Licensing (DOL)"],"explanation":"Washington, H onayı verilmeden önce HazMat başvuru sahiplerinin parmak izinin alınmasını ve bir TSA Tehlikeli Maddeler Onayı Tehdit Değerlendirmesini geçmelerini gerektirir. Kaynak: WA DOL, Tehlikeli maddeler onayı (hazmat); TSA HTAP."},"28":{"q":"Bir Washington CDL'sindeki HazMat (H) onayının, yeni bir TSA tehdit değerlendirmesiyle birlikte en az hangi sıklıkta yenilenmesi gerekir?","options":["Her 5 yılda bir","Her 2 yılda bir","Her 8 yılda bir","Her 10 yılda bir"],"explanation":"Washington'da uygulanan federal kurallar, yeni parmak izleri ve yeni bir TSA arka plan kontrolü dahil olmak üzere HazMat onayının en az her 5 yılda bir yenilenmesini gerektirir. Kaynak: WA DOL, Hazmat onayı; TSA HTAP."},"29":{"q":"Yalnızca EYALET İÇİ (intrastate) sürüş için bir Washington CDL'si almanın asgari yaşı nedir?","options":["18 yaş","21 yaş","19 yaş","16 yaş"],"explanation":"Washington, en az 18 yaşında olan bir sürücünün eyalet içi ticaret için bir CDL almasına izin verir; eyaletlerarası işletim 21 yaş gerektirir. Kaynak: WA DOL, Ticari sürücü belgesi (CDL) alma."},"30":{"q":"EYALETLERARASI ticarette (eyalet sınırları ötesinde) sürüşe izin veren bir Washington CDL'si almanın asgari yaşı nedir?","options":["21 yaş","18 yaş","19 yaş","25 yaş"],"explanation":"Washington ve federal kurallar uyarınca, bir sürücünün ticari bir motorlu aracı eyalet sınırları ötesinde kullanması için en az 21 yaşında olması gerekir. Kaynak: WA DOL, Ticari sürücü belgesi (CDL) alma."},"31":{"q":"Washington'da, bir Ticari Öğrenci Ehliyeti (CLP) verildiği tarihten itibaren ne kadar süre geçerlidir?","options":["180 gün","90 gün","1 yıl","60 gün"],"explanation":"Bir Washington CLP'si, verildiği tarihten itibaren 180 gün geçerlidir ve süresinin dolmasından önceki 30 gün içinde ek 180 gün için bir kez yenilenebilir. Kaynak: WA DOL, Ticari öğrenci ehliyeti (CLP)."},"32":{"q":"Orijinal bir Washington CLP'si verildikten sonra, bir sürücünün CDL beceri testine girmeden önce ne kadar beklemesi gerekir?","options":["14 takvim günü","7 takvim günü","30 takvim günü","10 iş günü"],"explanation":"Washington tarafından kabul edilen federal kurallar, orijinal veya yükseltilmiş bir CLP verildikten sonra sürücünün beceri testine girebilmesi için 14 takvim günü beklenmesini gerektirir. Kaynak: WA DOL, Ticari öğrenci ehliyeti (CLP)."},"33":{"q":"Bir Washington CLP'siyle sürüş sırasında, ehliyet sahibinin yanında oturan denetleyici CDL sahibinin uygun sınıf/onaylara sahip geçerli bir CDL'si olmalı ve en az ne kadar deneyime sahip olması gerekir?","options":["O araç türünde 2 yıl ve toplam 5 yıl sürüş","1 yıl CDL sürüşü","O araç türünde 6 ay","Toplam 10 yıl sürüş"],"explanation":"Washington, eşlik eden CDL sahibinin uygun onaylara, o tür araçta en az 2 yıl deneyime ve toplam en az 5 yıl sürüş deneyimine sahip olmasını gerektirir. Kaynak: WA DOL, Ticari öğrenci ehliyeti (CLP)."},"34":{"q":"Bir Washington CDL'sine başvururken hangi belge kategorisi ayrıca gerekli DEĞİLDİR?","options":["Ticari bir araca sahip olduğunuzun kanıtı","Kimlik / doğum tarihi kanıtı","Sosyal Güvenlik numarası","ABD vatandaşlığı veya yasal daimi ikamet kanıtı"],"explanation":"Washington; kimlik kanıtı, bir Sosyal Güvenlik numarası, ikamet kanıtı ve ABD vatandaşlığı ya da yasal daimi ikamet (yasal mevcudiyet) kanıtı gerektirir; ticari bir araca sahip olmak gerekli değildir. Kaynak: WA DOL, CDL için onaylanmış belgeler."},"35":{"q":"Bir Washington CDL'si için yasal mevcudiyeti kanıtlamak amacıyla, bir başvuru sahibinin aşağıdakilerden hangisini sunması gerekir?","options":["ABD pasaportu, doğum belgesi veya Daimi İkamet Kartı gibi federal olarak onaylanmış bir belge (orijinal, fotokopi değil)","Herhangi iki fatura","Noter onaylı bir vatandaşlık beyanı","Yalnızca bir seçmen kayıt kartı"],"explanation":"Washington; ABD pasaportu, devlet tarafından verilen doğum belgesi veya Daimi İkamet Kartı gibi, ABD vatandaşlığını ya da yasal daimi ikameti kanıtlayan kabul edilebilir bir orijinal belge gerektirir; fotokopiler kabul edilmez. Kaynak: WA DOL, CDL için onaylanmış belgeler."},"36":{"q":"Giriş Düzeyi Sürücü Eğitimi (ELDT), Washington'da hangi tarihte ya da sonrasında bir CLP alan başvuru sahipleri için zorunlu hale geldi?","options":["7 Şubat 2022","1 Ocak 2020","1 Eylül 2021","1 Temmuz 2023"],"explanation":"Washington'da uygulanan federal ELDT kuralları, 7 Şubat 2022'de veya sonrasında bir CLP alan başvuru sahipleri için kayıtlı bir sağlayıcıdan eğitim gerektirir. Kaynak: FMCSA Giriş Düzeyi Sürücü Eğitimi; WA DOL, CDL eğitim gereksinimleri."},"37":{"q":"Washington'daki ELDT kurallarına göre, hangi belgeyi almak isteyen bir sürücünün test öncesinde FMCSA Eğitim Sağlayıcı Sicili'nde (Training Provider Registry) listelenen bir sağlayıcıdan eğitim tamamlaması gerekir?","options":["İlk kez Class A veya Class B CDL ya da ilk kez bir P, S veya H onayı","Yalnızca T (double/triple) onayı","Yalnızca N (tank) onayı","Sınıf değişikliği olmayan mevcut bir CDL'nin yenilenmesi"],"explanation":"ELDT, ilk kez Class A ve Class B CDL başvuru sahipleri (ve B'den A'ya yükseltmeler) ile ilk kez yolcu (P), okul otobüsü (S) ve HazMat (H) onayı başvuru sahipleri için geçerlidir; sağlayıcının FMCSA Eğitim Sağlayıcı Sicili'nde olması gerekir. Kaynak: FMCSA ELDT Uygulanabilirliği."},"38":{"q":"Bir Washington CDL'sine başvururken, 'Muafiyetsiz Eyaletlerarası' (Non-Excepted Interstate) tıbbi öz-beyan kategorisi sürücünün şu anlama gelir:","options":["Eyaletlerarası ticarette faaliyet gösterir ve geçerli bir DOT tıbbi muayene uzmanı belgesini korumalıdır","Yalnızca Washington içinde faaliyet gösterir ve tüm tıbbi gereksinimlerden muaftır","Eyaletlerarası ticarette faaliyet gösterir ancak tıbbi belgeden muaftır","Yalnızca özel mülkte sürüş yapar ve hiçbir belgeye ihtiyaç duymaz"],"explanation":"Dört öz-beyan kategorisinden 'Muafiyetsiz Eyaletlerarası', sürücünün eyalet sınırları ötesinde faaliyet gösterdiği ve geçerli bir DOT tıbbi muayene uzmanı belgesine sahip olup bunu koruması gerektiği anlamına gelir. Kaynak: FMCSA tıbbi öz-beyan kategorileri; WA DOL, CDL alma."},"39":{"q":"Aşağıdakilerden hangisi, bir Washington başvuru sahibinin seçmesi gereken dört CDL tıbbi öz-beyan kategorisinden biridir?","options":["Muafiyetli Eyalet İçi (Excepted Intrastate)","Geçici Eyaletlerarası (Provisional Interstate)","Koşullu Eyalet İçi (Conditional Intrastate)","Kısıtlı Eyaletlerarası (Restricted Interstate)"],"explanation":"Washington'da kullanılan dört FMCSA öz-beyan kategorisi şunlardır: Muafiyetsiz Eyaletlerarası, Muafiyetli Eyaletlerarası, Muafiyetsiz Eyalet İçi ve Muafiyetli Eyalet İçi. Kaynak: FMCSA tıbbi öz-beyan; WA DOL, CDL alma."},"40":{"q":"Washington'da, bir kişinin yasal olarak ticari bir motorlu aracı (CMV) kullanabileceği azami kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.04","0.08","0.02","0.10"],"explanation":"Washington yasası (ve 49 CFR 383.51/392.5'i izleyen Washington CDL Kılavuzu), bir CMV'yi 0.04 veya daha yüksek bir BAC ile kullanmayı yasa dışı kılar — ticari olmayan sürücüler için geçerli olan 0.08 sınırının yarısı. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51."},"41":{"q":"Washington'ın zımni rıza yasası uyarınca, bir CDL'ye sahip olarak ve bir araç kullanarak, bir kolluk görevlisinin sürüş yeteneğinin bozulduğundan şüphelenmek için makul gerekçeleri olması halinde sürücünün neyi yapmayı kabul etmiş sayıldığı varsayılır?","options":["Alkol veya uyuşturucu için bir nefes veya kan testine tabi olmak","Yol kenarında sabit bir nakit teminat ödemek","CDL'yi anında kalıcı olarak teslim etmek","Önce 12 saatlik bir alkol eğitim dersini tamamlamak"],"explanation":"Washington'ın zımni rıza yasası (RCW 46.20.308), eyalette araç kullanan herkesin, bir görevlinin sürüş yeteneğinin bozulduğundan şüphelenmek için makul gerekçeleri olduğunda kimyasal testlere (nefes veya kan) rıza gösterdiği anlamına gelir. Kaynak: RCW 46.20.308; Washington DOL CDL Kılavuzu."},"42":{"q":"Bir Washington CDL sahibi, plakartsız bir ticari araç kullanırken ilk DUI suçundan mahkum edilir. Bu ilk büyük suç için diskalifiye süresi nedir?","options":["1 yıl","3 yıl","60 gün","6 ay"],"explanation":"İlk büyük suç (DUI, BAC 0.04+ veya test reddi dahil) bir CDL'yi 1 yıl süreyle diskalifiye eder. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 1."},"43":{"q":"Washington'da, sürücü olay sırasında plakartlı tehlikeli madde taşıyorsa, ilk büyük suç (DUI veya BAC 0.04+ gibi) için CDL diskalifiye süresi ne kadardır?","options":["3 yıl","1 yıl","5 yıl","120 gün"],"explanation":"Plakartlı tehlikeli madde taşınırken işlenen ilk büyük suç, diskalifiyeyi 1 yıldan 3 yıla çıkarır. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 1."},"44":{"q":"Washington'da ikinci bir büyük suç (örneğin ikinci bir DUI veya ikinci bir BAC 0.04+ mahkumiyeti) için CDL diskalifiye süresi nedir?","options":["Ömür boyu (yaşam boyu)","10 yıl","5 yıl","3 yıl"],"explanation":"İkinci bir büyük suç, ömür boyu CDL diskalifiyesiyle sonuçlanır; Washington, ömür boyu diskalifiyeden yeniden uygunluk kazanamayacağınızı belirtir. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 1."},"45":{"q":"Bir Washington CDL sahibi, plakartsız bir araç kullanırken bir görevli tarafından yasal olarak talep edildiğinde bir nefes veya kan testine tabi olmayı reddeder. Bu ilk ret için diskalifiye süresi nedir?","options":["1 yıl","90 gün","3 yıl","60 gün"],"explanation":"Kimyasal testi reddetmek bir büyük suç olarak değerlendirilir ve ilk reddte CDL'yi 1 yıl süreyle diskalifiye eder (plakartlı tehlikeli madde taşınıyorsa 3 yıl). Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 1."},"46":{"q":"Washington'da, bir nefes veya kan testini reddetmek, ömür boyu diskalifiyeye doğru sayılan bir büyük suçtur. Bir test reddinin ardından daha sonra ayrı bir DUI mahkumiyetinin gelmesi hangi diskalifiyeyle sonuçlanır?","options":["Ömür boyu diskalifiye (iki büyük suç)","Yalnızca toplam 1 yıllık diskalifiye","120 günlük bir diskalifiye","İlkinin ötesinde ek diskalifiye yok"],"explanation":"Hem bir test reddi hem de bir DUI büyük suçtur; ayrı olaylardan kaynaklanan iki büyük suç, ömür boyu bir CDL diskalifiyesini tetikler. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 1."},"47":{"q":"3 yıllık bir dönem içinde (ayrı olaylarda) kaç ciddi trafik ihlali, Washington'daki en kısa ciddi ihlal CDL diskalifiyesini tetikler?","options":["2 ciddi ihlal","3 ciddi ihlal","1 ciddi ihlal","4 ciddi ihlal"],"explanation":"3 yıl içinde ayrı olaylardan kaynaklanan iki ciddi trafik ihlali 60 günlük bir diskalifiyeyi tetikler; tek başına ilk ciddi ihlal diskalifiyeye neden olmaz. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 2."},"48":{"q":"Washington'da 3 yıllık bir dönem içinde ayrı olaylarda işlenen iki ciddi trafik ihlali için CDL diskalifiye süresi nedir?","options":["60 gün","120 gün","30 gün","90 gün"],"explanation":"3 yıl içinde iki ciddi trafik ihlali (ayrı olaylar) 60 günlük bir CDL diskalifiyesiyle sonuçlanır. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 2."},"49":{"q":"Washington'da 3 yıllık bir dönem içinde ayrı olaylarda işlenen üç ciddi trafik ihlali için CDL diskalifiye süresi nedir?","options":["120 gün","60 gün","1 yıl","180 gün"],"explanation":"3 yıl içinde üç ciddi trafik ihlali (ayrı olaylar) 120 günlük bir CDL diskalifiyesiyle sonuçlanır. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 2."},"50":{"q":"Bir Washington CDL sahibinin, bunun bir 'ciddi trafik ihlali' olarak sayılması için belirtilen hız sınırının ne kadar üzerinde ceza alması gerekir?","options":["Sınırın 15 mph veya daha fazla üzerinde","Sınırın 10 mph veya daha fazla üzerinde","Sınırın 20 mph veya daha fazla üzerinde","Sınırın 25 mph veya daha fazla üzerinde"],"explanation":"Belirtilen sınırın 15 mph veya daha fazla üzerinde hız yapmak, Washington'da CDL amaçları için bir ciddi trafik ihlali olarak listelenir. Kaynak: Washington DOL ciddi trafik suçları sayfası; 49 CFR 383.51 Tablo 2."},"51":{"q":"Aşağıdakilerden hangisi bir Washington CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Çok yakın takip (tampona tampon sürme)","Park yasağı bölgesinde park etmek","Yanmış bir plaka aydınlatma lambası","Bir tescil etiketini göstermemek"],"explanation":"Çok yakın takip, Washington'ın ciddi trafik ihlali listesindedir (dikkatsiz sürüş, hatalı şerit değiştirme, 15+ üzeri hız ve bir CMV'de mesaj yazma/telefon kullanımı ile birlikte). Ekipman ve park ihlalleri değildir. Kaynak: Washington DOL ciddi trafik suçları sayfası; 49 CFR 383.51."},"52":{"q":"Washington'ın kuralına göre, ticari bir motorlu araç kullanırken mesaj yazmak, CDL diskalifiye amaçları için nasıl sınıflandırılır?","options":["Bir ciddi trafik ihlali","Bir büyük suç","Bir hizmet dışı emri (out-of-service) ihlali","Bildirime tabi olmayan bir ekipman ihlali"],"explanation":"Bir CMV kullanırken mesaj yazmak (ve bir CMV kullanırken elde tutulan bir telefon kullanmak) bir ciddi trafik ihlalidir, bu nedenle 3 yıl içinde bunlardan ikisi 60 günlük bir diskalifiye getirir. Kaynak: Washington DOL ciddi trafik suçları sayfası; FMCSA 392.80/392.82."},"53":{"q":"Washington'da kabul edilen federal kurallar, bir CMV sürücüsünün sürüş sırasında elde tutulan bir cep telefonu kullanmasını yasaklar. Bu elde tutulan telefon/mesaj kısıtlamasını ihlal etmek için yaklaşık azami sürücü hukuki cezası nedir?","options":["Yaklaşık 2.750 dolara kadar","Yaklaşık 250 dolara kadar","Yaklaşık 500 dolara kadar","Yaklaşık 1.000 dolara kadar"],"explanation":"CMV sürücüleri tarafından elde tutulan telefon kullanımı ve mesaj yazmaya ilişkin federal kısıtlama (FMCSA 392.80/392.82), Washington'da uygulanır ve yaklaşık 2.750 dolara kadar sürücü hukuki cezaları taşır. Kaynak: FMCSA 392.82; Washington DOL CDL Kılavuzu."},"54":{"q":"Washington'da, bir CMV kullanırken bir demiryolu-karayolu hemzemin geçit ihlalinden ilk mahkumiyet için asgari CDL diskalifiye süresi nedir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Bir CMV'de ilk demiryolu-karayolu hemzemin geçit ihlali, CDL'yi 60 günden az olmamak üzere diskalifiye eder. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 3."},"55":{"q":"Washington'da, 3 yıllık bir dönem içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali için asgari CDL diskalifiye süresi nedir?","options":["120 gün","60 gün","1 yıl","180 gün"],"explanation":"3 yıl içinde ikinci bir demiryolu hemzemin geçit ihlali, CDL'yi 120 günden az olmamak üzere diskalifiye eder. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 3."},"56":{"q":"Washington'da, 3 yıllık bir dönem içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali için asgari CDL diskalifiye süresi nedir?","options":["1 yıl","120 gün","60 gün","3 yıl"],"explanation":"3 yıl içinde üçüncü bir demiryolu hemzemin geçit ihlali, CDL'yi 1 yıldan az olmamak üzere diskalifiye eder. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 3."},"57":{"q":"Washington'da, hazmat olmayan bir CMV kullanırken bir hizmet dışı (OOS) emrinin ilk ihlali için diskalifiye süresi nedir?","options":["180 günden az ve 1 yıldan fazla olmamak üzere","60 günden az ve 120 günden fazla olmamak üzere","30 günden az ve 90 günden fazla olmamak üzere","Ömür boyu diskalifiye"],"explanation":"İlk OOS emri ihlali, hazmat olmayan bir araç için CDL'yi 180 günden az ve 1 yıldan fazla olmamak üzere diskalifiye eder. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 4."},"58":{"q":"Bir Washington sürücüsü, plakartlı tehlikeli madde taşırken veya 16 ya da daha fazla yolcu taşırken ilk hizmet dışı emir ihlalini işler. Diskalifiye aralığı nedir?","options":["180 günden az ve 2 yıldan fazla olmamak üzere","180 günden az ve 1 yıldan fazla olmamak üzere","60 günden az ve 120 günden fazla olmamak üzere","1 yıldan az ve 5 yıldan fazla olmamak üzere"],"explanation":"Plakartlı hazmat taşırken veya 16+ yolcu taşırken işlenen ilk OOS emri ihlali, CDL'yi 180 günden az ve 2 yıldan fazla olmamak üzere diskalifiye eder. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 4."},"59":{"q":"Washington'da, 10 yıllık bir dönem içinde ayrı olaylardan kaynaklanan ikinci bir hizmet dışı emir ihlali (hazmat olmayan) için diskalifiye süresi nedir?","options":["2 yıldan az ve 5 yıldan fazla olmamak üzere","180 günden az ve 1 yıldan fazla olmamak üzere","1 yıldan az ve 3 yıldan fazla olmamak üzere","Ömür boyu diskalifiye"],"explanation":"10 yıl içinde ayrı olaylarda işlenen ikinci bir OOS emri ihlali (hazmat olmayan), CDL'yi 2 yıldan az ve 5 yıldan fazla olmamak üzere diskalifiye eder. Kaynak: Washington DOL CDL diskalifiye sayfası; 49 CFR 383.51 Tablo 4."},"60":{"q":"Washington'da, otomobillerin yasal olarak daha hızlı gidebileceği yerlerde bile, brüt ağırlığı 10,000 pound'un üzerindeki bir araç (veya herhangi bir kombinasyon aracı) için bir karayolundaki azami hız sınırı nedir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Washington, otomobiller için daha yüksek bir tabela sınırı olsa dahi, brüt ağırlığı 10,000 lbs'nin üzerindeki araçlar ile (otobüs hatları hariç) tüm araç kombinasyonları için hızı 60 mph ile sınırlandırır. Kaynak: RCW 46.61.410."},"61":{"q":"Gittiğiniz yönde üç veya daha fazla şeride sahip, sınırlı erişimli bir Washington otoyolunda, 10,000 pound'un üzerindeki bir kamyon veya kombinasyon (yasal bir sol dönüşe hazırlanma durumu hariç) NEREDE sürülemez?","options":["En sağdaki şerit","Herhangi bir orta şerit","Sol taraftaki şerit","Yüksek doluluklu araç (HOV) şeridi"],"explanation":"Römork çeken hiçbir araç ve 10,000 lbs'nin üzerindeki hiçbir araç veya kombinasyon, tek yönde üç veya daha fazla şeride sahip sınırlı erişimli bir yolun sol taraftaki şeridinde, yasal bir sol dönüşe hazırlanma durumu dışında sürülemez. HOV şeridi, sol taraftaki şerit olarak sayılmaz. Kaynak: RCW 46.61.100."},"62":{"q":"Bir Washington demiryolu hemzemin geçidine yaklaşırken, bir okul otobüsü veya tehlikeli madde tabelası taşıyan bir aracın sürücüsü, en yakın raya kaç fit mesafe içinde durmalıdır?","options":["50 fit içinde, ancak 15 fitten az olmamak üzere","75 fit içinde, ancak 25 fitten az olmamak üzere","40 fit içinde, ancak 10 fitten az olmamak üzere","100 fit içinde, ancak 30 fitten az olmamak üzere"],"explanation":"Washington, bir okul/yolcu otobüsü, yolcu taşıyan ticari araç veya tehlikeli madde kargo tankı sürücüsünün durma çizgisinden önce, aksi takdirde en yakın raya 50 fit içinde ancak 15 fitten az olmamak üzere durmasını gerektirir. Kaynak: RCW 46.61.350."},"63":{"q":"Bir demiryolu geçidinde durduktan sonra, Washington yasası bir otobüs veya tehlikeli madde (HazMat) tabelalı sürücüden rayları geçerken ne yapmasını gerektirir?","options":["Raylar üzerindeyken vites değiştirmeyi gerektirmeyen bir viteste geçmek ve geçerken vites değiştirmemek","Rayların orta noktasında en düşük vitese düşürmek","Geçmeden önce diferansiyel kilidini devreye almak","Yalnızca raylar üzerinde korna üç kez çaldıktan sonra geçmek"],"explanation":"Washington yasası, sürücünün geçişi yaparken vites değiştirmeyi gerektirmeyecek bir viteste geçmesi gerektiğini ve rayları geçerken vites değiştiremeyeceğini belirtir. Kaynak: RCW 46.61.350."},"64":{"q":"Washington'ın Şerit Değiştir (Move Over) yasası kapsamında, bir 'acil durum veya çalışma bölgesi', uyarı sinyalleri gösteren sabit bir acil durum veya çalışma aracının ne kadar öncesi ve sonrasına uzanan komşu şeritler olarak tanımlanır?","options":["100 fit","150 fit","200 fit","300 fit"],"explanation":"Washington, acil durum veya çalışma bölgesini, uyarı sinyallerini kullanan sabit bir yetkili acil durum aracı, çekici, polis, hizmet veya karayolu bakım aracının 200 fit öncesi ve sonrasındaki komşu şeritler olarak tanımlar. Kaynak: RCW 46.61.212."},"65":{"q":"Dörtten az şeride sahip bir Washington karayolunda, bir sürücü durmuş bir acil durum/çalışma aracından uzağa güvenli bir şekilde şerit değiştiremiyorsa, sürücü hızını tabela hız sınırının (sınırın 60 mph veya daha az olduğu yerlerde) en az ne kadar altına düşürmelidir?","options":["Tabela sınırının 5 mph altına","Tabela sınırının 10 mph altına","Tabela sınırının 15 mph altına","Tabela sınırının 20 mph altına"],"explanation":"Şerit değiştirmek güvenli olmadığında, Washington'ın Şerit Değiştir yasası hızın tabela sınırının en az 10 mph altına düşürülmesini gerektirir; tabela sınırının 60 mph'yi aştığı yerlerde ise sürücü en fazla 50 mph'ye yavaşlamalıdır. Kaynak: RCW 46.61.212."},"66":{"q":"TERS yönde seyrederken kırmızı yanıp sönen ışıklar gösteren durmuş bir okul otobüsüyle karşılaştığınızda, hangi Washington yolunda durmak zorunda DEĞİLSİNİZ?","options":["İki şeritli, bölünmemiş bir karayolu","Bir refüj veya bariyer ile ayrı yollara bölünmüş bir karayolu","Tabela hızı 25 mph olan herhangi bir şehir caddesi","Orta çift yönlü sol dönüş şeridi olan iki şeritli bir yol"],"explanation":"Ayrı yollara bölünmüş (RCW 46.61.150'ye göre) veya üç ya da daha fazla işaretli şeride sahip bir karayolunda, ters yönde giden bir okul otobüsüyle karşılaşan sürücünün durması gerekmez. Bölünmemiş iki şeritli yollarda durmalısınız. Kaynak: RCW 46.61.370."},"67":{"q":"Bölünmüş karayolu istisnasına ek olarak, durmadan karşıdan gelen, durmuş bir okul otobüsünü (ters yönde giden) hangi başka türdeki Washington yolunda geçebilirsiniz?","options":["Üç veya daha fazla işaretli trafik şeridine sahip bir yol","45 mph veya daha yüksek tabela hızı olan herhangi bir yol","En az 8 fit genişliğinde asfalt banketleri olan bir yol","Yalnızca tek bir orta dönüş şeridi olan bir yol"],"explanation":"Washington'ın okul otobüsü yasası, üç veya daha fazla işaretli trafik şeridine sahip bir karayolunda ters yönde ilerleyen bir otobüsle karşılaşan sürücülerin durması gerekmediğini ekler. Kaynak: RCW 46.61.370."},"68":{"q":"Bir Washington kamyon sürücüsü, iki şeritli, çift yönlü bir yolun banketinde durur. Dörtlü flaşörleri yaktıktan sonra, gerekli uyarı cihazları (üçgenler) kaç dakika içinde yerleştirilmelidir?","options":["5 dakika","10 dakika","15 dakika","30 dakika"],"explanation":"Bir yolda veya bankette duran bir CMV, önce dörtlü flaşörleri devreye aldıktan sonra, acil durum uyarı cihazlarını 10 dakika içinde yerleştirmelidir. Kaynak: Washington CDL Kılavuzu; 49 CFR 392.22 (Washington'da kabul edilmiştir)."},"69":{"q":"İki şeritli, çift yönlü bir Washington yolunda, durmuş bir CMV için üç reflektif üçgen nereye yerleştirilmelidir?","options":["Üçünün hepsi aracın arkasında 10, 50 ve 100 fit mesafede","Trafik tarafında 10 fit içinde, arkaya 100 fit ve öne 100 fit mesafede","Hepsi yaklaşan trafiğe doğru 10, 100 ve 200 fit mesafede","Biri çatıda ve ikisi önde ve arkada 50 fit mesafede"],"explanation":"Çift yönlü bir yolda, her iki yönden gelen trafik uyarılsın diye bir üçgeni aracın trafik tarafında 10 fit içine, birini yaklaşık 100 fit arkaya ve birini yaklaşık 100 fit öne yerleştirin. Kaynak: Washington CDL Kılavuzu; 49 CFR 392.22."},"70":{"q":"Bölünmüş veya tek yönlü bir Washington karayolunda, durmuş bir CMV'nin üç uyarı üçgeni nereye yerleştirilmelidir?","options":["Aracın arkasında yaklaşan trafiğe doğru 10, 100 ve 200 fit mesafede","Yaklaşan trafiğe doğru 10, 50 ve 100 fit mesafede","Biri önde ve ikisi arkada 100 fit mesafede","Üçünün hepsi aracın 200 fit arkasında"],"explanation":"Bölünmüş veya tek yönlü bir karayolunda, üçgenleri yaklaşan trafiğe doğru araçtan 10 fit, 100 fit ve 200 fit mesafelere yerleştirin. Kaynak: Washington CDL Kılavuzu; 49 CFR 392.22."},"71":{"q":"Washington, GVWR'si 10,000 pound'un üzerindeki araçların ve kombinasyonların, belirlenmiş dağ geçidi güzergahlarında her yıl hangi dönemde lastik zinciri taşımasını gerektirir?","options":["1 Ekim - 1 Mart","1 Kasım - 1 Nisan","1 Aralık - 31 Mart","15 Kasım - 15 Mart"],"explanation":"1 Kasım - 1 Nisan arasında, GVWR'si 10,000 lbs'nin üzerindeki araçlar ve kombinasyonlar, mevcut koşullar ne olursa olsun belirlenmiş zincir güzergahlarında (örneğin I-90, US 2 Stevens Pass, US 12 White Pass) zincir taşımalıdır. Kaynak: WSDOT ticari araç zincir gereklilikleri; WAC 204-24-050."},"72":{"q":"GVWR'si 10,000 pound'un üzerindeki bir Washington ticari aracı, zincir taşıma sezonunda belirlenmiş zincir güzergahlarında kaç adet yedek lastik zinciri taşımalıdır?","options":["En az bir yedek zincir","En az iki yedek zincir","En az dört yedek zincir","Çekiş lastiklerine zaten zincir takılıysa yedek gerekmez"],"explanation":"Washington, kırılan veya ek bir aksa ait bir zincirin değiştirilebilmesi için bu araçların 1 Kasım - 1 Nisan döneminde en az iki yedek lastik zinciri taşımasını gerektirir. Kaynak: WSDOT zincir gereklilikleri; WAC 204-24-050."},"73":{"q":"Çok şeritli bir Washington yolunda, sürekli olarak sol şeridi işgal eden yavaş bir araç hakkında eyalet yasası ne der?","options":["Araç hız sınırındaysa buna izin verilir","Diğer trafiği engellediğinde sürekli olarak sol şeritte sürmek bir trafik ihlalidir","Yalnızca 10,000 pound'un altındaki araçlara izin verilir","Sağ şerit kamyonlarla doluysa buna izin verilir"],"explanation":"Washington'ın sağda kal yasası, çok şeritli bir yolun sol şeridinde sürekli olarak sürmeyi, bu durum diğer trafiğin akışını engellediğinde bir trafik ihlali haline getirir. Kaynak: RCW 46.61.100."},"74":{"q":"Kırmızı ışıklarını ve dur levhasını gösteren, durmuş bir Washington okul otobüsünü yasa dışı şekilde geçmenin cezası, yasada şu şekilde tanımlanır:","options":["Mahkeme tarafından azaltılabilen sabit 250 dolar para cezası","Affedilemeyen, azaltılamayan veya ertelenemeyen, temel cezanın iki katı","İlk ihlal için yazılı bir uyarı","Parasal ceza olmadan yalnızca ehliyet askıya alınması"],"explanation":"Durmuş bir okul otobüsünü yasa dışı şekilde geçen bir sürücüye, RCW 46.63.110 kapsamındaki temel cezanın iki katına eşit bir parasal ceza uygulanır ve bu ceza affedilemez, azaltılamaz veya ertelenemez. Kaynak: RCW 46.61.370."},"75":{"q":"Washington State Patrol, 10,000 pound'un üzerindeki araçlar için 'Zincir Gerekli' (Chains Required) tabelası astığında, takozlu lastikler bu gereksinimi karşılar mı?","options":["Evet, takozlu lastikler zincir olarak sayılır","Evet, ancak yalnızca çekiş aksında","Hayır; takozlu lastiklerin üzerine bile zincir takılmalıdır","Yalnızca dört çekerli araçlar muaftır"],"explanation":"Takozlu lastikler, Washington'da tabelaya asılmış bir zincir gereksinimini karşılamaz; sürücüler bir zincir takma noktasını geçmek için zincir (varsa takozlu lastiklerin üzerine) takmalıdır. Kaynak: WSDOT/WSP kış zincir gereklilikleri."},"76":{"q":"Washington'da, bir araç veya yük şu boyut sınırlarından birini aştığında genellikle tek bir gabari dışı/aşırı yük izni gereklidir:","options":["8 fit 6 inç genişlik, 14 fit yükseklik veya geçerli uzunluk sınırları","10 fit genişlik, 13 fit 6 inç yükseklik veya 48 fit uzunluk","9 fit genişlik, 15 fit yükseklik veya 60 fit uzunluk","8 fit genişlik, 12 fit yükseklik veya 35 fit uzunluk"],"explanation":"Washington'ın yasal sınırları genellikle 8 fit 6 inç genişlik ve 14 fit yüksekliktir; genişliği, yüksekliği veya geçerli uzunluk sınırlarını aşmak bir WSDOT gabari dışı izni gerektirir. Kaynak: WSDOT Ticari Araç Hizmetleri gabari dışı/aşırı yük izinleri."},"77":{"q":"Washington'da ticari araç zincir gerekliliklerinin yaygın olarak uygulandığı, belirlenmiş bir zincir/çekiş güzergahı olan dağ karayolu hangisidir?","options":["Snoqualmie Pass üzerinden I-90","Seattle şehir merkezinden geçen I-5","Bellevue çevresindeki I-405","SR 520 yüzen köprü"],"explanation":"Snoqualmie Pass üzerinden I-90 (North Bend'den Ellensburg'a), US 2 Stevens Pass ve US 12 White Pass ile birlikte birincil belirlenmiş zincir güzergahıdır; I-5, I-405 ve SR 520 gibi kentsel eyaletler arası yollar dağ zincir güzergahları değildir. Kaynak: WSDOT dağ geçidi zincir gereklilikleri."},"78":{"q":"Dik bir yokuşta bulunan bir Washington kaçak kamyon kaçış rampası, tipik olarak ağır bir aracı şu şekilde durdurmak için inşa edilir:","options":["İçeri doğru ilerledikçe direnci artıran, bazen yokuş yukarı bir gevşek çakıl veya yumuşak kum yatağı","Şeride gerilmiş çelik korkuluk ağı","Kamyonun durana kadar süzülmesine izin veren yokuş aşağı asfalt bir oluk","Lastikleri yüzdüren su dolu bir tekne"],"explanation":"Washington kaçış rampaları, bazen yokuş yukarı bir eğimle gevşek çakıl veya yumuşak kum kullanır; kamyon içeri doğru ne kadar ilerlerse direnç o kadar artar ve durmasına yardımcı olur. Kaynak: Washington CDL Kılavuzu, dağ sürüşü / kaçış rampaları."},"79":{"q":"Washington'ın Şerit Değiştir yasası kapsamında, dört veya daha fazla şeride sahip bir karayolunda, yanıp sönen ışıkları olan durmuş bir acil durum/çalışma aracına yaklaşırken sürücünün İLK görevi şudur:","options":["Araç geçene kadar şeritte tamamen durmak","Dikkatli ilerlemek, hızı azaltmak ve güvenliyse ondan uzağa şerit değiştirmek","Korna çalmak ve tabela hızını korumak","Bankete geçmek ve sağdan geçmek"],"explanation":"Dört veya daha fazla şeride sahip karayollarında, sürücüler dikkatli ilerlemeli, hızı azaltmalı ve güvenli olduğunda bir şerit uzağa geçerek bölgeye yol vermelidir; yalnızca şerit değiştirmek güvenli değilse gerekli azaltılmış hıza yavaşlarlar. Kaynak: RCW 46.61.212."},"80":{"q":"Washington'da ticari sürücü belgelerini (CDL) hangi kurum verir?","options":["Washington Eyaleti Ruhsat Departmanı (DOL)","Washington State Patrol (WSP)","Washington Eyaleti Ulaştırma Departmanı (WSDOT)","Federal Motorlu Taşıyıcı Güvenlik İdaresi (FMCSA)"],"explanation":"Washington'da Ruhsat Departmanı (DOL) CDL'leri verir ve CDL sınavlarını yönetir. Kaynak: WA DOL, 'Ticari sürücü belgesi (CDL) alma.'"},"81":{"q":"Bir Washington CDL başvuru sahibi, gerekli beceri sınavını nerede yapabilir?","options":["Bir DOL sınav görevlisi veya DOL yetkili bir üçüncü taraf sınav görevlisi (TPE) ile","Yalnızca Washington State Patrol ticari araç biriminde","Yalnızca DOL web sitesi üzerinden çevrimiçi olarak","Seçtiğiniz herhangi bir FMCSA Eğitim Sağlayıcı Kayıt sicili okulunda"],"explanation":"Washington'ın CDL beceri sınavı, bir DOL sınav görevlisi veya DOL yetkili bir üçüncü taraf sınav görevlisi (TPE) tarafından yapılır. Kaynak: WA DOL, 'CDL beceri sınavı.'"},"82":{"q":"Washington CDL beceri sınavı kaç bölümden oluşur?","options":["Üç: araç (sefer öncesi) muayenesi, temel araç kontrolü ve yolda sürüş sınavı","İki: yazılı bir sınav ve bir yol sınavı","Dört: yazılı, görme, muayene ve yol sınavı","Her şeyi içeren tek bir birleşik yol sınavı"],"explanation":"Washington CDL beceri sınavının sırayla yapılan üç bölümü vardır: araç (sefer öncesi) muayenesi, temel araç kontrol becerileri ve yolda sürüş sınavı. Kaynak: WA DOL, 'CDL beceri sınavı.'"},"83":{"q":"Bir Washington Ticari Öğrenci Belgesi (CLP), verildiği tarihten itibaren ne kadar süre geçerlidir?","options":["180 gün","30 gün","1 yıl","60 gün"],"explanation":"Bir Washington CLP'si, verildiği tarihten itibaren 180 gün geçerlidir. Kaynak: WA DOL, 'Ticari öğrenci belgesi (CLP).'"},"84":{"q":"Bir Washington CLP'si verildikten sonra, belge sahibinin CDL beceri sınavına girmeden önce ne kadar beklemesi gerekir?","options":["14 takvim günü","30 takvim günü","7 takvim günü","Bekleme süresi gerekmez"],"explanation":"Washington, federal CLP kuralını yansıtacak şekilde, belge sahibinin beceri sınavına girebilmesi için orijinal veya yükseltilmiş bir CLP verildikten sonra 14 takvim günü beklenmesini gerektirir. Kaynak: WA DOL, 'Ticari öğrenci belgesi (CLP)' / 'CDL beceri sınavı.'"},"85":{"q":"Washington'da CDL beceri sınavına girmeden önce, ilk kez başvuran bir Sınıf A veya Sınıf B başvuru sahibi hangi gereksinimi tamamlamalıdır?","options":["FMCSA Eğitim Sağlayıcı Kayıt sicilinde yer alan bir sağlayıcıdan Giriş Seviyesi Sürücü Eğitimi (ELDT)","DOL'ye kaydedilmiş dört yıllık bir çıraklık","Washington State Patrol tarafından onaylanmış bir defansif sürüş kursu","WSDOT tarafından sunulan bir yol öfkesi önleme semineri"],"explanation":"7 Şubat 2022'den bu yana, ilk kez başvuran Sınıf A/B başvuru sahipleri, sınava girmeden önce FMCSA Eğitim Sağlayıcı Kayıt sicilinde listelenen bir sağlayıcıdan ELDT'yi tamamlamalıdır ve Washington, tamamlama doğrulanana kadar sınavı uygulayamaz. Kaynak: FMCSA ELDT kuralı; WA DOL, 'CDL beceri sınavı.'"},"86":{"q":"Bir Washington CDL başvuru sahibi, yaptığı sürüş türünü beyan ederken kaç öz-sertifikasyon kategorisinden seçim yapmalıdır?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört öz-sertifikasyon kategorisi vardır: muaf olmayan eyaletler arası, muaf eyaletler arası, muaf olmayan eyalet içi ve muaf eyalet içi. Kaynak: WA DOL, 'Sağlık sertifikaları ve öz-sertifikasyon'; 49 CFR 383.71."},"87":{"q":"Hangi Washington öz-sertifikasyon kategorisi, sürücünün dosyasında bir sağlık muayenecisi sertifikası bulundurmasını GEREKTİRMEZ?","options":["Muaf eyalet içi","Muaf olmayan eyaletler arası","Muaf eyaletler arası","Muaf olmayan eyalet içi"],"explanation":"Dört kategoriden üçü bir sağlık muayenecisi sertifikası gerektirir; yalnızca muaf eyalet içi sürücülerde 'belge gerekmez.' Kaynak: WA DOL, 'Sağlık sertifikaları ve öz-sertifikasyon.'"},"88":{"q":"Mevcut Washington/federal kurallar uyarınca, bir sürücünün DOT sağlık muayenecisi sertifikası normalde DOL'ye nasıl ulaşır?","options":["Sağlık muayenecisi bunu Ulusal Sicile yükler, sicil de bunu DOL'ye iletir","Sürücü her zaman Washington, D.C.'deki FMCSA'ya kağıt bir kopya postalar","İşveren bunu Washington State Patrol'a faksla gönderir","Sertifika, CLP verildiğinde otomatik olarak oluşturulur"],"explanation":"Sertifikalı sağlık muayenecisi sertifikayı FMCSA Ulusal Siciline yükler ve sonuç, sürücünün kaydını güncellemek üzere DOL'ye iletilir. Kaynak: WA DOL, 'Sağlık sertifikaları ve öz-sertifikasyon.'"},"89":{"q":"DOL bir sürücünün CDL sağlık belgelerini aldıktan sonra, sürücünün kaydını güncellemesi genellikle ne kadar sürer?","options":["7 ila 10 iş günü","1 ila 2 iş günü","30 ila 45 iş günü","Aynı iş günü"],"explanation":"DOL, sağlık belgeleri alındıktan sonra bir kaydın güncellenmesinin 7-10 iş günü sürebileceğini belirtir. Kaynak: WA DOL, 'Sağlık sertifikaları ve öz-sertifikasyon.'"},"90":{"q":"Washington DOL, CDL başvuru sahiplerini bilgi sınavlarına hazırlanmak için hangi çalışma kılavuzunu kullanmaya yönlendirir?","options":["Washington Ticari Sürücü Kılavuzu","Washington Sürücü Kılavuzu (ticari olmayan)","FMCSA Tehlikeli Maddeler Uyum Cep Kitabı","Washington Kamyoncu Almanağı"],"explanation":"DOL, CDL başvuru sahiplerini, sınavı geçmek için gereken tüm bilgileri içerdiğini belirttiği Washington Ticari Sürücü Kılavuzu'nu çalışmaya yönlendirir. Kaynak: WA DOL, 'CDL bilgi sınavı.'"},"91":{"q":"Washington DOL, CDL bilgi sınavını hangi dillerde sunar?","options":["İngilizce, İspanyolca, Rusça ve Sırp-Hırvatça","Yalnızca İngilizce","Yalnızca İngilizce ve İspanyolca","Başvuru sahibinin sağladığı bir tercümanla herhangi bir dilde"],"explanation":"Washington, CDL bilgi sınavını İngilizce, İspanyolca, Rusça ve Sırp-Hırvatça olarak sunar ve dil tercümanlarına izin verilmez. Kaynak: WA DOL, 'CDL bilgi sınavı.'"},"92":{"q":"Bir Washington CDL bilgi sınavı ücreti, ödendikten sonra hangi süre içinde girilen her bilgi sınavı için bir denemeyi kapsar?","options":["90 gün","30 gün","180 gün","1 yıl"],"explanation":"Bilgi sınavı ücreti, alındıktan sonraki 90 gün içinde girilen her bilgi sınavı için bir denemeyi kapsar. Kaynak: WA DOL, 'CDL bilgi sınavı.'"},"93":{"q":"Bir Washington başvuru sahibinin CLP başvurusu yapmak için hangi belgeleri getirmesi gerekir?","options":["Geçerli bir WA sürücü belgesi, Sosyal Güvenlik numarası kanıtı ve ABD vatandaşlığı veya yasal daimi ikamet kanıtı","Yalnızca bir doğum belgesi","Bir pasaport ve iki fatura","Bir araç ruhsatı ve sigorta kanıtı"],"explanation":"CLP başvurusu yapmak için DOL; geçerli bir Washington sürücü belgesi, Sosyal Güvenlik numarası ve ABD vatandaşlığı veya yasal daimi ikamet kanıtı ister. Kaynak: WA DOL, 'Ticari öğrenci belgesi (CLP).'"},"94":{"q":"Washington'da bir tehlikeli maddeler (H) onayı için sınava girmeden önce, bir başvuru sahibi ne tür bir ELDT tamamlamalıdır?","options":["H bilgi sınavından önce alınan, bir FMCSA Eğitim Sağlayıcı Kayıt sicili sağlayıcısından teori (bilgi) eğitimi","Tam bir direksiyon başında alan ve yol kursu","Hiç eğitim almadan, yalnızca arka plan kontrolü","Washington State Patrol gözetiminde yolda eğitim"],"explanation":"Tehlikeli madde (H) onayı için ELDT yalnızca teoriktir ve eyalet H bilgi sınavına girmeden önce bir Eğitim Sağlayıcı Kayıt sicili sağlayıcısıyla tamamlanmalıdır. Kaynak: FMCSA ELDT kuralı; FMCSA Eğitim Sağlayıcı Kayıt sicili, 'ELDT Uygulanabilirliği.'"},"95":{"q":"Standart, geliştirilmemiş Washington CDL yenileme döngüsü nasıl yapılandırılmıştır?","options":["Her 6 yılda bir yenilenmelidir","Her 4 yılda bir yenilenmelidir","Her 10 yılda bir yenilenmelidir","Bir kez verildikten sonra asla sona ermez"],"explanation":"Standart bir Washington CDL, 6 yıllık bir döngüde verilir. Kaynak: WA DOL, 'CDL'nizi yenileyin.'"},"96":{"q":"Bir Washington sürücüsü, bir CDL'yi süresi dolmadan ne kadar önce yenileyebilir?","options":["Süresi dolmadan 1 yıl öncesine kadar","Süresi dolmadan 6 ay öncesine kadar","Yalnızca tam son kullanma tarihinde","Süresi dolmadan 90 gün öncesine kadar"],"explanation":"DOL, CDL yenilemesine belgenin süresi dolmadan 1 yıl öncesine kadar izin verir. Kaynak: WA DOL, 'CDL'nizi yenileyin.'"},"97":{"q":"Bir Washington CDL'sinin süresi 8 yıldan fazla dolmuşsa ne olur?","options":["Sürücü yenileyemez ve CDL sürecine baştan başlamalıdır","Sürücü küçük bir gecikme ücretiyle yine de çevrimiçi yenileyebilir","Belge, bir görme testinden sonra otomatik olarak yeniden geçerli kılınır","Sürücü, süresi dolmuş kartla bir yıl daha sürmeye devam edebilir"],"explanation":"Bir Washington CDL'sinin süresi 8 yıldan fazla dolmuşsa, yenilenemez ve sürücünün ruhsatlandırma sürecine baştan başlaması gerekir. Kaynak: WA DOL, 'CDL'nizi yenileyin.'"},"98":{"q":"Bir Washington CLP'si kaç kez ve hangi koşulla yenilenebilir?","options":["Bir kez, süresi dolduktan sonraki 30 gün içinde yenilenirse, 180 gün daha uzatılarak","Belge sahibi çalışmaya devam ettiği sürece sınırsız kez","Zamanlamadan bağımsız olarak takvim yılı başına iki kez","Asla yenilenemez; yeni bir tane verilmelidir"],"explanation":"Bir Washington CLP'si yalnızca bir kez, süresi dolduktan sonraki 30 gün içinde yenilenebilir ve bu da onu 180 gün daha uzatır. Kaynak: WA DOL, 'Ticari öğrenci belgesi (CLP).'"},"99":{"q":"Washington'da, hangi CDL durumları bir Eğitim Sağlayıcı Kayıt sicili sağlayıcısından Giriş Seviyesi Sürücü Eğitimi (ELDT) gerektirir?","options":["İlk bir Sınıf A veya Sınıf B CDL alma, Sınıf B'yi Sınıf A'ya yükseltme ve ilk bir H, P veya S onayı alma","Yalnızca ilk bir Sınıf C CDL alma","Yalnızca mevcut bir CDL'yi yenileme","Başarısızlıktan sonraki her bilgi sınavı tekrarı"],"explanation":"ELDT; ilk kez başvuran Sınıf A veya Sınıf B başvuru sahiplerine, Sınıf B'den Sınıf A'ya yükseltmelere ve ilk kez alınan tehlikeli madde (H), yolcu (P) veya okul otobüsü (S) onaylarına uygulanır; Washington, sınavdan önce tamamlanmayı doğrular. Kaynak: FMCSA Eğitim Sağlayıcı Kayıt sicili, 'ELDT Uygulanabilirliği.'"}},"es":{"0":{"q":"¿Cuál es el ancho exterior legal máximo de un vehículo o su carga en las carreteras públicas de Washington, sin un permiso especial?","options":["8 pies (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies (108 pulgadas)","10 pies (120 pulgadas)"],"explanation":"La RCW 46.44.010 limita el ancho exterior total de un vehículo o su carga a 8 pies 6 pulgadas (102 pulgadas), excluyendo ciertos dispositivos de seguridad y espejos. Esta es también la norma federal. Fuente: RCW 46.44.010; Guía de Vehículos Comerciales de WSDOT."},"1":{"q":"¿Cuál es la altura legal máxima, incluyendo la carga, para un vehículo en las carreteras de Washington sin un permiso especial?","options":["13 pies 6 pulgadas","14 pies","14 pies 6 pulgadas","15 pies"],"explanation":"La RCW 46.44.020 establece que es ilegal que un vehículo, vacío o con carga, supere una altura de 14 pies sobre la superficie en la que se encuentra. Fuente: RCW 46.44.020."},"2":{"q":"¿Cuál es la longitud legal máxima de un solo vehículo (no una combinación) en las carreteras de Washington sin un permiso?","options":["35 pies","40 pies","45 pies","48 pies"],"explanation":"La RCW 46.44.030 establece la longitud máxima general de un solo vehículo en 40 pies, con excepciones que permiten autobuses, casas rodantes y remolques de viaje de hasta 46 pies. Fuente: RCW 46.44.030."},"3":{"q":"En una combinación de tractor con semirremolque en las carreteras de Washington, ¿cuál es la longitud máxima permitida del semirremolque por sí solo (sin permiso)?","options":["48 pies","53 pies","57 pies","60 pies"],"explanation":"La RCW 46.44.030 prohíbe operar un tractor con semirremolque cuyo semirremolque tenga una longitud que supere los 53 pies. Fuente: RCW 46.44.030."},"4":{"q":"¿Cuál es la carga bruta máxima que Washington permite sobre cualquier eje individual sin un permiso especial?","options":["18,000 libras","20,000 libras","22,400 libras","24,000 libras"],"explanation":"La RCW 46.44.041 prohíbe una carga bruta sobre cualquier eje individual que supere las 20,000 libras. Fuente: RCW 46.44.041; WSDOT 'Peso legal del vehículo'."},"5":{"q":"¿Cuál es la carga bruta máxima estándar sobre un grupo de ejes en tándem en Washington (sin permiso)?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"Conforme a la RCW 46.44.041 y la norma federal adoptada en Washington, un grupo de ejes en tándem está limitado a 34,000 libras. Fuente: RCW 46.44.041."},"6":{"q":"¿Cuál es el peso bruto vehicular máximo permitido en el sistema de carreteras interestatales en Washington sin un permiso?","options":["80,000 libras","90,000 libras","100,000 libras","105,500 libras"],"explanation":"En el sistema interestatal, la ley federal adoptada por Washington limita el peso bruto a 80,000 libras. Las cifras más altas solo aplican en ciertas carreteras estatales no interestatales. Fuente: RCW 46.44.041; 23 CFR 658.17; WSDOT."},"7":{"q":"Según la tabla de pesos de Washington, ¿cuál es el peso bruto vehicular total máximo que puede transportarse legalmente en carreteras estatales no interestatales con suficientes ejes y distancia entre ejes (sin permiso de sobrepeso)?","options":["80,000 libras","98,000 libras","105,500 libras","120,000 libras"],"explanation":"La tabla de pesos por distancia entre ejes/cantidad de ejes de la RCW 46.44.041 permite hasta 105,500 libras de peso bruto en carreteras no interestatales cuando el espaciamiento y la cantidad de ejes califican. El sistema interestatal permanece limitado a 80,000 libras. Fuente: RCW 46.44.041; WSDOT."},"8":{"q":"¿Qué fórmula usa Washington para determinar el peso máximo permitido sobre un grupo de ejes consecutivos?","options":["W = 500[LN/(N-1) + 12N + 36]","W = 1000(L + N + 12)","W = 700[LN/(N+1) + 10N]","W = 250[LN + 24N + 40]"],"explanation":"La RCW 46.44.041 incorpora la fórmula federal de puentes W = 500[LN/(N-1) + 12N + 36], donde L es la distancia entre los ejes extremos del grupo y N es el número de ejes. Fuente: RCW 46.44.041; Fórmula de Puentes de la FHWA."},"9":{"q":"En la fórmula de puentes de Washington W = 500[LN/(N-1) + 12N + 36], ¿qué representa 'N'?","options":["El número de ejes en el grupo","La distancia en pies entre los ejes extremos","El peso neto de la carga en toneladas","El número de neumáticos en el eje de tracción"],"explanation":"En la fórmula de puentes adoptada por la RCW 46.44.041, N es el número de ejes en el grupo que se está considerando y L es el espaciamiento en pies entre los ejes extremos de ese grupo. Fuente: RCW 46.44.041; FHWA."},"10":{"q":"En Washington, el peso bruto permitido sobre un eje individual también está limitado por el ancho del neumático. ¿Cuál es el peso máximo por pulgada de ancho de neumático?","options":["500 libras por pulgada","550 libras por pulgada","600 libras por pulgada","700 libras por pulgada"],"explanation":"La RCW 46.44.042 limita el peso del eje a 600 libras por pulgada de ancho de neumático. El peso bruto del eje se rige por el más restrictivo entre el tamaño del neumático, el peso del eje y la tabla de pesos. Fuente: RCW 46.44.042; WSDOT."},"11":{"q":"Dos conjuntos consecutivos de ejes en tándem pueden cargar cada uno 34,000 libras en Washington solo si la distancia entre el primer y el último eje de los dos conjuntos está separada por al menos cuánto?","options":["30 pies","34 pies","36 pies","40 pies"],"explanation":"La RCW 46.44.041 permite que dos conjuntos consecutivos de ejes en tándem carguen 34,000 libras cada uno solo cuando la distancia total entre el primer y el último eje de los conjuntos es de 36 pies o más. Fuente: RCW 46.44.041."},"12":{"q":"Un transportista necesita mover una carga que excede los límites legales de tamaño o peso de Washington. ¿Quién emite el permiso especial para el movimiento en carreteras estatales?","options":["La Patrulla del Estado de Washington","El Departamento de Licencias","El Departamento de Transporte del Estado de Washington (WSDOT)","La oficina del alguacil del condado"],"explanation":"La RCW 46.44.090 autoriza a WSDOT a emitir permisos especiales de sobredimensión/sobrepeso para las carreteras estatales; las autoridades locales los emiten para los caminos bajo su jurisdicción. Fuente: RCW 46.44.090; Permisos de Vehículos Comerciales de WSDOT."},"13":{"q":"Conforme a la RCW 46.44.090, ¿qué debe demostrar generalmente un solicitante para obtener un permiso especial de sobredimensión o sobrepeso en Washington?","options":["Una solicitud por escrito y una causa justificada demostrada","Una carta de exención federal","Comprobante de $1 millón en seguro de carga","Un historial de manejo limpio durante cinco años"],"explanation":"La RCW 46.44.090 dispone que WSDOT o las autoridades locales pueden emitir un permiso especial tras una solicitud por escrito (o electrónica) y la demostración de una causa justificada. Fuente: RCW 46.44.090."},"14":{"q":"¿Cuándo se requiere un permiso especial de sobredimensión/sobrepeso de Washington?","options":["Solo cuando el vehículo está vacío","Siempre que el vehículo o la carga excedan los límites legales de la RCW 46.44.010 a la 46.44.041","Solo en carreteras de peaje","Solo para vehículos de más de 53 pies de largo"],"explanation":"La RCW 46.44.090 requiere un permiso especial para mover un vehículo o carga que exceda los máximos establecidos en la RCW 46.44.010, .020, .030, .034 y .041. Una carga indivisible que no puede reducirse debe ser autorizada mediante permiso en lugar de dividirse. Fuente: RCW 46.44.090."},"15":{"q":"Washington permite que los camiones madereros obtengan un permiso especial de 'tolerancia para troncos'. ¿Cuánto peso bruto adicional permite este permiso sobre el máximo legal habitual?","options":["Hasta 4,000 libras","Hasta 6,800 libras","Hasta 10,000 libras","Hasta 12,500 libras"],"explanation":"La RCW 46.44.047 permite que los camiones madereros que transportan troncos excedan el peso bruto legal máximo (68,000 libras cuando están totalmente matriculados) en no más de 6,800 libras bajo un permiso especial de tolerancia para troncos. Fuente: RCW 46.44.047."},"16":{"q":"¿Cuál es la tarifa anual de un permiso especial de tolerancia para troncos de Washington cuando se emite por el período completo de 12 meses?","options":["$25","$50","$100","$120"],"explanation":"La RCW 46.44.047 fija la tarifa del permiso especial de tolerancia para troncos en $50 por el período de 12 meses que comienza el 1 de abril, con tarifas prorrateadas reducidas si se emite más tarde dentro del año del permiso. Fuente: RCW 46.44.047."},"17":{"q":"En una combinación de Washington de un tractor y dos remolques (un 'doble'), ¿cuál es la longitud combinada máxima de los dos remolques sin un permiso?","options":["56 pies","61 pies","65 pies","68 pies"],"explanation":"La RCW 46.44.030 limita un tractor con dos remolques de manera que la longitud combinada de los remolques no exceda los 61 pies. Fuente: RCW 46.44.030."},"18":{"q":"Un permiso de sobredimensión de un solo viaje autoemitido por WSDOT permite el movimiento hasta qué dimensiones y peso máximos antes de que se necesite un permiso más especializado?","options":["12 pies de ancho, 14 pies de alto, 100,000 lb","14 pies de ancho, 15 pies de alto, 150,000 lb","16 pies de ancho, 16 pies de alto, 200,000 lb","20 pies de ancho, 18 pies de alto, 250,000 lb"],"explanation":"El sistema de permisos autoemitidos de WSDOT cubre cargas de hasta 16 pies de ancho, 16 pies de alto, 125 pies de longitud de carga y 200,000 libras; los movimientos mayores requieren un permiso emitido directamente por la oficina de permisos de WSDOT. Fuente: Permisos de Vehículos Comerciales de WSDOT, 'Autoemitir un permiso'."},"19":{"q":"¿Las regulaciones de qué agencia limitan el peso bruto a 80,000 libras en el sistema interestatal, un límite que Washington debe cumplir para mantener el financiamiento federal de carreteras?","options":["La Agencia de Protección Ambiental","La Administración Federal de Carreteras (FHWA) conforme al 23 CFR Parte 658","La división médica de la Administración Federal de Seguridad de Autotransportistas","La Comisión de Comercio Interestatal"],"explanation":"El límite de peso bruto interestatal de 80,000 libras y la fórmula de puentes provienen de las regulaciones de la FHWA en el 23 CFR Parte 658, que Washington adopta en la RCW 46.44.041 para el sistema interestatal. Los límites más altos no interestatales reflejan los derechos adquiridos de Washington. Fuente: 23 CFR 658.17; RCW 46.44.041."},"20":{"q":"En Washington, ¿qué clase de CDL se requiere para conducir un vehículo de combinación con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, donde la(s) unidad(es) remolcada(s) exceden las 10,000 libras de GVWR?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Washington requiere una CDL Clase A para un vehículo de combinación con una GCWR de 26,001 libras o más cuando el o los vehículos remolcados tienen una GVWR superior a 10,000 libras. Fuente: WA DOL, Tipos de CDL / Guía del Conductor Comercial del Estado de Washington."},"21":{"q":"Según las reglas de Washington, ¿qué tipo de vehículo cubre una CDL Clase B?","options":["Cualquier vehículo individual con una GVWR de 26,001 libras o más (y que remolca una unidad de 10,000 lb o menos)","Un vehículo de combinación que remolca un remolque de más de 10,000 libras","Solo vehículos que transportan 16 o más pasajeros","Solo vehículos con rótulos para materiales peligrosos"],"explanation":"Una CDL Clase B en Washington cubre cualquier vehículo individual con una GVWR de 26,001 libras o más, incluyendo ese vehículo cuando remolca un remolque con clasificación de 10,000 libras o menos. Las combinaciones con una unidad remolcada más pesada requieren Clase A. Fuente: WA DOL, Tipos de CDL."},"22":{"q":"Se requiere una CDL Clase C de Washington cuando un vehículo no cumple con los umbrales de peso de Clase A o B pero está diseñado para transportar al menos cuántas personas (incluyendo al conductor), o transporta materiales peligrosos que requieren rótulos?","options":["16 o más","12 o más","20 o más","10 o más"],"explanation":"Una CDL Clase C aplica a vehículos que transportan 16 o más ocupantes incluyendo al conductor, o que transportan materiales peligrosos que requieren rótulos, cuando el vehículo es demasiado liviano para Clase A o B. Fuente: WA DOL, Tipos de CDL."},"23":{"q":"¿Qué endoso requiere Washington para un conductor que jala conjuntos de remolques dobles o triples?","options":["Endoso T","Endoso N","Endoso H","Endoso X"],"explanation":"El endoso T (Dobles/Triples) se requiere en Washington para los conductores que jalan conjuntos de remolques dobles o triples, y se obtiene aprobando únicamente un examen de conocimientos. Fuente: WA DOL, Endosos y restricciones."},"24":{"q":"En Washington, el endoso N (Vehículo Cisterna) se requiere para un CMV diseñado para transportar materiales líquidos o gaseosos en un tanque con una capacidad nominal individual de más de 119 galones y una capacidad nominal agregada de al menos cuántos galones?","options":["1,000 galones","500 galones","750 galones","1,500 galones"],"explanation":"Washington requiere el endoso N para cualquier CMV diseñado para transportar materiales líquidos/gaseosos en un tanque con una capacidad nominal individual superior a 119 galones y una capacidad nominal agregada de 1,000 galones o más. Fuente: WA DOL, Endosos y restricciones."},"25":{"q":"¿Qué endoso de CDL de Washington se requiere para conducir un vehículo de pasajeros diseñado para transportar 16 o más personas (incluyendo al conductor)?","options":["Endoso P","Endoso S","Endoso T","Endoso N"],"explanation":"El endoso P (Pasajeros) se requiere en Washington para los conductores de vehículos de pasajeros diseñados para transportar 16 o más personas incluyendo al conductor. Fuente: WA DOL, Endosos y restricciones."},"26":{"q":"En Washington, ¿para qué se requiere el endoso S (Autobús Escolar)?","options":["Cualquier tamaño de autobús escolar usado para transportar niños hacia/desde la escuela o actividades escolares","Solo autobuses escolares que transportan 16 o más niños","Solo autobuses escolares con motor diésel","Solo autobuses escolares operados a través de líneas de condado"],"explanation":"Washington requiere el endoso S para conducir cualquier tamaño de autobús escolar que se use regularmente para transportar niños hacia y desde la escuela o en relación con actividades escolares. Fuente: WA DOL, Endosos y restricciones."},"27":{"q":"Antes de obtener un endoso de HazMat (H) en Washington, un conductor debe completar una evaluación federal de amenazas de seguridad administrada por cuál agencia, que incluye la toma de huellas dactilares?","options":["Administración de Seguridad en el Transporte (TSA)","Patrulla del Estado de Washington (WSP)","Administración Federal de Seguridad de Autotransportistas (FMCSA)","Departamento de Licencias (DOL) únicamente"],"explanation":"Washington requiere que los solicitantes de HazMat se tomen las huellas dactilares y aprueben una Evaluación de Amenazas para el Endoso de Materiales Peligrosos de la TSA antes de que se emita el endoso H. Fuente: WA DOL, Endoso de materiales peligrosos (hazmat); TSA HTAP."},"28":{"q":"Un endoso de HazMat (H) en una CDL de Washington debe renovarse, con una nueva evaluación de amenazas de la TSA, al menos con qué frecuencia?","options":["Cada 5 años","Cada 2 años","Cada 8 años","Cada 10 años"],"explanation":"Las reglas federales aplicadas en Washington requieren la renovación del endoso de HazMat, incluyendo nuevas huellas dactilares y una nueva verificación de antecedentes de la TSA, al menos cada 5 años. Fuente: WA DOL, Endoso de hazmat; TSA HTAP."},"29":{"q":"¿Cuál es la edad mínima para obtener una CDL de Washington para conducir únicamente de forma INTRAESTATAL (dentro del estado)?","options":["18 años","21 años","19 años","16 años"],"explanation":"Washington permite que un conductor que tenga al menos 18 años obtenga una CDL para el comercio intraestatal; la operación interestatal requiere tener 21 años. Fuente: WA DOL, Obtener una licencia de conducir comercial (CDL)."},"30":{"q":"¿Cuál es la edad mínima para obtener una CDL de Washington que permita conducir en el comercio INTERESTATAL (a través de las líneas estatales)?","options":["21 años","18 años","19 años","25 años"],"explanation":"Un conductor debe tener al menos 21 años para operar un vehículo motorizado comercial a través de las líneas estatales conforme a las reglas de Washington y federales. Fuente: WA DOL, Obtener una licencia de conducir comercial (CDL)."},"31":{"q":"En Washington, ¿por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) desde la fecha en que se emite?","options":["180 días","90 días","1 año","60 días"],"explanation":"Un CLP de Washington es válido por 180 días desde la fecha de emisión, y puede renovarse una vez dentro de los 30 días posteriores al vencimiento por 180 días adicionales. Fuente: WA DOL, Permiso de aprendiz comercial (CLP)."},"32":{"q":"Después de que se emite un CLP original de Washington, ¿cuánto tiempo debe esperar un conductor antes de tomar el examen de habilidades de la CDL?","options":["14 días calendario","7 días calendario","30 días calendario","10 días hábiles"],"explanation":"Las reglas federales adoptadas por Washington requieren un período de espera de 14 días calendario después de que se emite un CLP original o mejorado antes de que el conductor pueda tomar el examen de habilidades. Fuente: WA DOL, Permiso de aprendiz comercial (CLP)."},"33":{"q":"Mientras conduce con un CLP de Washington, el titular de la CDL que supervisa y está sentado junto al titular del permiso debe tener una CDL válida con la clase/endosos adecuados y tener al menos cuánta experiencia?","options":["2 años en ese tipo de vehículo y 5 años totales de manejo","1 año de manejo con CDL","6 meses en ese tipo de vehículo","10 años totales de manejo"],"explanation":"Washington requiere que el titular de la CDL que acompaña tenga los endosos adecuados, al menos 2 años de experiencia en ese tipo de vehículo y al menos 5 años totales de experiencia de manejo. Fuente: WA DOL, Permiso de aprendiz comercial (CLP)."},"34":{"q":"¿Qué categoría de documento NO se requiere por separado al solicitar una CDL de Washington?","options":["Comprobante de que usted es dueño de un vehículo comercial","Comprobante de identidad / fecha de nacimiento","Número de Seguro Social","Comprobante de ciudadanía estadounidense o residencia permanente legal"],"explanation":"Washington requiere comprobante de identidad, un número de Seguro Social, comprobante de residencia y comprobante de ciudadanía estadounidense o residencia permanente legal (presencia legal); no se requiere ser dueño de un vehículo comercial. Fuente: WA DOL, Documentos aprobados para la CDL."},"35":{"q":"Para comprobar la presencia legal para una CDL de Washington, ¿cuál de los siguientes debe presentar un solicitante?","options":["Un documento aprobado a nivel federal como un pasaporte estadounidense, acta de nacimiento o Tarjeta de Residente Permanente (original, no una fotocopia)","Dos facturas de servicios públicos cualesquiera","Una declaración notariada de ciudadanía","Únicamente una tarjeta de registro de votante"],"explanation":"Washington requiere un documento original aceptable que compruebe la ciudadanía estadounidense o la residencia permanente legal, como un pasaporte estadounidense, un acta de nacimiento emitida por el gobierno o una Tarjeta de Residente Permanente; no se aceptan fotocopias. Fuente: WA DOL, Documentos aprobados para la CDL."},"36":{"q":"La Capacitación para Conductores Principiantes (ELDT) se volvió obligatoria en Washington para los solicitantes que obtienen un CLP en o después de qué fecha?","options":["7 de febrero de 2022","1 de enero de 2020","1 de septiembre de 2021","1 de julio de 2023"],"explanation":"Las reglas federales de ELDT, aplicadas en Washington, requieren capacitación de un proveedor registrado para los solicitantes que obtienen un CLP en o después del 7 de febrero de 2022. Fuente: Capacitación para Conductores Principiantes de FMCSA; WA DOL, Requisitos de capacitación de la CDL."},"37":{"q":"Según las reglas de ELDT en Washington, un conductor que busca cuál credencial debe completar la capacitación de un proveedor que figura en el Registro de Proveedores de Capacitación de la FMCSA antes de hacer el examen?","options":["CDL Clase A o Clase B por primera vez, o un endoso P, S o H por primera vez","Solo el endoso T (dobles/triples)","Solo el endoso N (cisterna)","Renovación de una CDL existente sin cambio de clase"],"explanation":"La ELDT aplica a los solicitantes de CDL Clase A y Clase B por primera vez (y a las mejoras de B a A) y a los solicitantes de endosos de pasajeros (P), autobús escolar (S) y HazMat (H) por primera vez; el proveedor debe estar en el Registro de Proveedores de Capacitación de la FMCSA. Fuente: Aplicabilidad de ELDT de FMCSA."},"38":{"q":"Al solicitar una CDL de Washington, la categoría de autocertificación médica 'Interestatal No Exento' significa que el conductor:","options":["Opera en el comercio interestatal y debe mantener un certificado válido de examinador médico del DOT","Opera únicamente dentro de Washington y está exento de todos los requisitos médicos","Opera en el comercio interestatal pero está exento del certificado médico","Conduce únicamente en propiedad privada y no necesita certificado"],"explanation":"De las cuatro categorías de autocertificación, Interestatal No Exento significa que el conductor opera a través de las líneas estatales y debe poseer y mantener un certificado válido de examinador médico del DOT. Fuente: Categorías de autocertificación médica de FMCSA; WA DOL, Obtener una CDL."},"39":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación médica de la CDL entre las que un solicitante de Washington debe elegir?","options":["Intraestatal Exento","Interestatal Provisional","Intraestatal Condicional","Interestatal Restringido"],"explanation":"Las cuatro categorías de autocertificación de la FMCSA usadas en Washington son Interestatal No Exento, Interestatal Exento, Intraestatal No Exento e Intraestatal Exento. Fuente: Autocertificación médica de FMCSA; WA DOL, Obtener una CDL."},"40":{"q":"En Washington, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.04","0.08","0.02","0.10"],"explanation":"La ley de Washington (y la Guía de CDL de Washington, conforme al 49 CFR 383.51/392.5) hace ilegal operar un CMV con un BAC de 0.04 o más, la mitad del límite de 0.08 para conductores no comerciales. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51."},"41":{"q":"Conforme a la ley de consentimiento implícito de Washington, al poseer una CDL y operar un vehículo, ¿se considera que un conductor ha aceptado hacer qué si un oficial de la ley tiene motivos razonables para sospechar deterioro?","options":["Someterse a una prueba de aliento o de sangre para detectar alcohol o drogas","Pagar una fianza fija en efectivo al costado de la carretera","Entregar la CDL permanentemente en el acto","Completar primero una clase de educación sobre el alcohol de 12 horas"],"explanation":"El estatuto de consentimiento implícito de Washington (RCW 46.20.308) significa que cualquier persona que conduce en el estado ha consentido a las pruebas químicas (de aliento o de sangre) cuando un oficial tiene motivos razonables para sospechar conducción con deterioro. Fuente: RCW 46.20.308; Guía de CDL del Washington DOL."},"42":{"q":"Un titular de CDL de Washington es condenado por un primer DUI mientras conducía un vehículo comercial sin rótulos. ¿Cuál es el período de descalificación para esta primera infracción mayor?","options":["1 año","3 años","60 días","6 meses"],"explanation":"Una primera infracción mayor (incluyendo DUI, BAC de 0.04+, o negarse a la prueba) descalifica una CDL por 1 año. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 1."},"43":{"q":"En Washington, ¿por cuánto tiempo es la descalificación de la CDL por una primera infracción mayor (como DUI o BAC de 0.04+) si el conductor transportaba materiales peligrosos con rótulos en ese momento?","options":["3 años","1 año","5 años","120 días"],"explanation":"Una primera infracción mayor cometida mientras se transportan materiales peligrosos con rótulos eleva la descalificación de 1 año a 3 años. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 1."},"44":{"q":"¿Cuál es el período de descalificación de la CDL en Washington por una segunda infracción mayor (por ejemplo, un segundo DUI o una segunda condena por BAC de 0.04+)?","options":["De por vida (vitalicia)","10 años","5 años","3 años"],"explanation":"Una segunda infracción mayor resulta en una descalificación vitalicia de la CDL; Washington señala que no puede volver a calificar después de una descalificación vitalicia. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 1."},"45":{"q":"Un titular de CDL de Washington se niega a someterse a una prueba de aliento o de sangre cuando un oficial lo solicita legalmente mientras opera un vehículo sin rótulos. ¿Cuál es el período de descalificación por esta primera negativa?","options":["1 año","90 días","3 años","60 días"],"explanation":"Negarse a la prueba química se trata como una infracción mayor, descalificando la CDL por 1 año en una primera negativa (3 años si se transportan materiales peligrosos con rótulos). Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 1."},"46":{"q":"En Washington, negarse a una prueba de aliento o de sangre es una infracción mayor que cuenta para la descalificación vitalicia. Una negativa a la prueba seguida posteriormente por una condena separada por DUI resultaría en qué descalificación?","options":["Descalificación vitalicia (dos infracciones mayores)","Solo una descalificación de 1 año en total","Una descalificación de 120 días","Ninguna descalificación adicional más allá de la primera"],"explanation":"Tanto una negativa a la prueba como un DUI son infracciones mayores; dos infracciones mayores de incidentes separados activan una descalificación vitalicia de la CDL. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 1."},"47":{"q":"¿Cuántas infracciones de tránsito graves dentro de un período de 3 años (en incidentes separados) activan la descalificación de CDL por infracción grave más corta en Washington?","options":["2 infracciones graves","3 infracciones graves","1 infracción grave","4 infracciones graves"],"explanation":"Dos infracciones de tránsito graves derivadas de incidentes separados dentro de 3 años activan una descalificación de 60 días; la primera infracción grave por sí sola no descalifica. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 2."},"48":{"q":"¿Cuál es el período de descalificación de la CDL en Washington por dos infracciones de tránsito graves cometidas en incidentes separados dentro de un período de 3 años?","options":["60 días","120 días","30 días","90 días"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años (incidentes separados) resultan en una descalificación de la CDL de 60 días. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 2."},"49":{"q":"¿Cuál es el período de descalificación de la CDL en Washington por tres infracciones de tránsito graves cometidas en incidentes separados dentro de un período de 3 años?","options":["120 días","60 días","1 año","180 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años (incidentes separados) resultan en una descalificación de la CDL de 120 días. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 2."},"50":{"q":"¿Cuánto por encima del límite de velocidad indicado debe ser citado un titular de CDL de Washington para que cuente como una 'infracción de tránsito grave'?","options":["15 mph o más por encima del límite","10 mph o más por encima del límite","20 mph o más por encima del límite","25 mph o más por encima del límite"],"explanation":"Exceder la velocidad en 15 mph o más por encima del límite indicado figura como una infracción de tránsito grave para fines de la CDL en Washington. Fuente: página de infracciones de tránsito graves del Washington DOL; 49 CFR 383.51 Tabla 2."},"51":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito grave' para un titular de CDL de Washington?","options":["Seguir demasiado de cerca (manejar pegado)","Estacionarse en una zona de no estacionamiento","Una luz de placa quemada","No mostrar una calcomanía de registro"],"explanation":"Seguir demasiado de cerca está en la lista de infracciones de tránsito graves de Washington (junto con conducción imprudente, cambio de carril indebido, exceso de velocidad de 15+ por encima, y enviar mensajes de texto/usar el teléfono en un CMV). Las infracciones de equipo y estacionamiento no lo están. Fuente: página de infracciones de tránsito graves del Washington DOL; 49 CFR 383.51."},"52":{"q":"Conforme a la regla de Washington, ¿cómo se clasifica enviar mensajes de texto mientras se conduce un vehículo motorizado comercial para fines de descalificación de la CDL?","options":["Una infracción de tránsito grave","Una infracción mayor","Una violación de una orden de fuera de servicio","Una infracción de equipo no reportable"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV (y usar un teléfono de mano mientras se conduce un CMV) es una infracción de tránsito grave, por lo que dos dentro de 3 años conllevan una descalificación de 60 días. Fuente: página de infracciones de tránsito graves del Washington DOL; FMCSA 392.80/392.82."},"53":{"q":"Las reglas federales adoptadas en Washington prohíben que un conductor de CMV use un teléfono móvil de mano mientras conduce. ¿Cuál es la sanción civil máxima aproximada para el conductor por violar esta restricción de teléfono de mano/mensajes de texto?","options":["Hasta aproximadamente $2,750","Hasta aproximadamente $250","Hasta aproximadamente $500","Hasta aproximadamente $1,000"],"explanation":"La restricción federal sobre el uso de teléfonos de mano y el envío de mensajes de texto por parte de conductores de CMV (FMCSA 392.80/392.82), aplicada en Washington, conlleva sanciones civiles para el conductor de hasta aproximadamente $2,750. Fuente: FMCSA 392.82; Guía de CDL del Washington DOL."},"54":{"q":"¿Cuál es el período mínimo de descalificación de la CDL en Washington por una primera condena por una violación en un cruce ferroviario a nivel mientras se opera un CMV?","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera violación en un cruce ferroviario a nivel en un CMV descalifica la CDL por no menos de 60 días. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 3."},"55":{"q":"¿Cuál es el período mínimo de descalificación de la CDL en Washington por una segunda violación en un cruce ferroviario a nivel dentro de un período de 3 años?","options":["120 días","60 días","1 año","180 días"],"explanation":"Una segunda violación en un cruce ferroviario a nivel dentro de 3 años descalifica la CDL por no menos de 120 días. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 3."},"56":{"q":"¿Cuál es el período mínimo de descalificación de la CDL en Washington por una tercera violación en un cruce ferroviario a nivel dentro de un período de 3 años?","options":["1 año","120 días","60 días","3 años"],"explanation":"Una tercera violación en un cruce ferroviario a nivel dentro de 3 años descalifica la CDL por no menos de 1 año. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 3."},"57":{"q":"¿Cuál es el período de descalificación en Washington por una primera violación de una orden de fuera de servicio (OOS) mientras se opera un CMV sin materiales peligrosos?","options":["No menos de 180 días y no más de 1 año","No menos de 60 días y no más de 120 días","No menos de 30 días y no más de 90 días","Descalificación vitalicia"],"explanation":"Una primera violación de una orden OOS descalifica la CDL por no menos de 180 días y no más de 1 año para un vehículo sin materiales peligrosos. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 4."},"58":{"q":"Un conductor de Washington comete una primera violación de una orden de fuera de servicio mientras transporta materiales peligrosos con rótulos o lleva 16 o más pasajeros. ¿Cuál es el rango de descalificación?","options":["No menos de 180 días y no más de 2 años","No menos de 180 días y no más de 1 año","No menos de 60 días y no más de 120 días","No menos de 1 año y no más de 5 años"],"explanation":"Una primera violación de una orden OOS mientras se transportan materiales peligrosos con rótulos o se llevan 16+ pasajeros descalifica la CDL por no menos de 180 días y no más de 2 años. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 4."},"59":{"q":"¿Cuál es el período de descalificación en Washington por una segunda violación de una orden de fuera de servicio (sin materiales peligrosos) dentro de un período de 10 años, derivada de incidentes separados?","options":["No menos de 2 años y no más de 5 años","No menos de 180 días y no más de 1 año","No menos de 1 año y no más de 3 años","Descalificación vitalicia"],"explanation":"Una segunda violación de una orden OOS (sin materiales peligrosos) en incidentes separados dentro de 10 años descalifica la CDL por no menos de 2 años y no más de 5 años. Fuente: página de descalificaciones de CDL del Washington DOL; 49 CFR 383.51 Tabla 4."},"60":{"q":"En Washington, ¿cuál es el límite máximo de velocidad para un vehículo de más de 10,000 libras de peso bruto (o cualquier combinación de vehículos) en una autopista, incluso donde los automóviles pueden circular legalmente a mayor velocidad?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Washington limita la velocidad de los vehículos de más de 10,000 lbs de peso bruto y de todas las combinaciones de vehículos (excepto los autobuses de etapa) a 60 mph, sin importar que haya un límite señalizado más alto para los automóviles. Fuente: RCW 46.61.410."},"61":{"q":"En una autopista de acceso limitado de Washington con tres o más carriles en tu sentido, ¿en cuál carril NO puede circular un camión o una combinación de más de 10,000 libras (excepto al prepararse para un giro a la izquierda legal)?","options":["El carril del extremo derecho","Cualquier carril central","El carril de la izquierda","Un carril para vehículos de alta ocupación (HOV)"],"explanation":"Ningún vehículo que remolque un tráiler ni ningún vehículo o combinación de más de 10,000 lbs puede circular en el carril de la izquierda de una vía de acceso limitado con tres o más carriles en un sentido, excepto para prepararse para un giro a la izquierda legal. Un carril HOV no se cuenta como el carril de la izquierda. Fuente: RCW 46.61.100."},"62":{"q":"Al acercarse a un cruce a nivel de ferrocarril en Washington, el conductor de un autobús escolar o de un vehículo con materiales peligrosos rotulado debe detenerse ¿a cuántos pies del riel más cercano?","options":["A no más de 50 pies pero no menos de 15 pies","A no más de 75 pies pero no menos de 25 pies","A no más de 40 pies pero no menos de 10 pies","A no más de 100 pies pero no menos de 30 pies"],"explanation":"Washington exige que el conductor de un autobús escolar/de pasajeros, un vehículo comercial que transporte pasajeros o un tanque de carga de materiales peligrosos se detenga antes de la línea de alto; de lo contrario, a no más de 50 pies pero no menos de 15 pies del riel más cercano. Fuente: RCW 46.61.350."},"63":{"q":"Después de detenerse en un cruce de ferrocarril, ¿qué exige la ley de Washington al conductor de un autobús o de un vehículo HazMat rotulado mientras cruza las vías?","options":["Cruzar en una marcha que no requiera cambiar de marcha mientras está sobre las vías, y no cambiar de marcha al cruzar","Reducir a la marcha más baja en el punto medio de las vías","Activar el bloqueo del diferencial antes de cruzar las vías","Cruzar solo después de tocar la bocina tres veces sobre las vías"],"explanation":"La ley de Washington establece que el conductor debe cruzar solo en una marcha que no requiera cambiar de marcha mientras atraviesa el cruce y no puede cambiar de marcha mientras cruza las vías. Fuente: RCW 46.61.350."},"64":{"q":"Según la ley 'Move Over' (Cédase el paso) de Washington, una 'zona de emergencia o de trabajo' se define como los carriles adyacentes de la vía que se extienden ¿a qué distancia antes y después de un vehículo de emergencia o de trabajo detenido que muestra señales de advertencia?","options":["100 pies","150 pies","200 pies","300 pies"],"explanation":"Washington define la zona de emergencia o de trabajo como los carriles adyacentes 200 pies antes y después de un vehículo de emergencia autorizado detenido, una grúa, un vehículo de policía, de servicios públicos o de mantenimiento de carreteras que use sus señales de advertencia. Fuente: RCW 46.61.212."},"65":{"q":"En una autopista de Washington con menos de cuatro carriles, si un conductor no puede cambiar de carril de forma segura para alejarse de un vehículo de emergencia/trabajo detenido, debe reducir la velocidad al menos ¿cuánto por debajo del límite de velocidad señalizado (donde el límite es de 60 mph o menos)?","options":["5 mph por debajo del límite señalizado","10 mph por debajo del límite señalizado","15 mph por debajo del límite señalizado","20 mph por debajo del límite señalizado"],"explanation":"Cuando un cambio de carril no es seguro, la ley 'Move Over' de Washington exige reducir la velocidad al menos 10 mph por debajo del límite señalizado; donde el límite señalizado supera las 60 mph, el conductor debe en cambio bajar a no más de 50 mph. Fuente: RCW 46.61.212."},"66":{"q":"Al encontrarte con un autobús escolar detenido que muestra luces rojas intermitentes mientras circulas en sentido CONTRARIO, ¿en cuál tipo de vía de Washington NO estás obligado a detenerte?","options":["Una carretera de dos carriles sin división","Una carretera dividida en calzadas separadas por una mediana o barrera","Cualquier calle de ciudad con un límite señalizado de 25 mph","Un camino de dos carriles con un carril central de giro a la izquierda en ambos sentidos"],"explanation":"En una carretera dividida en calzadas separadas (según RCW 46.61.150), o en una con tres o más carriles marcados, un conductor que se encuentra con un autobús escolar que va en sentido contrario no necesita detenerse. En caminos de dos carriles sin división debes detenerte. Fuente: RCW 46.61.370."},"67":{"q":"Además de la excepción de carretera dividida, ¿en qué otro tipo de vía de Washington puedes seguir adelante sin detenerte al pasar junto a un autobús escolar detenido que viene en sentido contrario?","options":["Una vía con tres o más carriles de tránsito marcados","Cualquier vía señalizada a 45 mph o más","Una vía con acotamientos pavimentados de al menos 8 pies de ancho","Una vía con un único carril central de giro"],"explanation":"La ley de autobuses escolares de Washington agrega que los conductores que se encuentran con un autobús que circula en sentido contrario en una carretera con tres o más carriles de tránsito marcados no necesitan detenerse. Fuente: RCW 46.61.370."},"68":{"q":"Un conductor de camión en Washington se detiene en el acotamiento de un camino de dos carriles y doble sentido. Después de encender las luces intermitentes de cuatro vías, ¿en cuántos minutos debe colocar los dispositivos de advertencia exigidos (triángulos)?","options":["5 minutos","10 minutos","15 minutos","30 minutos"],"explanation":"Un vehículo comercial detenido en una vía o acotamiento debe colocar los dispositivos de advertencia de emergencia dentro de 10 minutos, después de activar primero las luces intermitentes de emergencia. Fuente: Manual CDL de Washington; 49 CFR 392.22 (adoptado en Washington)."},"69":{"q":"En un camino de Washington de dos carriles y doble sentido, ¿dónde deben colocarse los tres triángulos reflectantes para un vehículo comercial detenido?","options":["Los tres detrás del vehículo a 10, 50 y 100 pies","Dentro de 10 pies del lado del tránsito, 100 pies hacia atrás y 100 pies hacia adelante","A 10, 100 y 200 pies, todos hacia el tránsito que se aproxima","Uno en el techo y dos a 50 pies adelante y atrás"],"explanation":"En un camino de doble sentido, coloca un triángulo dentro de 10 pies del vehículo del lado del tránsito, uno a unos 100 pies por detrás y uno a unos 100 pies por delante, para que se advierta al tránsito de ambos sentidos. Fuente: Manual CDL de Washington; 49 CFR 392.22."},"70":{"q":"En una autopista dividida o de un solo sentido en Washington, ¿dónde deben colocarse los tres triángulos de advertencia de un vehículo comercial detenido?","options":["A 10, 100 y 200 pies hacia el tránsito que se aproxima por detrás del vehículo","A 10, 50 y 100 pies hacia el tránsito que se aproxima","Uno al frente y dos a 100 pies por detrás","Los tres a 200 pies por detrás del vehículo"],"explanation":"En una autopista dividida o de un solo sentido, coloca los triángulos hacia el tránsito que se aproxima a 10 pies, 100 pies y 200 pies del vehículo. Fuente: Manual CDL de Washington; 49 CFR 392.22."},"71":{"q":"Washington exige que los vehículos y combinaciones de más de 10,000 libras de GVWR lleven cadenas para neumáticos en rutas designadas de pasos de montaña ¿durante qué período de cada año?","options":["Del 1 de octubre al 1 de marzo","Del 1 de noviembre al 1 de abril","Del 1 de diciembre al 31 de marzo","Del 15 de noviembre al 15 de marzo"],"explanation":"Del 1 de noviembre al 1 de abril, los vehículos y combinaciones de más de 10,000 lbs de GVWR deben llevar cadenas en las rutas designadas para cadenas (por ejemplo, I-90, US 2 Stevens Pass, US 12 White Pass), sin importar las condiciones del momento. Fuente: requisitos de cadenas para vehículos comerciales de WSDOT; WAC 204-24-050."},"72":{"q":"¿Cuántas cadenas para neumáticos adicionales debe llevar un vehículo comercial de Washington de más de 10,000 libras de GVWR en las rutas designadas para cadenas durante la temporada en que se exige llevarlas?","options":["Al menos una cadena adicional","Al menos dos cadenas adicionales","Al menos cuatro cadenas adicionales","Ninguna adicional si los neumáticos de tracción ya están encadenados"],"explanation":"Washington exige que estos vehículos lleven al menos dos cadenas para neumáticos adicionales durante el período del 1 de noviembre al 1 de abril, para que se pueda reemplazar una cadena rota o la de un eje adicional. Fuente: requisitos de cadenas de WSDOT; WAC 204-24-050."},"73":{"q":"En una vía de varios carriles en Washington, ¿qué dice la ley estatal sobre un vehículo más lento que ocupa de forma continua el carril izquierdo?","options":["Está permitido si el vehículo va al límite de velocidad","Es una infracción de tránsito circular de forma continua en el carril izquierdo cuando impide el paso de otro tránsito","Se permite solo para vehículos de menos de 10,000 libras","Se permite si el carril derecho está ocupado por camiones"],"explanation":"La ley de mantenerse a la derecha de Washington establece que es una infracción de tránsito circular de forma continua en el carril izquierdo de una vía de varios carriles cuando al hacerlo se impide el flujo de otro tránsito. Fuente: RCW 46.61.100."},"74":{"q":"La sanción por rebasar ilegalmente un autobús escolar detenido en Washington que muestra sus luces rojas y su señal de alto (paddle) se describe en la ley como:","options":["Una multa fija de $250 que el tribunal puede reducir","El doble de la sanción base, que no puede ser dispensada, reducida ni suspendida","Una advertencia por escrito por una primera infracción","Solo la suspensión de la licencia, sin sanción monetaria"],"explanation":"A un conductor que rebasa ilegalmente un autobús escolar detenido se le impone una sanción monetaria igual al doble de la sanción base según RCW 46.63.110, y no puede ser dispensada, reducida ni suspendida. Fuente: RCW 46.61.370."},"75":{"q":"Cuando la Patrulla del Estado de Washington publica 'Chains Required' (Cadenas obligatorias) para vehículos de más de 10,000 libras, ¿los neumáticos con clavos (studded tires) cumplen con el requisito?","options":["Sí, los neumáticos con clavos cuentan como cadenas","Sí, pero solo en el eje de tracción","No; se deben instalar cadenas incluso sobre los neumáticos con clavos","Solo los vehículos con tracción en las cuatro ruedas están exentos"],"explanation":"Los neumáticos con clavos no cumplen con un requisito de cadenas publicado en Washington; los conductores deben instalar cadenas (sobre los neumáticos con clavos si los tienen) para seguir más allá de un punto de colocación de cadenas señalizado. Fuente: requisitos de cadenas de invierno de WSDOT/WSP."},"76":{"q":"En Washington, generalmente se requiere un permiso individual de tamaño/peso excesivo cuando un vehículo o carga supera ¿cuál de estos límites legales de dimensión?","options":["8 pies 6 pulgadas de ancho, 14 pies de alto, o los límites de longitud aplicables","10 pies de ancho, 13 pies 6 pulgadas de alto, o 48 pies de largo","9 pies de ancho, 15 pies de alto, o 60 pies de largo","8 pies de ancho, 12 pies de alto, o 35 pies de largo"],"explanation":"Los límites legales de Washington son generalmente 8 ft 6 in de ancho y 14 ft de alto; superar el ancho, la altura o los límites de longitud aplicables requiere un permiso de tamaño excesivo de WSDOT. Fuente: permisos de tamaño/peso excesivo de Commercial Vehicle Services de WSDOT."},"77":{"q":"¿Cuál autopista de montaña es una ruta designada para cadenas/tracción en Washington donde comúnmente se hacen cumplir los requisitos de cadenas para vehículos comerciales?","options":["I-90 sobre Snoqualmie Pass","I-5 a través del centro de Seattle","I-405 alrededor de Bellevue","El puente flotante SR 520"],"explanation":"La I-90 sobre Snoqualmie Pass (de North Bend a Ellensburg) es una ruta primaria designada para cadenas, junto con US 2 Stevens Pass y US 12 White Pass; las autopistas interestatales urbanas como I-5, I-405 y SR 520 no son rutas de cadenas de montaña. Fuente: requisitos de cadenas de pasos de montaña de WSDOT."},"78":{"q":"Una rampa de escape para camiones sin frenos en una pendiente pronunciada en Washington normalmente se construye para detener un vehículo pesado mediante:","options":["Un lecho de grava suelta o arena blanda, a veces en una subida, que aumenta la resistencia mientras más avanzas","Una red de barrera de acero tendida a través del carril","Una rampa pavimentada en bajada que permite que el camión se detenga por inercia","Una canaleta llena de agua que hace flotar los neumáticos"],"explanation":"Las rampas de escape de Washington usan grava suelta o arena blanda, a veces con una pendiente cuesta arriba; la resistencia aumenta mientras más avanza el camión, lo que ayuda a detenerlo. Fuente: Manual CDL de Washington, conducción en montaña / rampas de escape."},"79":{"q":"Según la ley 'Move Over' de Washington en una autopista de cuatro o más carriles, la PRIMERA obligación del conductor al acercarse a un vehículo de emergencia/trabajo detenido con luces intermitentes es:","options":["Detenerse por completo en el carril hasta que el vehículo se retire","Avanzar con precaución, reducir la velocidad y cambiar de carril para alejarse de él si es seguro hacerlo","Tocar la bocina y mantener la velocidad señalizada","Pasarse al acotamiento y rebasar por la derecha"],"explanation":"En autopistas de cuatro o más carriles, los conductores deben avanzar con precaución, reducir la velocidad y cederle el paso cambiándose un carril para alejarse de la zona cuando sea seguro; solo si un cambio de carril no es seguro reducen a la velocidad reducida exigida. Fuente: RCW 46.61.212."},"80":{"q":"¿Qué agencia emite las licencias de conducir comerciales (CDL) en Washington?","options":["El Departamento de Licencias del Estado de Washington (DOL)","La Patrulla del Estado de Washington (WSP)","El Departamento de Transporte del Estado de Washington (WSDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"En Washington, el Departamento de Licencias (DOL) emite las CDL y administra las pruebas de la CDL. Fuente: WA DOL, 'Getting a commercial driver license (CDL).'"},"81":{"q":"¿Dónde puede un solicitante de CDL en Washington presentar la prueba de habilidades requerida?","options":["Con un examinador del DOL o con un examinador externo (TPE) autorizado por el DOL","Solo en la división de vehículos comerciales de la Patrulla del Estado de Washington","Solo en línea a través del sitio web del DOL","En cualquier escuela del Registro de Proveedores de Capacitación de la FMCSA que elijas"],"explanation":"La prueba de habilidades de la CDL de Washington la aplica ya sea un examinador del DOL o un examinador externo (TPE) autorizado por el DOL. Fuente: WA DOL, 'CDL skills test.'"},"82":{"q":"¿De cuántas partes consta la prueba de habilidades de la CDL de Washington?","options":["Tres: inspección del vehículo (previa al viaje), control básico del vehículo y la prueba de manejo en carretera","Dos: un examen escrito y una prueba de manejo","Cuatro: escrita, de visión, de inspección y de manejo en carretera","Una sola prueba de manejo combinada que incluye todo"],"explanation":"La prueba de habilidades de la CDL de Washington tiene tres partes que se realizan en secuencia: la inspección del vehículo (previa al viaje), las habilidades básicas de control del vehículo y la prueba de manejo en carretera. Fuente: WA DOL, 'CDL skills test.'"},"83":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Washington a partir de la fecha en que se emite?","options":["180 días","30 días","1 año","60 días"],"explanation":"Un CLP de Washington es válido por 180 días a partir de la fecha de emisión. Fuente: WA DOL, 'Commercial learner's permit (CLP).'"},"84":{"q":"Después de que se emite un CLP de Washington, ¿cuánto tiempo debe esperar el titular antes de presentar la prueba de habilidades de la CDL?","options":["14 días calendario","30 días calendario","7 días calendario","No se requiere período de espera"],"explanation":"Washington requiere una espera de 14 días calendario después de que se emite un CLP original o mejorado antes de que el titular pueda presentar la prueba de habilidades, reflejando la regla federal del CLP. Fuente: WA DOL, 'Commercial learner's permit (CLP)' / 'CDL skills test.'"},"85":{"q":"Antes de presentar la prueba de habilidades de la CDL en Washington, un solicitante de Clase A o Clase B por primera vez debe completar ¿cuál requisito?","options":["Capacitación para Conductores Principiantes (ELDT) de un proveedor del Registro de Proveedores de Capacitación de la FMCSA","Un aprendizaje de cuatro años registrado ante el DOL","Un curso de manejo defensivo aprobado por la Patrulla del Estado de Washington","Un seminario de prevención de la furia al volante ofrecido por WSDOT"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de Clase A/B por primera vez deben completar la ELDT de un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes de la prueba, y Washington no puede aplicar la prueba hasta que se verifique su finalización. Fuente: regla ELDT de la FMCSA; WA DOL, 'CDL skills test.'"},"86":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL en Washington al declarar el tipo de conducción que realiza?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Hay cuatro categorías de autocertificación: interestatal no exceptuada, interestatal exceptuada, intraestatal no exceptuada e intraestatal exceptuada. Fuente: WA DOL, 'Medical certificates and self-certification'; 49 CFR 383.71."},"87":{"q":"¿Cuál categoría de autocertificación de Washington NO exige que un conductor tenga un certificado de examinador médico en su expediente?","options":["Intraestatal exceptuada","Interestatal no exceptuada","Interestatal exceptuada","Intraestatal no exceptuada"],"explanation":"Tres de las cuatro categorías exigen un certificado de examinador médico; solo los conductores intraestatales exceptuados no necesitan presentar documentos. Fuente: WA DOL, 'Medical certificates and self-certification.'"},"88":{"q":"Según las reglas actuales de Washington/federales, ¿cómo llega normalmente al DOL el certificado de examinador médico DOT de un conductor?","options":["El examinador médico lo carga en el National Registry, que lo transmite al DOL","El conductor siempre envía por correo una copia en papel a la FMCSA en Washington, D.C.","El empleador lo envía por fax a la Patrulla del Estado de Washington","El certificado se genera automáticamente cuando se emite el CLP"],"explanation":"El examinador médico certificado carga el certificado en el National Registry de la FMCSA, y el resultado se transmite al DOL para actualizar el expediente del conductor. Fuente: WA DOL, 'Medical certificates and self-certification.'"},"89":{"q":"Después de que el DOL recibe los documentos médicos de la CDL de un conductor, ¿cuánto tiempo suele tardar en actualizar el expediente del conductor?","options":["De 7 a 10 días hábiles","De 1 a 2 días hábiles","De 30 a 45 días hábiles","El mismo día hábil"],"explanation":"El DOL indica que puede tardar de 7 a 10 días hábiles en actualizar un expediente después de recibir los documentos médicos. Fuente: WA DOL, 'Medical certificates and self-certification.'"},"90":{"q":"¿Qué guía de estudio recomienda el DOL de Washington a los solicitantes de CDL para prepararse para las pruebas de conocimiento?","options":["La Washington Commercial Driver Guide","La Washington Driver Guide (no comercial)","El FMCSA Hazardous Materials Compliance Pocketbook","El Washington Trucker's Almanac"],"explanation":"El DOL recomienda a los solicitantes de CDL estudiar la Washington Commercial Driver Guide, la cual, según indica, contiene toda la información necesaria para aprobar la prueba. Fuente: WA DOL, 'CDL knowledge test.'"},"91":{"q":"¿En qué idiomas ofrece el DOL de Washington la prueba de conocimiento de la CDL?","options":["Inglés, español, ruso y serbocroata","Solo inglés","Solo inglés y español","Cualquier idioma, con un intérprete que el solicitante proporcione"],"explanation":"Washington ofrece la prueba de conocimiento de la CDL en inglés, español, ruso y serbocroata, y no se permiten intérpretes de idiomas. Fuente: WA DOL, 'CDL knowledge test.'"},"92":{"q":"La tarifa de la prueba de conocimiento de la CDL de Washington cubre un intento de cada prueba de conocimiento que se realice dentro de ¿qué período después de pagarla?","options":["90 días","30 días","180 días","1 año"],"explanation":"La tarifa de la prueba de conocimiento cubre un intento de cada prueba de conocimiento que se realice dentro de los 90 días posteriores a su recepción. Fuente: WA DOL, 'CDL knowledge test.'"},"93":{"q":"¿Qué documentos debe llevar un solicitante de Washington para solicitar un CLP?","options":["Una licencia de conducir de WA válida, prueba del número de Seguro Social y prueba de ciudadanía estadounidense o residencia permanente legal","Solo un acta de nacimiento","Un pasaporte y dos recibos de servicios públicos","Un registro vehicular y prueba de seguro"],"explanation":"Para solicitar un CLP, el DOL exige una licencia de conducir vigente de Washington, el número de Seguro Social y prueba de ciudadanía estadounidense o residencia permanente legal. Fuente: WA DOL, 'Commercial learner's permit (CLP).'"},"94":{"q":"Antes de presentar la prueba para un endoso de materiales peligrosos (H) en Washington, un solicitante debe completar ¿qué tipo de ELDT?","options":["Capacitación teórica (de conocimiento) de un proveedor del Registro de Proveedores de Capacitación de la FMCSA, antes de la prueba de conocimiento de H","Un curso completo de práctica al volante en pista y carretera","Ninguna capacitación, solo la verificación de antecedentes","Capacitación en carretera supervisada por la Patrulla del Estado de Washington"],"explanation":"Para el endoso de materiales peligrosos (H), la ELDT es solo teórica y debe completarse con un proveedor del Registro de Proveedores de Capacitación antes de presentar la prueba estatal de conocimiento de H. Fuente: regla ELDT de la FMCSA; Registro de Proveedores de Capacitación de la FMCSA, 'ELDT Applicability.'"},"95":{"q":"¿Cómo está estructurado el ciclo de renovación estándar de una CDL no mejorada de Washington?","options":["Debe renovarse cada 6 años","Debe renovarse cada 4 años","Debe renovarse cada 10 años","Nunca vence una vez emitida"],"explanation":"Una CDL estándar de Washington se emite con un ciclo de 6 años. Fuente: WA DOL, 'Renew your CDL.'"},"96":{"q":"¿Con cuánta anticipación puede un conductor de Washington renovar una CDL antes de que venza?","options":["Hasta 1 año antes de que venza","Hasta 6 meses antes de que venza","Solo en la fecha exacta de vencimiento","Hasta 90 días antes de que venza"],"explanation":"El DOL permite la renovación de la CDL hasta 1 año antes de que venza la licencia. Fuente: WA DOL, 'Renew your CDL.'"},"97":{"q":"¿Qué sucede si una CDL de Washington ha estado vencida por más de 8 años?","options":["El conductor no puede renovarla y debe comenzar el proceso de la CDL desde cero","El conductor aún puede renovarla en línea con un pequeño cargo por demora","La licencia se reinstala automáticamente tras una prueba de visión","El conductor puede seguir manejando con la tarjeta vencida por un año más"],"explanation":"Si una CDL de Washington ha estado vencida por más de 8 años, no puede renovarse y el conductor debe comenzar el proceso de licencia desde cero. Fuente: WA DOL, 'Renew your CDL.'"},"98":{"q":"¿Cuántas veces puede renovarse un CLP de Washington, y bajo qué condición?","options":["Una vez, si se renueva dentro de los 30 días de su vencimiento, extendiéndolo otros 180 días","Un número ilimitado de veces, siempre que el titular siga estudiando","Dos veces por año calendario sin importar el momento","Nunca puede renovarse; debe emitirse uno nuevo"],"explanation":"Un CLP de Washington puede renovarse solo una vez, dentro de los 30 días de su vencimiento, lo que lo extiende otros 180 días. Fuente: WA DOL, 'Commercial learner's permit (CLP).'"},"99":{"q":"En Washington, ¿cuáles eventos de la CDL requieren Capacitación para Conductores Principiantes (ELDT) de un proveedor del Registro de Proveedores de Capacitación?","options":["Obtener una primera CDL de Clase A o Clase B, mejorar de Clase B a Clase A y obtener un primer endoso H, P o S","Solo obtener una primera CDL de Clase C","Solo renovar una CDL existente","Cada repetición de la prueba de conocimiento después de una reprobación"],"explanation":"La ELDT aplica a los solicitantes de Clase A o Clase B por primera vez, a las mejoras de Clase B a Clase A y a los primeros endosos de materiales peligrosos (H), de pasajeros (P) o de autobús escolar (S); Washington verifica su finalización antes de la prueba. Fuente: Registro de Proveedores de Capacitación de la FMCSA, 'ELDT Applicability.'"}},"hi":{"0":{"q":"विशेष परमिट के बिना, वॉशिंगटन के सार्वजनिक राजमार्गों पर किसी वाहन या उसके लोड की अधिकतम कानूनी बाहरी चौड़ाई कितनी है?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","9 feet (108 inches)","10 feet (120 inches)"],"explanation":"RCW 46.44.010 किसी वाहन या उसके लोड की कुल बाहरी चौड़ाई को 8 feet 6 inches (102 inches) तक सीमित करता है, जिसमें कुछ सुरक्षा उपकरण और शीशे शामिल नहीं हैं। यह संघीय मानक भी है। स्रोत: RCW 46.44.010; WSDOT Commercial Vehicle Guide।"},"1":{"q":"विशेष परमिट के बिना, वॉशिंगटन के राजमार्गों पर किसी वाहन की, लोड सहित, अधिकतम कानूनी ऊँचाई कितनी है?","options":["13 feet 6 inches","14 feet","14 feet 6 inches","15 feet"],"explanation":"RCW 46.44.020 के अनुसार किसी वाहन के लिए, चाहे वह खाली हो या लोड के साथ, जिस सतह पर वह खड़ा है उससे 14 feet से अधिक ऊँचाई होना गैरकानूनी है। स्रोत: RCW 46.44.020।"},"2":{"q":"परमिट के बिना, वॉशिंगटन के राजमार्गों पर किसी एकल वाहन (संयोजन नहीं) की अधिकतम कानूनी लंबाई कितनी है?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"RCW 46.44.030 एकल वाहन की सामान्य अधिकतम लंबाई 40 feet निर्धारित करता है, जिसमें अपवादों के तहत बसों, मोटर होम और ट्रैवल ट्रेलरों को 46 feet तक की अनुमति है। स्रोत: RCW 46.44.030।"},"3":{"q":"वॉशिंगटन के राजमार्गों पर ट्रैक्टर-सेमीट्रेलर संयोजन में, अकेले सेमीट्रेलर की अधिकतम स्वीकार्य लंबाई कितनी है (कोई परमिट नहीं)?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"RCW 46.44.030 ऐसे ट्रैक्टर-सेमीट्रेलर को चलाने पर रोक लगाता है जिसमें सेमीट्रेलर की लंबाई 53 feet से अधिक हो। स्रोत: RCW 46.44.030।"},"4":{"q":"विशेष परमिट के बिना, वॉशिंगटन किसी भी एकल एक्सल पर अधिकतम कितने सकल लोड की अनुमति देता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"RCW 46.44.041 किसी भी एकल एक्सल पर 20,000 pounds से अधिक सकल लोड पर रोक लगाता है। स्रोत: RCW 46.44.041; WSDOT 'Legal vehicle weight'।"},"5":{"q":"वॉशिंगटन में किसी टैंडम एक्सल समूह पर मानक अधिकतम सकल लोड कितना है (कोई परमिट नहीं)?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"RCW 46.44.041 और वॉशिंगटन में अपनाए गए संघीय मानक के तहत, किसी टैंडम एक्सल समूह को 34,000 pounds तक सीमित किया गया है। स्रोत: RCW 46.44.041।"},"6":{"q":"परमिट के बिना, वॉशिंगटन में अंतरराज्यीय (Interstate) राजमार्ग प्रणाली पर अनुमत अधिकतम सकल वाहन वज़न कितना है?","options":["80,000 pounds","90,000 pounds","100,000 pounds","105,500 pounds"],"explanation":"अंतरराज्यीय प्रणाली पर, वॉशिंगटन द्वारा अपनाया गया संघीय कानून सकल वज़न को 80,000 pounds पर सीमित करता है। इससे अधिक आंकड़े केवल कुछ गैर-अंतरराज्यीय राज्य राजमार्गों पर लागू होते हैं। स्रोत: RCW 46.44.041; 23 CFR 658.17; WSDOT।"},"7":{"q":"वॉशिंगटन की वज़न तालिका के अनुसार, पर्याप्त एक्सल और व्हीलबेस के साथ गैर-अंतरराज्यीय राज्य राजमार्गों पर कानूनी रूप से ले जाया जा सकने वाला अधिकतम कुल सकल वाहन वज़न कितना है (कोई ओवरवेट परमिट नहीं)?","options":["80,000 pounds","98,000 pounds","105,500 pounds","120,000 pounds"],"explanation":"RCW 46.44.041 की व्हीलबेस/एक्सल वज़न तालिका गैर-अंतरराज्यीय राजमार्गों पर 105,500 pounds तक सकल वज़न की अनुमति देती है, जब एक्सल की दूरी और संख्या पात्र हो। अंतरराज्यीय प्रणाली 80,000 pounds पर ही सीमित रहती है। स्रोत: RCW 46.44.041; WSDOT।"},"8":{"q":"वॉशिंगटन लगातार एक्सलों के समूह पर अनुमत अधिकतम वज़न निर्धारित करने के लिए कौन सा सूत्र इस्तेमाल करता है?","options":["W = 500[LN/(N-1) + 12N + 36]","W = 1000(L + N + 12)","W = 700[LN/(N+1) + 10N]","W = 250[LN + 24N + 40]"],"explanation":"RCW 46.44.041 संघीय ब्रिज सूत्र W = 500[LN/(N-1) + 12N + 36] को शामिल करता है, जहाँ L समूह के अंतिम छोर के एक्सलों के बीच की दूरी है और N एक्सलों की संख्या है। स्रोत: RCW 46.44.041; FHWA Bridge Formula।"},"9":{"q":"वॉशिंगटन ब्रिज सूत्र W = 500[LN/(N-1) + 12N + 36] में, 'N' किसका प्रतिनिधित्व करता है?","options":["समूह में एक्सलों की संख्या","अंतिम छोर के एक्सलों के बीच की दूरी फीट में","लोड का शुद्ध वज़न टन में","ड्राइव एक्सल पर टायरों की संख्या"],"explanation":"RCW 46.44.041 द्वारा अपनाए गए ब्रिज सूत्र में, N विचाराधीन समूह में एक्सलों की संख्या है और L उस समूह के अंतिम छोर के एक्सलों के बीच की दूरी फीट में है। स्रोत: RCW 46.44.041; FHWA।"},"10":{"q":"वॉशिंगटन में, किसी एकल एक्सल पर अनुमत सकल वज़न टायर की चौड़ाई से भी सीमित होता है। टायर की चौड़ाई के प्रति इंच अधिकतम वज़न कितना है?","options":["500 pounds per inch","550 pounds per inch","600 pounds per inch","700 pounds per inch"],"explanation":"RCW 46.44.042 एक्सल वज़न को टायर की चौड़ाई के प्रति इंच 600 pounds तक सीमित करता है। सकल एक्सल वज़न टायर के आकार, एक्सल वज़न और वज़न तालिका में से सबसे प्रतिबंधात्मक मानक द्वारा निर्धारित होता है। स्रोत: RCW 46.44.042; WSDOT।"},"11":{"q":"वॉशिंगटन में टैंडम एक्सलों के दो लगातार सेट प्रत्येक 34,000 pounds तभी ले जा सकते हैं जब दोनों सेटों के पहले और अंतिम एक्सलों के बीच की दूरी कम से कम कितनी हो?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"RCW 46.44.041 टैंडम एक्सलों के दो लगातार सेटों को प्रत्येक 34,000 pounds ले जाने की अनुमति केवल तभी देता है जब सेटों के पहले और अंतिम एक्सलों के बीच की कुल दूरी 36 feet या उससे अधिक हो। स्रोत: RCW 46.44.041।"},"12":{"q":"एक वाहक को ऐसा लोड ले जाना है जो वॉशिंगटन की कानूनी आकार या वज़न सीमाओं से अधिक है। राज्य राजमार्गों पर आवाजाही के लिए विशेष परमिट कौन जारी करता है?","options":["Washington State Patrol","Department of Licensing","Washington State Department of Transportation (WSDOT)","काउंटी शेरिफ का कार्यालय"],"explanation":"RCW 46.44.090 WSDOT को राज्य राजमार्गों के लिए विशेष ओवरसाइज़/ओवरवेट परमिट जारी करने के लिए अधिकृत करता है; स्थानीय प्राधिकरण अपने अधिकार क्षेत्र की सड़कों के लिए ये जारी करते हैं। स्रोत: RCW 46.44.090; WSDOT Commercial Vehicle Permits।"},"13":{"q":"RCW 46.44.090 के तहत, वॉशिंगटन में विशेष ओवरसाइज़ या ओवरवेट परमिट प्राप्त करने के लिए आवेदक को आम तौर पर क्या प्रदर्शित करना होता है?","options":["एक लिखित आवेदन और उचित कारण दिखाना","एक संघीय छूट पत्र","$1 million के कार्गो बीमा का प्रमाण","पाँच वर्षों का साफ ड्राइविंग रिकॉर्ड"],"explanation":"RCW 46.44.090 यह प्रावधान करता है कि WSDOT या स्थानीय प्राधिकरण लिखित (या इलेक्ट्रॉनिक) आवेदन और उचित कारण दिखाए जाने पर विशेष परमिट जारी कर सकते हैं। स्रोत: RCW 46.44.090।"},"14":{"q":"वॉशिंगटन का ओवरसाइज़/ओवरवेट विशेष परमिट कब आवश्यक होता है?","options":["केवल जब वाहन खाली हो","जब भी वाहन या लोड RCW 46.44.010 से 46.44.041 तक की कानूनी सीमाओं से अधिक हो","केवल टोल सड़कों पर","केवल 53 feet से अधिक लंबे वाहनों के लिए"],"explanation":"RCW 46.44.090 के तहत RCW 46.44.010, .020, .030, .034, और .041 में निर्धारित अधिकतम सीमाओं से अधिक वाहन या लोड को ले जाने के लिए विशेष परमिट आवश्यक है। ऐसे अविभाज्य लोड को, जिसे छोटा नहीं किया जा सकता, बाँटने के बजाय परमिट लेना आवश्यक है। स्रोत: RCW 46.44.090।"},"15":{"q":"वॉशिंगटन लॉगिंग ट्रकों को एक विशेष 'log tolerance' परमिट प्राप्त करने की अनुमति देता है। यह परमिट अन्यथा कानूनी अधिकतम सीमा से कितना अतिरिक्त सकल वज़न अनुमत करता है?","options":["Up to 4,000 pounds","Up to 6,800 pounds","Up to 10,000 pounds","Up to 12,500 pounds"],"explanation":"RCW 46.44.047 लट्ठे ढोने वाले लॉगिंग ट्रकों को एक विशेष log tolerance परमिट के तहत अधिकतम कानूनी सकल वज़न (पूरी तरह लाइसेंस प्राप्त होने पर 68,000 pounds) से 6,800 pounds से अधिक नहीं, अधिक होने की अनुमति देता है। स्रोत: RCW 46.44.047।"},"16":{"q":"वॉशिंगटन log tolerance विशेष परमिट के लिए वार्षिक शुल्क कितना है जब यह पूरी 12-month अवधि के लिए जारी किया जाता है?","options":["$25","$50","$100","$120"],"explanation":"RCW 46.44.047 log tolerance विशेष परमिट शुल्क को 1 अप्रैल से शुरू होने वाली 12-month अवधि के लिए $50 निर्धारित करता है, और यदि परमिट वर्ष में बाद में जारी किया जाए तो कम आनुपातिक शुल्क लगता है। स्रोत: RCW 46.44.047।"},"17":{"q":"वॉशिंगटन में एक ट्रैक्टर और दो ट्रेलरों के संयोजन ('double') में, परमिट के बिना दोनों ट्रेलरों की अधिकतम संयुक्त लंबाई कितनी है?","options":["56 feet","61 feet","65 feet","68 feet"],"explanation":"RCW 46.44.030 दो ट्रेलरों वाले ट्रैक्टर को इस प्रकार सीमित करता है कि ट्रेलरों की संयुक्त लंबाई 61 feet से अधिक न हो। स्रोत: RCW 46.44.030।"},"18":{"q":"WSDOT द्वारा स्वयं-जारी सिंगल-ट्रिप ओवरसाइज़ परमिट किसी अधिक विशेषीकृत परमिट की आवश्यकता होने से पहले किन अधिकतम आयामों और वज़न तक आवाजाही की अनुमति देता है?","options":["12 ft wide, 14 ft high, 100,000 lb","14 ft wide, 15 ft high, 150,000 lb","16 ft wide, 16 ft high, 200,000 lb","20 ft wide, 18 ft high, 250,000 lb"],"explanation":"WSDOT की स्वयं-जारी परमिट प्रणाली 16 feet चौड़े, 16 feet ऊँचे, 125 feet लोड लंबाई और 200,000 pounds तक के लोड को कवर करती है; इससे बड़ी आवाजाही के लिए WSDOT permit office द्वारा सीधे जारी परमिट की आवश्यकता होती है। स्रोत: WSDOT Commercial Vehicle Permits, 'Self-issue a permit.'"},"19":{"q":"किस एजेंसी के नियम अंतरराज्यीय प्रणाली पर सकल वज़न को 80,000 pounds पर सीमित करते हैं, एक ऐसी सीमा जिसका वॉशिंगटन को संघीय राजमार्ग वित्तपोषण बनाए रखने के लिए पालन करना होता है?","options":["Environmental Protection Agency","Federal Highway Administration (FHWA) under 23 CFR Part 658","Federal Motor Carrier Safety Administration medical division","Interstate Commerce Commission"],"explanation":"80,000-pound अंतरराज्यीय सकल वज़न सीमा और ब्रिज सूत्र 23 CFR Part 658 पर FHWA के नियमों से आते हैं, जिन्हें वॉशिंगटन अंतरराज्यीय प्रणाली के लिए RCW 46.44.041 में अपनाता है। उच्चतर गैर-अंतरराज्यीय सीमाएँ वॉशिंगटन के grandfather rights को दर्शाती हैं। स्रोत: 23 CFR 658.17; RCW 46.44.041।"},"20":{"q":"वॉशिंगटन में, 26,001 pounds या उससे अधिक के सकल संयोजन वज़न रेटिंग (GCWR) वाले संयोजन वाहन को चलाने के लिए कौन सा CDL वर्ग आवश्यक है, जहाँ खींची जा रही इकाई/इकाइयों का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"वॉशिंगटन में 26,001 pounds या उससे अधिक GCWR वाले संयोजन वाहन के लिए Class A CDL आवश्यक है जब खींचे जा रहे वाहन/वाहनों का GVWR 10,000 pounds से अधिक हो। स्रोत: WA DOL, Types of CDLs / Washington State Commercial Driver Guide।"},"21":{"q":"वॉशिंगटन के नियमों के तहत, Class B CDL किस प्रकार के वाहन को कवर करता है?","options":["26,001 pounds या उससे अधिक GVWR वाला कोई भी एकल वाहन (और 10,000 lbs या उससे कम की इकाई खींचना)","10,000 pounds से अधिक का ट्रेलर खींचने वाला संयोजन वाहन","केवल 16 या अधिक यात्रियों को ले जाने वाले वाहन","केवल खतरनाक सामग्री के लिए प्लेकार्ड लगे वाहन"],"explanation":"वॉशिंगटन में Class B CDL किसी भी एकल वाहन को कवर करता है जिसका GVWR 26,001 pounds या उससे अधिक हो, जिसमें 10,000 pounds या उससे कम रेटेड ट्रेलर खींचने वाला ऐसा वाहन भी शामिल है। भारी खींची गई इकाई वाले संयोजनों के लिए Class A आवश्यक है। स्रोत: WA DOL, Types of CDLs।"},"22":{"q":"वॉशिंगटन Class C CDL तब आवश्यक होता है जब कोई वाहन Class A या B के वज़न मानकों को पूरा नहीं करता लेकिन कम से कम कितने लोगों (ड्राइवर सहित) को ले जाने के लिए डिज़ाइन किया गया हो, या प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करता हो?","options":["16 या अधिक","12 या अधिक","20 या अधिक","10 या अधिक"],"explanation":"Class C CDL उन वाहनों पर लागू होता है जो ड्राइवर सहित 16 या अधिक यात्रियों को ले जाते हैं, या जो प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करते हैं, जब वाहन Class A या B के लिए बहुत हल्का हो। स्रोत: WA DOL, Types of CDLs।"},"23":{"q":"डबल या ट्रिपल ट्रेलरों के सेट खींचने वाले ड्राइवर के लिए वॉशिंगटन किस एंडोर्समेंट की आवश्यकता रखता है?","options":["T endorsement","N endorsement","H endorsement","X endorsement"],"explanation":"वॉशिंगटन में डबल या ट्रिपल ट्रेलरों के सेट खींचने वाले ड्राइवरों के लिए T (Doubles/Triples) एंडोर्समेंट आवश्यक है, और यह केवल एक नॉलेज टेस्ट पास करके प्राप्त किया जाता है। स्रोत: WA DOL, Endorsements and restrictions।"},"24":{"q":"वॉशिंगटन में, N (Tank Vehicle) एंडोर्समेंट ऐसे CMV के लिए आवश्यक है जो किसी टैंक में तरल या गैसीय सामग्री को ले जाने के लिए डिज़ाइन किया गया हो, जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और कुल रेटेड क्षमता कम से कम कितने gallons हो?","options":["1,000 gallons","500 gallons","750 gallons","1,500 gallons"],"explanation":"वॉशिंगटन ऐसे किसी भी CMV के लिए N एंडोर्समेंट की आवश्यकता रखता है जो किसी टैंक में तरल/गैसीय सामग्री ढोने के लिए डिज़ाइन किया गया हो, जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक हो और कुल रेटेड क्षमता 1,000 gallons या उससे अधिक हो। स्रोत: WA DOL, Endorsements and restrictions।"},"25":{"q":"16 या अधिक लोगों (ड्राइवर सहित) को ले जाने के लिए डिज़ाइन किए गए यात्री वाहन को चलाने के लिए कौन सा वॉशिंगटन CDL एंडोर्समेंट आवश्यक है?","options":["P endorsement","S endorsement","T endorsement","N endorsement"],"explanation":"वॉशिंगटन में ड्राइवर सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए यात्री वाहनों के ड्राइवरों के लिए P (Passenger) एंडोर्समेंट आवश्यक है। स्रोत: WA DOL, Endorsements and restrictions।"},"26":{"q":"वॉशिंगटन में, S (School Bus) एंडोर्समेंट किसे चलाने के लिए आवश्यक है?","options":["स्कूल आने-जाने या स्कूल गतिविधियों के लिए बच्चों को ले जाने के लिए इस्तेमाल होने वाली किसी भी आकार की स्कूल बस","केवल 16 या अधिक बच्चों को ले जाने वाली स्कूल बसें","केवल डीज़ल से चलने वाली स्कूल बसें","केवल काउंटी सीमाओं के पार चलने वाली स्कूल बसें"],"explanation":"वॉशिंगटन में किसी भी आकार की स्कूल बस को चलाने के लिए S एंडोर्समेंट आवश्यक है जो नियमित रूप से बच्चों को स्कूल आने-जाने या स्कूल गतिविधियों के संबंध में ले जाने के लिए इस्तेमाल की जाती है। स्रोत: WA DOL, Endorsements and restrictions।"},"27":{"q":"वॉशिंगटन में HazMat (H) एंडोर्समेंट प्राप्त करने से पहले, ड्राइवर को किस एजेंसी द्वारा संचालित संघीय सुरक्षा खतरा आकलन (security threat assessment) पूरा करना होता है, जिसमें फिंगरप्रिंटिंग शामिल है?","options":["Transportation Security Administration (TSA)","Washington State Patrol (WSP)","Federal Motor Carrier Safety Administration (FMCSA)","केवल Department of Licensing (DOL)"],"explanation":"वॉशिंगटन H एंडोर्समेंट जारी होने से पहले HazMat आवेदकों के फिंगरप्रिंट लिए जाने और TSA Hazardous Materials Endorsement Threat Assessment पास करने की आवश्यकता रखता है। स्रोत: WA DOL, Hazardous materials endorsement (hazmat); TSA HTAP।"},"28":{"q":"वॉशिंगटन CDL पर HazMat (H) एंडोर्समेंट को, एक नए TSA खतरा आकलन के साथ, कम से कम कितनी बार नवीनीकृत करना होता है?","options":["Every 5 years","Every 2 years","Every 8 years","Every 10 years"],"explanation":"वॉशिंगटन में लागू संघीय नियमों के अनुसार HazMat एंडोर्समेंट का नवीनीकरण, जिसमें नए फिंगरप्रिंट और एक नई TSA पृष्ठभूमि जाँच शामिल है, कम से कम हर 5 years में आवश्यक है। स्रोत: WA DOL, Hazmat endorsement; TSA HTAP।"},"29":{"q":"केवल इंट्रास्टेट (राज्य के भीतर) ड्राइविंग के लिए वॉशिंगटन CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"वॉशिंगटन कम से कम 18 वर्ष के ड्राइवर को इंट्रास्टेट वाणिज्य के लिए CDL प्राप्त करने की अनुमति देता है; अंतरराज्यीय संचालन के लिए आयु 21 आवश्यक है। स्रोत: WA DOL, Getting a commercial driver license (CDL)।"},"30":{"q":"ऐसा वॉशिंगटन CDL प्राप्त करने की न्यूनतम आयु क्या है जो इंटरस्टेट वाणिज्य (राज्य की सीमाओं के पार) में ड्राइविंग की अनुमति देता है?","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"वॉशिंगटन और संघीय नियमों के तहत राज्य की सीमाओं के पार वाणिज्यिक मोटर वाहन चलाने के लिए ड्राइवर का कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: WA DOL, Getting a commercial driver license (CDL)।"},"31":{"q":"वॉशिंगटन में, Commercial Learner's Permit (CLP) जारी होने की तारीख से कितने समय तक वैध रहता है?","options":["180 days","90 days","1 year","60 days"],"explanation":"वॉशिंगटन CLP जारी होने की तारीख से 180 days तक वैध रहता है, और समाप्ति के 30 days के भीतर इसे एक बार अतिरिक्त 180 days के लिए नवीनीकृत किया जा सकता है। स्रोत: WA DOL, Commercial learner's permit (CLP)।"},"32":{"q":"मूल वॉशिंगटन CLP जारी होने के बाद, CDL स्किल्स टेस्ट देने से पहले ड्राइवर को कितने समय तक प्रतीक्षा करनी होती है?","options":["14 calendar days","7 calendar days","30 calendar days","10 business days"],"explanation":"वॉशिंगटन द्वारा अपनाए गए संघीय नियमों के अनुसार किसी मूल या अपग्रेड किए गए CLP जारी होने के बाद ड्राइवर के स्किल्स टेस्ट देने से पहले 14-calendar-day की प्रतीक्षा अवधि आवश्यक है। स्रोत: WA DOL, Commercial learner's permit (CLP)।"},"33":{"q":"वॉशिंगटन CLP पर ड्राइविंग करते समय, परमिट धारक के बगल में बैठा पर्यवेक्षक CDL धारक के पास उचित वर्ग/एंडोर्समेंट के साथ एक वैध CDL होना चाहिए और कम से कम कितना अनुभव होना चाहिए?","options":["उस वाहन प्रकार में 2 साल और कुल 5 साल की ड्राइविंग","1 साल की CDL ड्राइविंग","उस वाहन प्रकार में 6 महीने","कुल 10 साल की ड्राइविंग"],"explanation":"वॉशिंगटन के अनुसार साथ में बैठे CDL धारक के पास उचित एंडोर्समेंट, उस प्रकार के वाहन में कम से कम 2 साल का अनुभव, और कम से कम कुल 5 साल का ड्राइविंग अनुभव होना चाहिए। स्रोत: WA DOL, Commercial learner's permit (CLP)।"},"34":{"q":"वॉशिंगटन CDL के लिए आवेदन करते समय किस दस्तावेज़ श्रेणी की अलग से आवश्यकता नहीं होती?","options":["आपके पास एक वाणिज्यिक वाहन के स्वामित्व का प्रमाण","पहचान / जन्म तिथि का प्रमाण","Social Security number","अमेरिकी नागरिकता या वैध स्थायी निवास का प्रमाण"],"explanation":"वॉशिंगटन पहचान का प्रमाण, एक Social Security number, निवास का प्रमाण, और अमेरिकी नागरिकता या वैध स्थायी निवास (lawful presence) का प्रमाण माँगता है; वाणिज्यिक वाहन का स्वामित्व आवश्यक नहीं है। स्रोत: WA DOL, CDL-approved documents।"},"35":{"q":"वॉशिंगटन CDL के लिए वैध उपस्थिति (lawful presence) साबित करने के लिए, आवेदक को निम्नलिखित में से कौन सा प्रस्तुत करना होता है?","options":["एक संघीय रूप से स्वीकृत दस्तावेज़ जैसे U.S. passport, birth certificate, या Permanent Resident Card (मूल, फोटोकॉपी नहीं)","कोई भी दो उपयोगिता बिल","नागरिकता का एक नोटरीकृत बयान","केवल एक मतदाता पंजीकरण कार्ड"],"explanation":"वॉशिंगटन अमेरिकी नागरिकता या वैध स्थायी निवास साबित करने वाला एक स्वीकार्य मूल दस्तावेज़ माँगता है, जैसे U.S. passport, सरकार द्वारा जारी birth certificate, या Permanent Resident Card; फोटोकॉपी स्वीकार नहीं की जातीं। स्रोत: WA DOL, CDL-approved documents।"},"36":{"q":"वॉशिंगटन में Entry-Level Driver Training (ELDT) उन आवेदकों के लिए किस तारीख को या उसके बाद CLP प्राप्त करने पर अनिवार्य हो गया?","options":["February 7, 2022","January 1, 2020","September 1, 2021","July 1, 2023"],"explanation":"वॉशिंगटन में लागू संघीय ELDT नियमों के अनुसार February 7, 2022 को या उसके बाद CLP प्राप्त करने वाले आवेदकों के लिए एक पंजीकृत प्रदाता से प्रशिक्षण आवश्यक है। स्रोत: FMCSA Entry-Level Driver Training; WA DOL, CDL training requirements।"},"37":{"q":"वॉशिंगटन में ELDT नियमों के तहत, किस क्रेडेंशियल की चाह रखने वाले ड्राइवर को परीक्षण से पहले FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता से प्रशिक्षण पूरा करना होता है?","options":["पहली बार Class A या Class B CDL, या पहली बार P, S, या H एंडोर्समेंट","केवल T (doubles/triples) एंडोर्समेंट","केवल N (tank) एंडोर्समेंट","बिना वर्ग परिवर्तन के मौजूदा CDL का नवीनीकरण"],"explanation":"ELDT पहली बार Class A और Class B CDL आवेदकों (और B-to-A अपग्रेड) पर और पहली बार passenger (P), school bus (S), और HazMat (H) एंडोर्समेंट आवेदकों पर लागू होता है; प्रदाता का FMCSA Training Provider Registry पर होना आवश्यक है। स्रोत: FMCSA ELDT Applicability।"},"38":{"q":"वॉशिंगटन CDL के लिए आवेदन करते समय, मेडिकल स्व-प्रमाणन श्रेणी 'Non-Excepted Interstate' का अर्थ है कि ड्राइवर:","options":["इंटरस्टेट वाणिज्य में संचालन करता है और उसे एक वैध DOT medical examiner's certificate बनाए रखना होगा","केवल वॉशिंगटन के भीतर संचालन करता है और सभी मेडिकल आवश्यकताओं से छूट प्राप्त है","इंटरस्टेट वाणिज्य में संचालन करता है लेकिन मेडिकल प्रमाणपत्र से छूट प्राप्त है","केवल निजी संपत्ति पर ड्राइव करता है और उसे किसी प्रमाणपत्र की आवश्यकता नहीं"],"explanation":"चार स्व-प्रमाणन श्रेणियों में से, Non-Excepted Interstate का अर्थ है कि ड्राइवर राज्य की सीमाओं के पार संचालन करता है और उसके पास एक वैध DOT medical examiner's certificate होना और उसे बनाए रखना आवश्यक है। स्रोत: FMCSA medical self-certification categories; WA DOL, Getting a CDL।"},"39":{"q":"निम्नलिखित में से कौन सी चार CDL मेडिकल स्व-प्रमाणन श्रेणियों में से एक है जिनमें से एक वॉशिंगटन आवेदक को चुनना होता है?","options":["Excepted Intrastate","Provisional Interstate","Conditional Intrastate","Restricted Interstate"],"explanation":"वॉशिंगटन में इस्तेमाल होने वाली चार FMCSA स्व-प्रमाणन श्रेणियाँ हैं Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate। स्रोत: FMCSA medical self-certification; WA DOL, Getting a CDL।"},"40":{"q":"वॉशिंगटन में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितनी है जिस पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.04","0.08","0.02","0.10"],"explanation":"वॉशिंगटन कानून (और Washington CDL Guide, जो 49 CFR 383.51/392.5 का पालन करता है) के अनुसार 0.04 या उससे अधिक BAC के साथ CMV चलाना गैरकानूनी है — गैर-वाणिज्यिक ड्राइवरों के लिए 0.08 सीमा का आधा। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51।"},"41":{"q":"वॉशिंगटन के निहित सहमति (implied consent) कानून के तहत, CDL रखने और वाहन चलाने से कोई ड्राइवर तब क्या करने के लिए सहमत माना जाता है जब किसी कानून प्रवर्तन अधिकारी के पास नशे का संदेह करने के उचित आधार हों?","options":["अल्कोहल या ड्रग्स के लिए सांस या रक्त परीक्षण कराना","सड़क किनारे एक निश्चित नकद बॉन्ड का भुगतान करना","मौके पर ही CDL को स्थायी रूप से समर्पित करना","पहले 12-hour अल्कोहल शिक्षा क्लास पूरी करना"],"explanation":"वॉशिंगटन का निहित-सहमति कानून (RCW 46.20.308) का अर्थ है कि राज्य में वाहन चलाने वाला कोई भी व्यक्ति, जब किसी अधिकारी के पास नशे में ड्राइविंग का संदेह करने के उचित आधार हों, रासायनिक परीक्षण (सांस या रक्त) के लिए सहमत हो गया है। स्रोत: RCW 46.20.308; Washington DOL CDL Guide।"},"42":{"q":"एक वॉशिंगटन CDL धारक को गैर-प्लेकार्ड वाणिज्यिक वाहन चलाते समय पहले DUI के लिए दोषी ठहराया जाता है। इस पहले प्रमुख अपराध के लिए अयोग्यता अवधि क्या है?","options":["1 year","3 years","60 days","6 months"],"explanation":"पहला प्रमुख अपराध (जिसमें DUI, BAC 0.04+, या परीक्षण से इनकार शामिल है) CDL को 1 year के लिए अयोग्य ठहराता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1।"},"43":{"q":"वॉशिंगटन में, यदि ड्राइवर उस समय प्लेकार्ड लगी खतरनाक सामग्री का परिवहन कर रहा था, तो पहले प्रमुख अपराध (जैसे DUI या BAC 0.04+) के लिए CDL अयोग्यता कितने समय की होती है?","options":["3 years","1 year","5 years","120 days"],"explanation":"प्लेकार्ड लगी खतरनाक सामग्री का परिवहन करते समय किया गया पहला प्रमुख अपराध अयोग्यता को 1 year से बढ़ाकर 3 years कर देता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1।"},"44":{"q":"वॉशिंगटन में दूसरे प्रमुख अपराध (उदाहरण के लिए, दूसरा DUI या दूसरा BAC 0.04+ दोषसिद्धि) के लिए CDL अयोग्यता अवधि क्या है?","options":["आजीवन (life)","10 years","5 years","3 years"],"explanation":"दूसरे प्रमुख अपराध के परिणामस्वरूप आजीवन CDL अयोग्यता होती है; वॉशिंगटन नोट करता है कि आप आजीवन अयोग्यता से पुनः योग्य नहीं हो सकते। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1।"},"45":{"q":"एक वॉशिंगटन CDL धारक गैर-प्लेकार्ड वाहन चलाते समय किसी अधिकारी द्वारा कानूनी रूप से अनुरोध किए जाने पर सांस या रक्त परीक्षण कराने से इनकार करता है। इस पहले इनकार के लिए अयोग्यता अवधि क्या है?","options":["1 year","90 days","3 years","60 days"],"explanation":"रासायनिक परीक्षण से इनकार करना एक प्रमुख अपराध माना जाता है, जो पहले इनकार पर CDL को 1 year के लिए अयोग्य ठहराता है (खतरनाक सामग्री के साथ प्लेकार्ड लगा होने पर 3 years)। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1।"},"46":{"q":"वॉशिंगटन में, सांस या रक्त परीक्षण से इनकार करना एक प्रमुख अपराध है जो आजीवन अयोग्यता की ओर गिना जाता है। परीक्षण से इनकार के बाद बाद में एक अलग DUI दोषसिद्धि का परिणाम क्या अयोग्यता होगी?","options":["आजीवन अयोग्यता (दो प्रमुख अपराध)","कुल मिलाकर केवल 1-year अयोग्यता","एक 120-day अयोग्यता","पहले से आगे कोई अतिरिक्त अयोग्यता नहीं"],"explanation":"परीक्षण से इनकार और DUI दोनों प्रमुख अपराध हैं; अलग-अलग घटनाओं से दो प्रमुख अपराध आजीवन CDL अयोग्यता को ट्रिगर करते हैं। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 1।"},"47":{"q":"3-year अवधि के भीतर (अलग-अलग घटनाओं में) कितने गंभीर यातायात उल्लंघन वॉशिंगटन में सबसे छोटी गंभीर-उल्लंघन CDL अयोग्यता को ट्रिगर करते हैं?","options":["2 गंभीर उल्लंघन","3 गंभीर उल्लंघन","1 गंभीर उल्लंघन","4 गंभीर उल्लंघन"],"explanation":"3 years के भीतर अलग-अलग घटनाओं से उत्पन्न दो गंभीर यातायात उल्लंघन एक 60-day अयोग्यता को ट्रिगर करते हैं; अकेला पहला एकल गंभीर उल्लंघन अयोग्य नहीं ठहराता। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2।"},"48":{"q":"वॉशिंगटन में 3-year अवधि के भीतर अलग-अलग घटनाओं में किए गए दो गंभीर यातायात उल्लंघनों के लिए CDL अयोग्यता अवधि क्या है?","options":["60 days","120 days","30 days","90 days"],"explanation":"3 years के भीतर दो गंभीर यातायात उल्लंघन (अलग-अलग घटनाएँ) एक 60-day CDL अयोग्यता का परिणाम होते हैं। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2।"},"49":{"q":"वॉशिंगटन में 3-year अवधि के भीतर अलग-अलग घटनाओं में किए गए तीन गंभीर यातायात उल्लंघनों के लिए CDL अयोग्यता अवधि क्या है?","options":["120 days","60 days","1 year","180 days"],"explanation":"3 years के भीतर तीन गंभीर यातायात उल्लंघन (अलग-अलग घटनाएँ) एक 120-day CDL अयोग्यता का परिणाम होते हैं। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 2।"},"50":{"q":"वॉशिंगटन CDL धारक को 'गंभीर यातायात उल्लंघन' के रूप में गिने जाने के लिए पोस्ट की गई गति सीमा से कितना ऊपर चालान किया जाना चाहिए?","options":["सीमा से 15 mph या अधिक ऊपर","सीमा से 10 mph या अधिक ऊपर","सीमा से 20 mph या अधिक ऊपर","सीमा से 25 mph या अधिक ऊपर"],"explanation":"पोस्ट की गई सीमा से 15 mph या अधिक तेज़ गति को वॉशिंगटन में CDL प्रयोजनों के लिए एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध किया गया है। स्रोत: Washington DOL serious traffic offenses page; 49 CFR 383.51 Table 2।"},"51":{"q":"वॉशिंगटन CDL धारक के लिए निम्नलिखित में से किसे 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["बहुत पास से चलना (tailgating)","नो-पार्किंग ज़ोन में पार्किंग","एक जली हुई लाइसेंस प्लेट लाइट","रजिस्ट्रेशन टैब प्रदर्शित करने में विफलता"],"explanation":"बहुत पास से चलना वॉशिंगटन की गंभीर-यातायात-उल्लंघन सूची में है (लापरवाह ड्राइविंग, अनुचित लेन परिवर्तन, 15+ ऊपर गति, और CMV में टेक्स्टिंग/फोन उपयोग के साथ)। उपकरण और पार्किंग उल्लंघन नहीं हैं। स्रोत: Washington DOL serious traffic offenses page; 49 CFR 383.51।"},"52":{"q":"वॉशिंगटन के नियम के तहत, वाणिज्यिक मोटर वाहन चलाते समय टेक्स्टिंग को CDL अयोग्यता प्रयोजनों के लिए कैसे वर्गीकृत किया गया है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक आउट-ऑफ-सर्विस ऑर्डर उल्लंघन","एक गैर-रिपोर्ट योग्य उपकरण उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग (और CMV चलाते समय हैंडहेल्ड फोन का उपयोग) एक गंभीर यातायात उल्लंघन है, इसलिए 3 years के भीतर दो उल्लंघन एक 60-day अयोग्यता लाते हैं। स्रोत: Washington DOL serious traffic offenses page; FMCSA 392.80/392.82।"},"53":{"q":"वॉशिंगटन में अपनाए गए संघीय नियम CMV ड्राइवर को ड्राइविंग करते समय हैंडहेल्ड मोबाइल फोन का उपयोग करने से रोकते हैं। इस हैंडहेल्ड/टेक्स्टिंग प्रतिबंध के उल्लंघन के लिए लगभग अधिकतम ड्राइवर नागरिक दंड क्या है?","options":["लगभग $2,750 तक","लगभग $250 तक","लगभग $500 तक","लगभग $1,000 तक"],"explanation":"CMV ड्राइवरों द्वारा हैंडहेल्ड फोन उपयोग और टेक्स्टिंग पर संघीय प्रतिबंध (FMCSA 392.80/392.82), जो वॉशिंगटन में लागू है, लगभग $2,750 तक के ड्राइवर नागरिक दंड वहन करता है। स्रोत: FMCSA 392.82; Washington DOL CDL Guide।"},"54":{"q":"वॉशिंगटन में CMV चलाते समय रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन की पहली दोषसिद्धि के लिए न्यूनतम CDL अयोग्यता अवधि क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"CMV में पहला रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन CDL को 60 days से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3।"},"55":{"q":"वॉशिंगटन में 3-year अवधि के भीतर दूसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम CDL अयोग्यता अवधि क्या है?","options":["120 days","60 days","1 year","180 days"],"explanation":"3 years के भीतर दूसरा रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन CDL को 120 days से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3।"},"56":{"q":"वॉशिंगटन में 3-year अवधि के भीतर तीसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम CDL अयोग्यता अवधि क्या है?","options":["1 year","120 days","60 days","3 years"],"explanation":"3 years के भीतर तीसरा रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन CDL को 1 year से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 3।"},"57":{"q":"वॉशिंगटन में गैर-हज़मत CMV चलाते समय आउट-ऑफ-सर्विस (OOS) ऑर्डर के पहले उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["180 days से कम नहीं और 1 year से अधिक नहीं","60 days से कम नहीं और 120 days से अधिक नहीं","30 days से कम नहीं और 90 days से अधिक नहीं","आजीवन अयोग्यता"],"explanation":"गैर-हज़मत वाहन के लिए पहला OOS-ऑर्डर उल्लंघन CDL को 180 days से कम नहीं और 1 year से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4।"},"58":{"q":"एक वॉशिंगटन ड्राइवर प्लेकार्ड लगी खतरनाक सामग्री ढोते हुए या 16 या अधिक यात्रियों को ले जाते हुए पहला आउट-ऑफ-सर्विस ऑर्डर उल्लंघन करता है। अयोग्यता सीमा क्या है?","options":["180 days से कम नहीं और 2 years से अधिक नहीं","180 days से कम नहीं और 1 year से अधिक नहीं","60 days से कम नहीं और 120 days से अधिक नहीं","1 year से कम नहीं और 5 years से अधिक नहीं"],"explanation":"प्लेकार्ड लगी हज़मत ढोते हुए या 16+ यात्रियों को ले जाते हुए पहला OOS-ऑर्डर उल्लंघन CDL को 180 days से कम नहीं और 2 years से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4।"},"59":{"q":"वॉशिंगटन में 10-year अवधि के भीतर अलग-अलग घटनाओं से उत्पन्न दूसरे आउट-ऑफ-सर्विस ऑर्डर उल्लंघन (गैर-हज़मत) के लिए अयोग्यता अवधि क्या है?","options":["2 years से कम नहीं और 5 years से अधिक नहीं","180 days से कम नहीं और 1 year से अधिक नहीं","1 year से कम नहीं और 3 years से अधिक नहीं","आजीवन अयोग्यता"],"explanation":"10 years के भीतर अलग-अलग घटनाओं में दूसरा OOS-ऑर्डर उल्लंघन (गैर-हज़मत) CDL को 2 years से कम नहीं और 5 years से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Washington DOL CDL disqualifications page; 49 CFR 383.51 Table 4।"},"60":{"q":"वॉशिंगटन में, हाईवे पर 10,000 पाउंड सकल वजन से अधिक के वाहन (या किसी भी संयोजन वाहन) के लिए अधिकतम गति सीमा क्या है, भले ही वहाँ कारें कानूनी रूप से तेज़ चल सकती हों?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"वॉशिंगटन 10,000 lbs सकल वजन से अधिक के वाहनों और सभी वाहन संयोजनों (ऑटो स्टेज को छोड़कर) की गति को 60 mph पर सीमित करता है, चाहे कारों के लिए कोई भी अधिक पोस्ट की गई सीमा क्यों न हो। स्रोत: RCW 46.61.410।"},"61":{"q":"आपकी दिशा में तीन या अधिक लेन वाले एक सीमित-पहुँच वॉशिंगटन फ्रीवे पर, 10,000 पाउंड से अधिक के ट्रक या संयोजन को कहाँ नहीं चलाया जा सकता (कानूनी बाएँ मोड़ की तैयारी के समय को छोड़कर)?","options":["सबसे दाहिनी लेन","कोई भी बीच की लेन","बाएँ हाथ की लेन","एक उच्च-अधिभोग वाहन (HOV) लेन"],"explanation":"ट्रेलर खींचने वाला कोई भी वाहन और 10,000 lbs से अधिक का कोई भी वाहन या संयोजन एक दिशा में तीन या अधिक लेन वाली सीमित-पहुँच सड़क की बाएँ हाथ की लेन में नहीं चलाया जा सकता, सिवाय कानूनी बाएँ मोड़ की तैयारी के लिए। HOV लेन को बाएँ हाथ की लेन के रूप में नहीं गिना जाता। स्रोत: RCW 46.61.100।"},"62":{"q":"एक वॉशिंगटन रेलरोड ग्रेड क्रॉसिंग के पास पहुँचते समय, एक स्कूल बस या प्लैकार्ड लगे खतरनाक-सामग्री वाहन के चालक को निकटतम रेल से कितने फुट के भीतर रुकना चाहिए?","options":["50 फुट के भीतर लेकिन 15 फुट से कम नहीं","75 फुट के भीतर लेकिन 25 फुट से कम नहीं","40 फुट के भीतर लेकिन 10 फुट से कम नहीं","100 फुट के भीतर लेकिन 30 फुट से कम नहीं"],"explanation":"वॉशिंगटन में स्कूल/यात्री बस, यात्री-वाहक वाणिज्यिक वाहन, या हैज़मैट कार्गो टैंक के चालक को स्टॉप लाइन से पहले रुकना आवश्यक है, अन्यथा निकटतम रेल से 50 फुट के भीतर लेकिन 15 फुट से कम नहीं। स्रोत: RCW 46.61.350।"},"63":{"q":"रेलरोड क्रॉसिंग पर रुकने के बाद, पटरियों को पार करते समय वॉशिंगटन कानून एक बस या प्लैकार्ड लगे हैज़मैट चालक से क्या अपेक्षा करता है?","options":["ऐसे गियर में पार करें जिसमें पटरियों पर रहते हुए गियर बदलने की आवश्यकता न हो, और पार करते समय गियर न बदलें","पटरियों के मध्य बिंदु पर सबसे निचले गियर में डाउनशिफ्ट करें","पटरियों को पार करने से पहले डिफरेंशियल लॉक लगाएँ","पटरियों पर हॉर्न तीन बार बजाने के बाद ही पार करें"],"explanation":"वॉशिंगटन कानून कहता है कि चालक को केवल ऐसे गियर में पार करना चाहिए जिसमें क्रॉसिंग पार करते समय गियर बदलने की आवश्यकता न पड़े और पटरियों को पार करते समय गियर नहीं बदल सकते। स्रोत: RCW 46.61.350।"},"64":{"q":"वॉशिंगटन के Move Over कानून के तहत, एक 'आपातकालीन या कार्य क्षेत्र' को चेतावनी संकेत प्रदर्शित करने वाले एक स्थिर आपातकालीन या कार्य वाहन से पहले और बाद में कितनी दूरी तक फैली सड़क की निकटवर्ती लेन के रूप में परिभाषित किया गया है?","options":["100 फुट","150 फुट","200 फुट","300 फुट"],"explanation":"वॉशिंगटन आपातकालीन या कार्य क्षेत्र को अपने चेतावनी संकेतों का उपयोग करने वाले एक स्थिर अधिकृत आपातकालीन वाहन, टो ट्रक, पुलिस, उपयोगिता, या हाईवे रखरखाव वाहन से 200 फुट पहले और बाद की निकटवर्ती लेन के रूप में परिभाषित करता है। स्रोत: RCW 46.61.212।"},"65":{"q":"चार से कम लेन वाले एक वॉशिंगटन हाईवे पर, यदि कोई चालक रुके हुए आपातकालीन/कार्य वाहन से दूर सुरक्षित रूप से लेन नहीं बदल सकता, तो चालक को गति को पोस्ट की गई गति सीमा से कम से कम कितना कम करना चाहिए (जहाँ सीमा 60 mph या उससे कम है)?","options":["पोस्ट की गई सीमा से 5 mph कम","पोस्ट की गई सीमा से 10 mph कम","पोस्ट की गई सीमा से 15 mph कम","पोस्ट की गई सीमा से 20 mph कम"],"explanation":"जब लेन बदलना असुरक्षित हो, तो वॉशिंगटन का Move Over कानून गति को पोस्ट की गई सीमा से कम से कम 10 mph कम करने की आवश्यकता बताता है; जहाँ पोस्ट की गई सीमा 60 mph से अधिक हो, वहाँ चालक को इसके बजाय 50 mph से अधिक नहीं तक धीमा करना चाहिए। स्रोत: RCW 46.61.212।"},"66":{"q":"विपरीत दिशा में यात्रा करते समय लाल चमकती बत्तियाँ प्रदर्शित कर रही एक रुकी हुई स्कूल बस से मिलने पर, किस वॉशिंगटन सड़क पर आपको रुकने की आवश्यकता नहीं है?","options":["एक दो-लेन अविभाजित हाईवे","एक हाईवे जो मीडियन या बैरियर द्वारा अलग सड़कों में विभाजित है","25 mph की पोस्ट की गई गति वाली कोई भी शहर की सड़क","एक केंद्रीय दो-तरफ़ा बाएँ-मोड़ लेन वाली दो-लेन सड़क"],"explanation":"एक हाईवे जो अलग सड़कों में विभाजित है (RCW 46.61.150 के अनुसार), या जिसमें तीन या अधिक चिह्नित लेन हैं, उस पर विपरीत दिशा में जा रही स्कूल बस से मिलने वाले चालक को रुकने की आवश्यकता नहीं है। अविभाजित दो-लेन सड़कों पर आपको रुकना ही चाहिए। स्रोत: RCW 46.61.370।"},"67":{"q":"विभाजित-हाईवे अपवाद के अलावा, किस अन्य प्रकार की वॉशिंगटन सड़क पर आप बिना रुके एक आने वाली, रुकी हुई स्कूल बस (विपरीत दिशा में जा रही) के पास से आगे बढ़ सकते हैं?","options":["तीन या अधिक चिह्नित यातायात लेन वाली एक सड़क","45 mph या उससे अधिक पर पोस्ट की गई कोई भी सड़क","कम से कम 8 फुट चौड़े पक्के किनारों वाली एक सड़क","केवल एक केंद्रीय मोड़ लेन वाली एक सड़क"],"explanation":"वॉशिंगटन का स्कूल-बस कानून यह जोड़ता है कि तीन या अधिक चिह्नित यातायात लेन वाले हाईवे पर विपरीत दिशा में आगे बढ़ रही बस से मिलने वाले चालकों को रुकने की आवश्यकता नहीं है। स्रोत: RCW 46.61.370।"},"68":{"q":"एक वॉशिंगटन ट्रक चालक एक दो-लेन, दो-तरफ़ा सड़क के किनारे पर रुकता है। चार-तरफ़ा फ्लैशर चालू करने के बाद, आवश्यक चेतावनी उपकरण (त्रिकोण) कितने मिनट के भीतर रखे जाने चाहिए?","options":["5 मिनट","10 मिनट","15 मिनट","30 मिनट"],"explanation":"सड़क या किनारे पर रुका हुआ एक CMV पहले हैज़र्ड फ्लैशर चालू करने के बाद, 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण रखना आवश्यक है। स्रोत: वॉशिंगटन CDL मैनुअल; 49 CFR 392.22 (वॉशिंगटन में अपनाया गया)।"},"69":{"q":"एक दो-लेन, दो-तरफ़ा वॉशिंगटन सड़क पर, एक रुके हुए CMV के लिए तीन परावर्तक त्रिकोण कहाँ रखे जाने चाहिए?","options":["तीनों वाहन के पीछे 10, 50, और 100 फुट पर","यातायात की ओर 10 फुट के भीतर, पीछे की ओर 100 फुट, और आगे की ओर 100 फुट","10, 100, और 200 फुट पर, सभी आने वाले यातायात की ओर","एक छत पर और दो आगे और पीछे 50 फुट पर"],"explanation":"एक दो-तरफ़ा सड़क पर, एक त्रिकोण वाहन के यातायात की ओर 10 फुट के भीतर, एक लगभग 100 फुट पीछे, और एक लगभग 100 फुट आगे रखें, ताकि दोनों दिशाओं के यातायात को चेतावनी मिले। स्रोत: वॉशिंगटन CDL मैनुअल; 49 CFR 392.22।"},"70":{"q":"एक वॉशिंगटन विभाजित या एक-तरफ़ा हाईवे पर, एक रुके हुए CMV के तीन चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["वाहन के पीछे आने वाले यातायात की ओर 10, 100, और 200 फुट पर","आने वाले यातायात की ओर 10, 50, और 100 फुट पर","एक आगे और दो पीछे की ओर 100 फुट पर","तीनों वाहन के पीछे 200 फुट पर"],"explanation":"एक विभाजित या एक-तरफ़ा हाईवे पर, त्रिकोणों को आने वाले यातायात की ओर वाहन से 10 फुट, 100 फुट, और 200 फुट पर रखें। स्रोत: वॉशिंगटन CDL मैनुअल; 49 CFR 392.22।"},"71":{"q":"वॉशिंगटन 10,000 पाउंड GVWR से अधिक के वाहनों और संयोजनों को निर्दिष्ट पर्वत-दर्रा मार्गों पर हर साल किस अवधि के दौरान टायर चेन ले जाना आवश्यक करता है?","options":["1 अक्टूबर से 1 मार्च","1 नवंबर से 1 अप्रैल","1 दिसंबर से 31 मार्च","15 नवंबर से 15 मार्च"],"explanation":"1 नवंबर से 1 अप्रैल तक, 10,000 lbs GVWR से अधिक के वाहनों और संयोजनों को निर्दिष्ट चेन मार्गों (जैसे, I-90, US 2 Stevens Pass, US 12 White Pass) पर चेन ले जाना आवश्यक है, चाहे वर्तमान स्थिति कुछ भी हो। स्रोत: WSDOT वाणिज्यिक-वाहन चेन आवश्यकताएँ; WAC 204-24-050।"},"72":{"q":"चेन-ले-जाने वाले मौसम के दौरान निर्दिष्ट चेन मार्गों पर 10,000 पाउंड GVWR से अधिक के एक वॉशिंगटन वाणिज्यिक वाहन को कितनी अतिरिक्त टायर चेन ले जानी चाहिए?","options":["कम से कम एक अतिरिक्त चेन","कम से कम दो अतिरिक्त चेन","कम से कम चार अतिरिक्त चेन","यदि ड्राइव टायरों पर पहले से चेन लगी हो तो कोई अतिरिक्त नहीं"],"explanation":"वॉशिंगटन इन वाहनों को 1 नवंबर से 1 अप्रैल की अवधि के दौरान कम से कम दो अतिरिक्त टायर चेन ले जाना आवश्यक करता है ताकि एक टूटी या अतिरिक्त-एक्सल चेन को बदला जा सके। स्रोत: WSDOT चेन आवश्यकताएँ; WAC 204-24-050।"},"73":{"q":"एक बहु-लेन वॉशिंगटन सड़क पर, राज्य कानून एक धीमे वाहन के बारे में क्या कहता है जो लगातार बाईं लेन में रहता है?","options":["यदि वाहन गति सीमा पर हो तो इसकी अनुमति है","बहु-लेन सड़क की बाईं लेन में लगातार चलना एक यातायात उल्लंघन है जब यह अन्य यातायात को बाधित करता है","केवल 10,000 पाउंड से कम के वाहनों के लिए अनुमति है","यदि दाईं लेन ट्रकों से भरी हो तो अनुमति है"],"explanation":"वॉशिंगटन का keep-right कानून बहु-लेन सड़क की बाईं लेन में लगातार चलना एक यातायात उल्लंघन बनाता है जब ऐसा करना अन्य यातायात के प्रवाह को बाधित करता है। स्रोत: RCW 46.61.100।"},"74":{"q":"अपनी लाल बत्तियाँ और स्टॉप पैडल प्रदर्शित कर रही एक रुकी हुई वॉशिंगटन स्कूल बस को अवैध रूप से पार करने का दंड क़ानून में इस प्रकार वर्णित है:","options":["एक निश्चित $250 जुर्माना जिसे अदालत कम कर सकती है","आधार दंड का दोगुना, जिसे माफ, कम, या निलंबित नहीं किया जा सकता","पहले अपराध के लिए एक लिखित चेतावनी","केवल लाइसेंस निलंबन, बिना किसी मौद्रिक दंड के"],"explanation":"एक चालक जो एक रुकी हुई स्कूल बस को गैरकानूनी रूप से पार करता है, उस पर RCW 46.63.110 के तहत आधार दंड के दोगुने के बराबर एक मौद्रिक दंड लगाया जाता है, और इसे माफ, कम, या निलंबित नहीं किया जा सकता। स्रोत: RCW 46.61.370।"},"75":{"q":"जब वॉशिंगटन स्टेट पैट्रोल 10,000 पाउंड से अधिक के वाहनों के लिए 'Chains Required' पोस्ट करता है, तो क्या स्टडेड टायर इस आवश्यकता को पूरा करते हैं?","options":["हाँ, स्टडेड टायर चेन के रूप में गिने जाते हैं","हाँ, लेकिन केवल ड्राइव एक्सल पर","नहीं; स्टडेड टायरों पर भी चेन लगानी होगी","केवल ऑल-व्हील-ड्राइव वाहन छूट प्राप्त हैं"],"explanation":"वॉशिंगटन में स्टडेड टायर एक पोस्ट की गई चेन आवश्यकता को पूरा नहीं करते; चालकों को एक पोस्ट किए गए चेन-अप बिंदु से आगे बढ़ने के लिए चेन (यदि स्टडेड टायर लगे हों तो उनके ऊपर) लगानी होगी। स्रोत: WSDOT/WSP शीतकालीन चेन आवश्यकताएँ।"},"76":{"q":"वॉशिंगटन में, एक एकल ओवरसाइज़/ओवरवेट परमिट आम तौर पर तब आवश्यक होता है जब कोई वाहन या भार इनमें से किस कानूनी आयाम सीमा को पार करता है?","options":["8 फुट 6 इंच चौड़ा, 14 फुट ऊँचा, या लागू लंबाई सीमाएँ","10 फुट चौड़ा, 13 फुट 6 इंच ऊँचा, या 48 फुट लंबा","9 फुट चौड़ा, 15 फुट ऊँचा, या 60 फुट लंबा","8 फुट चौड़ा, 12 फुट ऊँचा, या 35 फुट लंबा"],"explanation":"वॉशिंगटन की कानूनी सीमाएँ आम तौर पर 8 ft 6 in चौड़ी और 14 ft ऊँची हैं; चौड़ाई, ऊँचाई, या लागू लंबाई सीमाओं को पार करने पर एक WSDOT ओवरसाइज़ परमिट आवश्यक है। स्रोत: WSDOT Commercial Vehicle Services ओवरसाइज़/ओवरवेट परमिट।"},"77":{"q":"वॉशिंगटन में कौन सा पर्वतीय हाईवे एक निर्दिष्ट चेन/ट्रैक्शन मार्ग है जहाँ वाणिज्यिक-वाहन चेन आवश्यकताएँ आमतौर पर लागू की जाती हैं?","options":["Snoqualmie Pass के ऊपर I-90","डाउनटाउन Seattle से होकर I-5","Bellevue के आसपास I-405","SR 520 फ्लोटिंग ब्रिज"],"explanation":"Snoqualmie Pass के ऊपर I-90 (North Bend से Ellensburg) एक प्राथमिक निर्दिष्ट चेन मार्ग है, US 2 Stevens Pass और US 12 White Pass के साथ; I-5, I-405, और SR 520 जैसे शहरी इंटरस्टेट पर्वतीय चेन मार्ग नहीं हैं। स्रोत: WSDOT पर्वत दर्रा चेन आवश्यकताएँ।"},"78":{"q":"एक खड़ी ढलान पर एक वॉशिंगटन रनअवे ट्रक एस्केप रैंप आमतौर पर एक भारी वाहन को रोकने के लिए इस तरह बनाया जाता है:","options":["एक ढीली-बजरी या नरम-रेत की क्यारी, कभी-कभी एक चढ़ाई पर, जो आपके जितना आगे यात्रा करने पर प्रतिरोध बढ़ाती है","लेन के पार फैला एक स्टील गार्डरेल जाल","एक ढलान वाली पक्की नली जो ट्रक को रुकने तक धीमे चलने देती है","एक पानी से भरा कुंड जो टायरों को तैराता है"],"explanation":"वॉशिंगटन एस्केप रैंप ढीली बजरी या नरम रेत का उपयोग करते हैं, कभी-कभी एक चढ़ाई वाली ढलान के साथ; ट्रक जितना अंदर यात्रा करता है, प्रतिरोध उतना बढ़ता है, जिससे उसे रुकने में मदद मिलती है। स्रोत: वॉशिंगटन CDL मैनुअल, पर्वतीय ड्राइविंग / एस्केप रैंप।"},"79":{"q":"चार या अधिक लेन वाले हाईवे पर वॉशिंगटन के Move Over कानून के तहत, चमकती बत्तियों वाले एक रुके हुए आपातकालीन/कार्य वाहन के पास पहुँचते समय चालक का पहला कर्तव्य क्या है:","options":["वाहन के हटने तक लेन में पूरी तरह रुकें","सावधानी से आगे बढ़ें, गति कम करें, और यदि ऐसा करना सुरक्षित हो तो उससे दूर लेन बदलें","हॉर्न बजाएँ और पोस्ट की गई गति बनाए रखें","किनारे पर चले जाएँ और दाईं ओर से पार करें"],"explanation":"चार या अधिक लेन वाले हाईवे पर, चालकों को सावधानी से आगे बढ़ना चाहिए, गति कम करनी चाहिए, और जब सुरक्षित हो तब क्षेत्र से एक लेन दूर हटकर रास्ता देना चाहिए; केवल यदि लेन बदलना असुरक्षित हो तो वे आवश्यक कम गति तक धीमे हों। स्रोत: RCW 46.61.212।"},"80":{"q":"वॉशिंगटन में वाणिज्यिक चालक लाइसेंस (CDL) कौन सी एजेंसी जारी करती है?","options":["Washington State Department of Licensing (DOL)","Washington State Patrol (WSP)","Washington State Department of Transportation (WSDOT)","संघीय Motor Carrier Safety Administration (FMCSA)"],"explanation":"वॉशिंगटन में Department of Licensing (DOL) CDL जारी करता है और CDL परीक्षण का संचालन करता है। स्रोत: WA DOL, 'Getting a commercial driver license (CDL).'"},"81":{"q":"एक वॉशिंगटन CDL आवेदक आवश्यक कौशल परीक्षा कहाँ दे सकता है?","options":["एक DOL परीक्षक या एक DOL-अधिकृत तृतीय-पक्ष परीक्षक (TPE) के साथ","केवल Washington State Patrol वाणिज्यिक वाहन प्रभाग में","केवल DOL वेबसाइट के माध्यम से ऑनलाइन","अपनी पसंद के किसी भी FMCSA Training Provider Registry स्कूल में"],"explanation":"वॉशिंगटन की CDL कौशल परीक्षा या तो एक DOL परीक्षक द्वारा या एक DOL-अधिकृत तृतीय-पक्ष परीक्षक (TPE) द्वारा दी जाती है। स्रोत: WA DOL, 'CDL skills test.'"},"82":{"q":"वॉशिंगटन CDL कौशल परीक्षा कितने भागों से बनी है?","options":["तीन: वाहन (प्री-ट्रिप) निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग परीक्षा","दो: एक लिखित परीक्षा और एक रोड टेस्ट","चार: लिखित, दृष्टि, निरीक्षण, और रोड टेस्ट","एक संयुक्त रोड टेस्ट जिसमें सब कुछ शामिल है"],"explanation":"वॉशिंगटन CDL कौशल परीक्षा के तीन भाग होते हैं जो क्रम में लिए जाते हैं: वाहन (प्री-ट्रिप) निरीक्षण, बुनियादी वाहन नियंत्रण कौशल, और ऑन-रोड ड्राइविंग परीक्षा। स्रोत: WA DOL, 'CDL skills test.'"},"83":{"q":"एक वॉशिंगटन Commercial Learner's Permit (CLP) जारी होने की तारीख से कितने समय तक वैध है?","options":["180 दिन","30 दिन","1 साल","60 दिन"],"explanation":"एक वॉशिंगटन CLP जारी होने की तारीख से 180 दिनों के लिए वैध है। स्रोत: WA DOL, 'Commercial learner's permit (CLP).'"},"84":{"q":"एक वॉशिंगटन CLP जारी होने के बाद, धारक को CDL कौशल परीक्षा देने से पहले कितनी देर प्रतीक्षा करनी चाहिए?","options":["14 कैलेंडर दिन","30 कैलेंडर दिन","7 कैलेंडर दिन","किसी प्रतीक्षा अवधि की आवश्यकता नहीं है"],"explanation":"वॉशिंगटन एक मूल या उन्नत CLP जारी होने के बाद धारक के कौशल परीक्षा देने से पहले 14-कैलेंडर-दिन की प्रतीक्षा आवश्यक करता है, जो संघीय CLP नियम के अनुरूप है। स्रोत: WA DOL, 'Commercial learner's permit (CLP)' / 'CDL skills test.'"},"85":{"q":"वॉशिंगटन में CDL कौशल परीक्षा देने से पहले, एक पहली बार Class A या Class B आवेदक को कौन सी आवश्यकता पूरी करनी चाहिए?","options":["FMCSA Training Provider Registry पर एक प्रदाता से Entry-Level Driver Training (ELDT)","DOL के साथ दर्ज एक चार-वर्षीय शिक्षुता","Washington State Patrol द्वारा अनुमोदित एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","WSDOT द्वारा प्रस्तुत एक रोड-रेज रोकथाम संगोष्ठी"],"explanation":"7 फरवरी, 2022 से, पहली बार Class A/B आवेदकों को परीक्षण से पहले FMCSA Training Provider Registry पर सूचीबद्ध एक प्रदाता से ELDT पूरा करना होगा, और वॉशिंगटन पूर्णता सत्यापित होने तक परीक्षा का संचालन नहीं कर सकता। स्रोत: FMCSA ELDT नियम; WA DOL, 'CDL skills test.'"},"86":{"q":"एक वॉशिंगटन CDL आवेदक को अपने द्वारा की जाने वाली ड्राइविंग के प्रकार की घोषणा करते समय कितनी स्व-प्रमाणन श्रेणियों में से चुनना चाहिए?","options":["चार","दो","तीन","पाँच"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं: non-excepted interstate, excepted interstate, non-excepted intrastate, और excepted intrastate। स्रोत: WA DOL, 'Medical certificates and self-certification'; 49 CFR 383.71।"},"87":{"q":"कौन सी वॉशिंगटन स्व-प्रमाणन श्रेणी में एक चालक को फ़ाइल पर एक चिकित्सा परीक्षक का प्रमाणपत्र रखने की आवश्यकता नहीं होती?","options":["Excepted intrastate","Non-excepted interstate","Excepted interstate","Non-excepted intrastate"],"explanation":"चार में से तीन श्रेणियों में एक चिकित्सा परीक्षक का प्रमाणपत्र आवश्यक है; केवल excepted intrastate चालकों के लिए 'कोई दस्तावेज़ आवश्यक नहीं' है। स्रोत: WA DOL, 'Medical certificates and self-certification.'"},"88":{"q":"वर्तमान वॉशिंगटन/संघीय नियमों के तहत, एक चालक का DOT चिकित्सा परीक्षक का प्रमाणपत्र आमतौर पर DOL तक कैसे पहुँचता है?","options":["चिकित्सा परीक्षक इसे National Registry पर अपलोड करता है, जो इसे DOL को प्रेषित करता है","चालक हमेशा Washington, D.C. में FMCSA को एक कागज़ी प्रति मेल करता है","नियोक्ता इसे Washington State Patrol को फ़ैक्स करता है","CLP जारी होने पर प्रमाणपत्र स्वचालित रूप से उत्पन्न होता है"],"explanation":"प्रमाणित चिकित्सा परीक्षक प्रमाणपत्र को FMCSA National Registry पर अपलोड करता है, और परिणाम चालक के रिकॉर्ड को अपडेट करने के लिए DOL को प्रेषित किया जाता है। स्रोत: WA DOL, 'Medical certificates and self-certification.'"},"89":{"q":"DOL को एक चालक के CDL चिकित्सा दस्तावेज़ प्राप्त होने के बाद, चालक के रिकॉर्ड को अपडेट करने में आमतौर पर कितना समय लगता है?","options":["7 से 10 व्यावसायिक दिन","1 से 2 व्यावसायिक दिन","30 से 45 व्यावसायिक दिन","उसी व्यावसायिक दिन"],"explanation":"DOL बताता है कि चिकित्सा दस्तावेज़ प्राप्त होने के बाद एक रिकॉर्ड को अपडेट करने में 7-10 व्यावसायिक दिन लग सकते हैं। स्रोत: WA DOL, 'Medical certificates and self-certification.'"},"90":{"q":"वॉशिंगटन DOL ज्ञान परीक्षाओं की तैयारी के लिए CDL आवेदकों को कौन सी अध्ययन मार्गदर्शिका का उपयोग करने का निर्देश देता है?","options":["Washington Commercial Driver Guide","Washington Driver Guide (गैर-वाणिज्यिक)","FMCSA Hazardous Materials Compliance Pocketbook","Washington Trucker's Almanac"],"explanation":"DOL CDL आवेदकों को Washington Commercial Driver Guide का अध्ययन करने का निर्देश देता है, जिसके बारे में वह कहता है कि इसमें परीक्षा पास करने के लिए आवश्यक सभी जानकारी है। स्रोत: WA DOL, 'CDL knowledge test.'"},"91":{"q":"वॉशिंगटन DOL किन भाषाओं में CDL ज्ञान परीक्षा प्रदान करता है?","options":["अंग्रेज़ी, स्पेनिश, रूसी, और सर्बो-क्रोएशियाई","केवल अंग्रेज़ी","केवल अंग्रेज़ी और स्पेनिश","कोई भी भाषा, आवेदक द्वारा प्रदान किए गए एक दुभाषिए के साथ"],"explanation":"वॉशिंगटन CDL ज्ञान परीक्षा अंग्रेज़ी, स्पेनिश, रूसी, और सर्बो-क्रोएशियाई में प्रदान करता है, और भाषा दुभाषियों की अनुमति नहीं है। स्रोत: WA DOL, 'CDL knowledge test.'"},"92":{"q":"एक वॉशिंगटन CDL ज्ञान परीक्षा शुल्क भुगतान के बाद किस समयावधि के भीतर ली गई प्रत्येक ज्ञान परीक्षा के एक प्रयास को कवर करता है?","options":["90 दिन","30 दिन","180 दिन","1 साल"],"explanation":"ज्ञान परीक्षा शुल्क प्राप्ति के 90 दिनों के भीतर ली गई प्रत्येक ज्ञान परीक्षा के एक प्रयास को कवर करता है। स्रोत: WA DOL, 'CDL knowledge test.'"},"93":{"q":"एक वॉशिंगटन आवेदक को CLP के लिए आवेदन करने के लिए कौन से दस्तावेज़ लाने चाहिए?","options":["एक वैध WA चालक लाइसेंस, Social Security नंबर का प्रमाण, और U.S. नागरिकता या वैध स्थायी निवास का प्रमाण","केवल एक जन्म प्रमाणपत्र","एक पासपोर्ट और दो उपयोगिता बिल","एक वाहन पंजीकरण और बीमा का प्रमाण"],"explanation":"एक CLP के लिए आवेदन करने हेतु DOL एक वर्तमान वॉशिंगटन चालक लाइसेंस, Social Security नंबर, और U.S. नागरिकता या वैध स्थायी निवास का प्रमाण आवश्यक करता है। स्रोत: WA DOL, 'Commercial learner's permit (CLP).'"},"94":{"q":"वॉशिंगटन में एक खतरनाक सामग्री (H) एंडोर्समेंट के लिए परीक्षण से पहले, एक आवेदक को किस प्रकार का ELDT पूरा करना चाहिए?","options":["एक FMCSA Training Provider Registry प्रदाता से सिद्धांत (ज्ञान) प्रशिक्षण, H ज्ञान परीक्षा से पहले लिया गया","एक पूर्ण बिहाइंड-द-व्हील रेंज और रोड कोर्स","कोई प्रशिक्षण नहीं, केवल पृष्ठभूमि जाँच","Washington State Patrol द्वारा पर्यवेक्षित ऑन-रोड प्रशिक्षण"],"explanation":"हैज़मैट (H) एंडोर्समेंट के लिए, ELDT केवल सिद्धांत है और राज्य की H ज्ञान परीक्षा देने से पहले एक Training Provider Registry प्रदाता के साथ पूरा किया जाना चाहिए। स्रोत: FMCSA ELDT नियम; FMCSA Training Provider Registry, 'ELDT Applicability.'"},"95":{"q":"मानक गैर-उन्नत वॉशिंगटन CDL नवीनीकरण चक्र किस प्रकार संरचित है?","options":["इसे हर 6 साल में नवीनीकृत करना होगा","इसे हर 4 साल में नवीनीकृत करना होगा","इसे हर 10 साल में नवीनीकृत करना होगा","एक बार जारी होने के बाद यह कभी समाप्त नहीं होता"],"explanation":"एक मानक वॉशिंगटन CDL 6-वर्षीय चक्र पर जारी किया जाता है। स्रोत: WA DOL, 'Renew your CDL.'"},"96":{"q":"एक वॉशिंगटन चालक अपने CDL के समाप्त होने से कितनी जल्दी पहले उसे नवीनीकृत कर सकता है?","options":["समाप्त होने से 1 साल पहले तक","समाप्त होने से 6 महीने पहले तक","केवल ठीक समाप्ति तिथि पर","समाप्त होने से 90 दिन पहले तक"],"explanation":"DOL लाइसेंस समाप्त होने से 1 साल पहले तक CDL नवीनीकरण की अनुमति देता है। स्रोत: WA DOL, 'Renew your CDL.'"},"97":{"q":"यदि एक वॉशिंगटन CDL 8 साल से अधिक समय से समाप्त हो चुका है तो क्या होता है?","options":["चालक नवीनीकरण नहीं कर सकता और उसे CDL प्रक्रिया फिर से शुरू करनी होगी","चालक अभी भी एक छोटे विलंब शुल्क के साथ ऑनलाइन नवीनीकरण कर सकता है","एक दृष्टि परीक्षा के बाद लाइसेंस स्वचालित रूप से बहाल हो जाता है","चालक समाप्त हो चुके कार्ड पर एक और साल तक गाड़ी चला सकता है"],"explanation":"यदि एक वॉशिंगटन CDL 8 साल से अधिक समय से समाप्त हो चुका है, तो इसे नवीनीकृत नहीं किया जा सकता और चालक को लाइसेंसिंग प्रक्रिया फिर से शुरू करनी होगी। स्रोत: WA DOL, 'Renew your CDL.'"},"98":{"q":"एक वॉशिंगटन CLP को कितनी बार और किस शर्त पर नवीनीकृत किया जा सकता है?","options":["एक बार, यदि इसकी समाप्ति के 30 दिनों के भीतर नवीनीकृत किया जाए, जो इसे अन्य 180 दिनों के लिए बढ़ाता है","असीमित बार, जब तक धारक अध्ययन करता रहे","समय की परवाह किए बिना प्रति कैलेंडर वर्ष दो बार","इसे कभी नवीनीकृत नहीं किया जा सकता; एक नया जारी करना होगा"],"explanation":"एक वॉशिंगटन CLP को केवल एक बार, समाप्ति के 30 दिनों के भीतर नवीनीकृत किया जा सकता है, जो इसे अन्य 180 दिनों के लिए बढ़ाता है। स्रोत: WA DOL, 'Commercial learner's permit (CLP).'"},"99":{"q":"वॉशिंगटन में, किन CDL घटनाओं के लिए एक Training Provider Registry प्रदाता से Entry-Level Driver Training (ELDT) आवश्यक है?","options":["पहला Class A या Class B CDL प्राप्त करना, Class B को Class A में अपग्रेड करना, और पहला H, P, या S एंडोर्समेंट प्राप्त करना","केवल पहला Class C CDL प्राप्त करना","केवल एक मौजूदा CDL का नवीनीकरण","विफलता के बाद हर ज्ञान-परीक्षा पुनः प्रयास"],"explanation":"ELDT पहली बार Class A या Class B आवेदकों, Class B-से-Class A अपग्रेड, और पहली बार खतरनाक सामग्री (H), यात्री (P), या स्कूल बस (S) एंडोर्समेंट पर लागू होता है; वॉशिंगटन परीक्षण से पहले पूर्णता सत्यापित करता है। स्रोत: FMCSA Training Provider Registry, 'ELDT Applicability.'"}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني للعرض الخارجي للمركبة أو حمولتها على الطرق العامة في ولاية واشنطن، دون تصريح خاص؟","options":["8 أقدام (96 بوصة)","8 أقدام و6 بوصات (102 بوصة)","9 أقدام (108 بوصات)","10 أقدام (120 بوصة)"],"explanation":"تحدد المادة RCW 46.44.010 إجمالي العرض الخارجي للمركبة أو حمولتها بـ 8 أقدام و6 بوصات (102 بوصة)، باستثناء بعض أجهزة السلامة والمرايا. وهذا أيضاً هو المعيار الفيدرالي. المصدر: RCW 46.44.010؛ دليل المركبات التجارية لـ WSDOT."},"1":{"q":"ما هو الحد الأقصى القانوني للارتفاع، بما في ذلك الحمولة، لمركبة على طرق ولاية واشنطن دون تصريح خاص؟","options":["13 قدماً و6 بوصات","14 قدماً","14 قدماً و6 بوصات","15 قدماً"],"explanation":"تجعل المادة RCW 46.44.020 من غير القانوني أن يتجاوز ارتفاع مركبة، فارغة أو محملة، 14 قدماً فوق السطح الذي تقف عليه. المصدر: RCW 46.44.020."},"2":{"q":"ما هو الحد الأقصى القانوني لطول مركبة مفردة (وليست مجموعة مركبات) على طرق ولاية واشنطن دون تصريح؟","options":["35 قدماً","40 قدماً","45 قدماً","48 قدماً"],"explanation":"تحدد المادة RCW 46.44.030 الحد الأقصى العام لطول المركبة المفردة بـ 40 قدماً، مع استثناءات تسمح للحافلات والمنازل المتنقلة ومقطورات السفر بأن تصل إلى 46 قدماً. المصدر: RCW 46.44.030."},"3":{"q":"في مجموعة جرار-نصف مقطورة على طرق ولاية واشنطن، ما هو الحد الأقصى المسموح به لطول نصف المقطورة بمفردها (دون تصريح)؟","options":["48 قدماً","53 قدماً","57 قدماً","60 قدماً"],"explanation":"تحظر المادة RCW 46.44.030 تشغيل جرار-نصف مقطورة بطول نصف مقطورة يتجاوز 53 قدماً. المصدر: RCW 46.44.030."},"4":{"q":"ما هو الحد الأقصى للحمولة الإجمالية التي تسمح بها ولاية واشنطن على أي محور مفرد دون تصريح خاص؟","options":["18,000 رطل","20,000 رطل","22,400 رطل","24,000 رطل"],"explanation":"تحظر المادة RCW 46.44.041 وجود حمولة إجمالية على أي محور مفرد تتجاوز 20,000 رطل. المصدر: RCW 46.44.041؛ WSDOT 'الوزن القانوني للمركبة'."},"5":{"q":"ما هو الحد الأقصى القياسي للحمولة الإجمالية على مجموعة محاور ترادفية في ولاية واشنطن (دون تصريح)؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"بموجب المادة RCW 46.44.041 والمعيار الفيدرالي المعتمد في ولاية واشنطن، تقتصر مجموعة المحاور الترادفية على 34,000 رطل. المصدر: RCW 46.44.041."},"6":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به على نظام الطرق السريعة بين الولايات في ولاية واشنطن دون تصريح؟","options":["80,000 رطل","90,000 رطل","100,000 رطل","105,500 رطل"],"explanation":"على نظام الطرق بين الولايات، يحدد القانون الفيدرالي المعتمد من قبل ولاية واشنطن الوزن الإجمالي بـ 80,000 رطل. وتنطبق الأرقام الأعلى فقط على بعض طرق الولاية غير العابرة للولايات. المصدر: RCW 46.44.041؛ 23 CFR 658.17؛ WSDOT."},"7":{"q":"بموجب جدول الأوزان في ولاية واشنطن، ما هو الحد الأقصى لإجمالي الوزن الإجمالي للمركبة الذي يمكن حمله قانونياً على طرق الولاية غير العابرة للولايات مع وجود محاور وقاعدة عجلات كافية (دون تصريح للوزن الزائد)؟","options":["80,000 رطل","98,000 رطل","105,500 رطل","120,000 رطل"],"explanation":"يسمح جدول وزن قاعدة العجلات/المحاور في المادة RCW 46.44.041 بما يصل إلى 105,500 رطل وزناً إجمالياً على الطرق غير العابرة للولايات عندما يكون تباعد المحاور وعددها مؤهلين لذلك. ويبقى نظام الطرق بين الولايات محدداً بـ 80,000 رطل. المصدر: RCW 46.44.041؛ WSDOT."},"8":{"q":"أي معادلة تستخدمها ولاية واشنطن لتحديد الوزن الأقصى المسموح به على مجموعة من المحاور المتتالية؟","options":["W = 500[LN/(N-1) + 12N + 36]","W = 1000(L + N + 12)","W = 700[LN/(N+1) + 10N]","W = 250[LN + 24N + 40]"],"explanation":"تتضمن المادة RCW 46.44.041 معادلة الجسر الفيدرالية W = 500[LN/(N-1) + 12N + 36]، حيث L هي المسافة بين المحاور الطرفية للمجموعة وN هو عدد المحاور. المصدر: RCW 46.44.041؛ معادلة الجسر لـ FHWA."},"9":{"q":"في معادلة الجسر لولاية واشنطن W = 500[LN/(N-1) + 12N + 36]، ماذا يمثل الرمز 'N'؟","options":["عدد المحاور في المجموعة","المسافة بالأقدام بين المحاور الطرفية","الوزن الصافي للحمولة بالأطنان","عدد الإطارات على محور القيادة"],"explanation":"في معادلة الجسر المعتمدة بموجب المادة RCW 46.44.041، N هو عدد المحاور في المجموعة قيد الدراسة وL هو التباعد بالأقدام بين المحاور الطرفية لتلك المجموعة. المصدر: RCW 46.44.041؛ FHWA."},"10":{"q":"في ولاية واشنطن، يتم تحديد الوزن الإجمالي المسموح به على محور مفرد أيضاً بعرض الإطار. ما هو الحد الأقصى للوزن لكل بوصة من عرض الإطار؟","options":["500 رطل لكل بوصة","550 رطل لكل بوصة","600 رطل لكل بوصة","700 رطل لكل بوصة"],"explanation":"تحدد المادة RCW 46.44.042 وزن المحور بـ 600 رطل لكل بوصة من عرض الإطار. ويخضع وزن المحور الإجمالي للأكثر تقييداً من بين حجم الإطار ووزن المحور وجدول الأوزان. المصدر: RCW 46.44.042؛ WSDOT."},"11":{"q":"يمكن لمجموعتين متتاليتين من المحاور الترادفية أن تحمل كل منهما 34,000 رطل في ولاية واشنطن فقط إذا كانت المسافة بين أول وآخر محور للمجموعتين متباعدة بمقدار لا يقل عن كم؟","options":["30 قدماً","34 قدماً","36 قدماً","40 قدماً"],"explanation":"تسمح المادة RCW 46.44.041 لمجموعتين متتاليتين من المحاور الترادفية بحمل 34,000 رطل لكل منهما فقط عندما تكون المسافة الإجمالية بين أول وآخر محور للمجموعتين 36 قدماً أو أكثر. المصدر: RCW 46.44.041."},"12":{"q":"تحتاج شركة نقل إلى نقل حمولة تتجاوز حدود الحجم أو الوزن القانونية في ولاية واشنطن. من الذي يصدر التصريح الخاص للحركة على طرق الولاية؟","options":["دورية ولاية واشنطن","إدارة الترخيص","إدارة النقل في ولاية واشنطن (WSDOT)","مكتب شريف المقاطعة"],"explanation":"تخوّل المادة RCW 46.44.090 إدارة WSDOT بإصدار تصاريح خاصة للحجم/الوزن الزائد لطرق الولاية؛ وتصدرها السلطات المحلية للطرق الواقعة ضمن اختصاصها. المصدر: RCW 46.44.090؛ تصاريح المركبات التجارية لـ WSDOT."},"13":{"q":"بموجب المادة RCW 46.44.090، ماذا يجب على مقدم الطلب أن يُثبت عموماً للحصول على تصريح خاص للحجم الزائد أو الوزن الزائد في ولاية واشنطن؟","options":["طلب مكتوب وإثبات سبب وجيه","خطاب إعفاء فيدرالي","إثبات تأمين على الشحن بقيمة مليون دولار","سجل قيادة نظيف لمدة خمس سنوات"],"explanation":"تنص المادة RCW 46.44.090 على أنه يجوز لـ WSDOT أو السلطات المحلية إصدار تصريح خاص بناءً على طلب مكتوب (أو إلكتروني) وإثبات سبب وجيه. المصدر: RCW 46.44.090."},"14":{"q":"متى يكون التصريح الخاص للحجم الزائد/الوزن الزائد في ولاية واشنطن مطلوباً؟","options":["فقط عندما تكون المركبة فارغة","كلما تجاوزت المركبة أو الحمولة الحدود القانونية في المواد RCW 46.44.010 حتى 46.44.041","فقط على الطرق ذات الرسوم","فقط للمركبات التي يزيد طولها عن 53 قدماً"],"explanation":"تتطلب المادة RCW 46.44.090 تصريحاً خاصاً لنقل مركبة أو حمولة تتجاوز الحدود القصوى المحددة في المواد RCW 46.44.010 و.020 و.030 و.034 و.041. ويُشترط الحصول على تصريح للحمولة غير القابلة للتجزئة التي لا يمكن تقليصها بدلاً من تقسيمها. المصدر: RCW 46.44.090."},"15":{"q":"تسمح ولاية واشنطن لشاحنات نقل الأخشاب بالحصول على تصريح خاص لـ 'تسامح الأخشاب'. ما مقدار الوزن الإجمالي الإضافي الذي يسمح به هذا التصريح فوق الحد الأقصى القانوني المعتاد؟","options":["حتى 4,000 رطل","حتى 6,800 رطل","حتى 10,000 رطل","حتى 12,500 رطل"],"explanation":"تسمح المادة RCW 46.44.047 لشاحنات نقل الأخشاب التي تنقل الجذوع بتجاوز الحد الأقصى للوزن الإجمالي القانوني (68,000 رطل عند الترخيص الكامل) بما لا يزيد عن 6,800 رطل بموجب تصريح خاص لتسامح الأخشاب. المصدر: RCW 46.44.047."},"16":{"q":"ما هو الرسم السنوي لتصريح تسامح الأخشاب الخاص في ولاية واشنطن عند إصداره لكامل فترة الـ 12 شهراً؟","options":["$25","$50","$100","$120"],"explanation":"تحدد المادة RCW 46.44.047 رسم تصريح تسامح الأخشاب الخاص بـ $50 لفترة الـ 12 شهراً التي تبدأ في 1 أبريل، مع رسوم منخفضة مخفضة نسبياً إذا أُصدر لاحقاً خلال سنة التصريح. المصدر: RCW 46.44.047."},"17":{"q":"في مجموعة مركبات بولاية واشنطن مكوّنة من جرار ومقطورتين ('مزدوجة')، ما هو الحد الأقصى للطول المجمّع للمقطورتين دون تصريح؟","options":["56 قدماً","61 قدماً","65 قدماً","68 قدماً"],"explanation":"تحدد المادة RCW 46.44.030 الجرار المزود بمقطورتين بحيث لا يتجاوز الطول المجمّع للمقطورتين 61 قدماً. المصدر: RCW 46.44.030."},"18":{"q":"يسمح تصريح الحجم الزائد للرحلة الواحدة ذاتي الإصدار من WSDOT بالحركة حتى أي أبعاد ووزن أقصى قبل الحاجة إلى تصريح أكثر تخصصاً؟","options":["عرض 12 قدماً، ارتفاع 14 قدماً، 100,000 رطل","عرض 14 قدماً، ارتفاع 15 قدماً، 150,000 رطل","عرض 16 قدماً، ارتفاع 16 قدماً، 200,000 رطل","عرض 20 قدماً، ارتفاع 18 قدماً، 250,000 رطل"],"explanation":"يغطي نظام التصريح ذاتي الإصدار لـ WSDOT الحمولات حتى عرض 16 قدماً، وارتفاع 16 قدماً، وطول حمولة 125 قدماً، و200,000 رطل؛ وتتطلب عمليات النقل الأكبر تصريحاً يصدره مكتب تصاريح WSDOT مباشرة. المصدر: تصاريح المركبات التجارية لـ WSDOT، 'إصدار تصريح ذاتياً'."},"19":{"q":"لوائح أي وكالة تحدد الوزن الإجمالي بـ 80,000 رطل على نظام الطرق بين الولايات، وهو حد يجب على ولاية واشنطن اتباعه للحفاظ على التمويل الفيدرالي للطرق السريعة؟","options":["وكالة حماية البيئة","إدارة الطرق السريعة الفيدرالية (FHWA) بموجب 23 CFR Part 658","قسم الفحص الطبي لإدارة سلامة الناقلين بالمركبات الآلية الفيدرالية","لجنة التجارة بين الولايات"],"explanation":"يأتي حد الوزن الإجمالي البالغ 80,000 رطل على الطرق بين الولايات ومعادلة الجسر من لوائح FHWA في 23 CFR Part 658، التي تعتمدها ولاية واشنطن في المادة RCW 46.44.041 لنظام الطرق بين الولايات. وتعكس الحدود الأعلى للطرق غير العابرة للولايات حقوق ولاية واشنطن المكتسبة. المصدر: 23 CFR 658.17؛ RCW 46.44.041."},"20":{"q":"في ولاية واشنطن، أي فئة من رخصة القيادة التجارية CDL مطلوبة لقيادة مركبة مركّبة بتصنيف وزن إجمالي للمجموعة (GCWR) قدره 26,001 رطل أو أكثر، حيث تتجاوز الوحدة (الوحدات) المقطورة 10,000 رطل من تصنيف الوزن الإجمالي للمركبة GVWR؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تتطلب ولاية واشنطن رخصة CDL من الفئة A لمركبة مركّبة بتصنيف GCWR قدره 26,001 رطل أو أكثر عندما يكون لدى المركبة (المركبات) المقطورة تصنيف GVWR يزيد عن 10,000 رطل. المصدر: WA DOL، أنواع رخص CDL / دليل سائق المركبات التجارية لولاية واشنطن."},"21":{"q":"بموجب قواعد ولاية واشنطن، أي نوع من المركبات تغطيه رخصة CDL من الفئة B؟","options":["أي مركبة مفردة بتصنيف GVWR قدره 26,001 رطل أو أكثر (وتقطر وحدة بوزن 10,000 رطل أو أقل)","مركبة مركّبة تقطر مقطورة تزيد عن 10,000 رطل","فقط المركبات التي تحمل 16 راكباً أو أكثر","فقط المركبات التي تحمل لوحات إرشادية للمواد الخطرة"],"explanation":"تغطي رخصة CDL من الفئة B في ولاية واشنطن أي مركبة مفردة بتصنيف GVWR قدره 26,001 رطل أو أكثر، بما في ذلك مركبة كهذه تقطر مقطورة مصنفة بـ 10,000 رطل أو أقل. وتتطلب المركبات المركّبة ذات وحدة مقطورة أثقل الفئة A. المصدر: WA DOL، أنواع رخص CDL."},"22":{"q":"تكون رخصة CDL من الفئة C في ولاية واشنطن مطلوبة عندما لا تستوفي المركبة عتبات وزن الفئة A أو B لكنها مصممة لنقل ما لا يقل عن كم شخصاً (بما في ذلك السائق)، أو تنقل مواد خطرة تتطلب لوحات إرشادية؟","options":["16 أو أكثر","12 أو أكثر","20 أو أكثر","10 أو أكثر"],"explanation":"تنطبق رخصة CDL من الفئة C على المركبات التي تحمل 16 شاغلاً أو أكثر بما في ذلك السائق، أو التي تنقل مواد خطرة تتطلب لوحات إرشادية، عندما تكون المركبة أخف من أن تنطبق عليها الفئة A أو B. المصدر: WA DOL، أنواع رخص CDL."},"23":{"q":"أي تصديق تتطلبه ولاية واشنطن لسائق يقطر مجموعات من المقطورات المزدوجة أو الثلاثية؟","options":["تصديق T","تصديق N","تصديق H","تصديق X"],"explanation":"يُطلب تصديق T (المزدوجة/الثلاثية) في ولاية واشنطن للسائقين الذين يقطرون مجموعات من المقطورات المزدوجة أو الثلاثية، ويتم الحصول عليه باجتياز اختبار المعرفة فقط. المصدر: WA DOL، التصديقات والقيود."},"24":{"q":"في ولاية واشنطن، يُطلب تصديق N (مركبة الصهريج) لمركبة تجارية مصممة لنقل مواد سائلة أو غازية في صهريج بسعة مصنفة فردية تزيد عن 119 غالوناً وسعة مصنفة إجمالية لا تقل عن كم غالوناً؟","options":["1,000 غالون","500 غالون","750 غالون","1,500 غالون"],"explanation":"تتطلب ولاية واشنطن تصديق N لأي مركبة تجارية مصممة لنقل مواد سائلة/غازية في صهريج بسعة مصنفة فردية تزيد عن 119 غالوناً وسعة مصنفة إجمالية قدرها 1,000 غالون أو أكثر. المصدر: WA DOL، التصديقات والقيود."},"25":{"q":"أي تصديق لرخصة CDL في ولاية واشنطن مطلوب لقيادة مركبة ركاب مصممة لنقل 16 شخصاً أو أكثر (بما في ذلك السائق)؟","options":["تصديق P","تصديق S","تصديق T","تصديق N"],"explanation":"يُطلب تصديق P (الركاب) في ولاية واشنطن لسائقي مركبات الركاب المصممة لنقل 16 شخصاً أو أكثر بما في ذلك السائق. المصدر: WA DOL، التصديقات والقيود."},"26":{"q":"في ولاية واشنطن، يُطلب تصديق S (حافلة المدرسة) لقيادة ماذا؟","options":["حافلة مدرسة من أي حجم تُستخدم لنقل الأطفال من/إلى المدرسة أو الأنشطة المدرسية","فقط حافلات المدرسة التي تحمل 16 طفلاً أو أكثر","فقط حافلات المدرسة التي تعمل بالديزل","فقط حافلات المدرسة التي تُشغّل عبر حدود المقاطعات"],"explanation":"تتطلب ولاية واشنطن تصديق S لقيادة حافلة مدرسة من أي حجم تُستخدم بانتظام لنقل الأطفال من وإلى المدرسة أو فيما يتعلق بالأنشطة المدرسية. المصدر: WA DOL، التصديقات والقيود."},"27":{"q":"قبل الحصول على تصديق المواد الخطرة (H) في ولاية واشنطن، يجب على السائق إكمال تقييم فيدرالي للتهديد الأمني تديره أي وكالة، بما في ذلك أخذ البصمات؟","options":["إدارة أمن النقل (TSA)","دورية ولاية واشنطن (WSP)","إدارة سلامة الناقلين بالمركبات الآلية الفيدرالية (FMCSA)","إدارة الترخيص (DOL) فقط"],"explanation":"تتطلب ولاية واشنطن من المتقدمين للحصول على تصديق المواد الخطرة أخذ بصماتهم واجتياز تقييم تهديد تصديق المواد الخطرة الذي تديره TSA قبل إصدار تصديق H. المصدر: WA DOL، تصديق المواد الخطرة (HazMat)؛ TSA HTAP."},"28":{"q":"يجب تجديد تصديق المواد الخطرة (H) على رخصة CDL في ولاية واشنطن، مع تقييم تهديد جديد من TSA، على الأقل كل كم؟","options":["كل 5 سنوات","كل سنتين","كل 8 سنوات","كل 10 سنوات"],"explanation":"تتطلب القواعد الفيدرالية المطبقة في ولاية واشنطن تجديد تصديق المواد الخطرة، بما في ذلك بصمات جديدة وفحص خلفية جديد من TSA، على الأقل كل 5 سنوات. المصدر: WA DOL، تصديق HazMat؛ TSA HTAP."},"29":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في ولاية واشنطن للقيادة داخل الولاية (INTRASTATE) فقط؟","options":["18 عاماً","21 عاماً","19 عاماً","16 عاماً"],"explanation":"تسمح ولاية واشنطن للسائق الذي يبلغ من العمر 18 عاماً على الأقل بالحصول على رخصة CDL للتجارة داخل الولاية؛ ويتطلب التشغيل بين الولايات سن 21 عاماً. المصدر: WA DOL، الحصول على رخصة قيادة تجارية (CDL)."},"30":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في ولاية واشنطن تسمح بالقيادة في التجارة بين الولايات (INTERSTATE) (عبر حدود الولايات)؟","options":["21 عاماً","18 عاماً","19 عاماً","25 عاماً"],"explanation":"يجب أن يكون عمر السائق 21 عاماً على الأقل لتشغيل مركبة تجارية آلية عبر حدود الولايات بموجب قواعد ولاية واشنطن والقواعد الفيدرالية. المصدر: WA DOL، الحصول على رخصة قيادة تجارية (CDL)."},"31":{"q":"في ولاية واشنطن، كم تبلغ مدة صلاحية تصريح المتعلم التجاري (CLP) من تاريخ إصداره؟","options":["180 يوماً","90 يوماً","سنة واحدة","60 يوماً"],"explanation":"تصريح CLP في ولاية واشنطن صالح لمدة 180 يوماً من تاريخ الإصدار، ويمكن تجديده مرة واحدة خلال 30 يوماً من انتهاء صلاحيته لمدة 180 يوماً إضافية. المصدر: WA DOL، تصريح المتعلم التجاري (CLP)."},"32":{"q":"بعد إصدار تصريح CLP أصلي في ولاية واشنطن، كم يجب أن ينتظر السائق قبل إجراء اختبار مهارات رخصة CDL؟","options":["14 يوماً تقويمياً","7 أيام تقويمية","30 يوماً تقويمياً","10 أيام عمل"],"explanation":"تتطلب القواعد الفيدرالية المعتمدة من قبل ولاية واشنطن فترة انتظار قدرها 14 يوماً تقويمياً بعد إصدار تصريح CLP أصلي أو مرقّى قبل أن يتمكن السائق من إجراء اختبار المهارات. المصدر: WA DOL، تصريح المتعلم التجاري (CLP)."},"33":{"q":"أثناء القيادة بتصريح CLP في ولاية واشنطن، يجب أن يحمل حامل رخصة CDL المشرف الجالس بجانب حامل التصريح رخصة CDL سارية بالفئة/التصديقات المناسبة وأن يكون لديه خبرة لا تقل عن كم؟","options":["سنتان في ذلك النوع من المركبات و5 سنوات إجمالية من القيادة","سنة واحدة من القيادة بـ CDL","6 أشهر في ذلك النوع من المركبات","10 سنوات إجمالية من القيادة"],"explanation":"تتطلب ولاية واشنطن أن يكون لدى حامل رخصة CDL المرافق التصديقات المناسبة، وخبرة لا تقل عن سنتين في ذلك النوع من المركبات، وما لا يقل عن 5 سنوات إجمالية من خبرة القيادة. المصدر: WA DOL، تصريح المتعلم التجاري (CLP)."},"34":{"q":"أي فئة من المستندات لا تكون مطلوبة بشكل منفصل عند التقدم للحصول على رخصة CDL في ولاية واشنطن؟","options":["إثبات امتلاكك لمركبة تجارية","إثبات الهوية / تاريخ الميلاد","رقم الضمان الاجتماعي","إثبات الجنسية الأمريكية أو الإقامة الدائمة القانونية"],"explanation":"تتطلب ولاية واشنطن إثبات الهوية، ورقم الضمان الاجتماعي، وإثبات الإقامة، وإثبات الجنسية الأمريكية أو الإقامة الدائمة القانونية (الوجود القانوني)؛ ولا يُشترط امتلاك مركبة تجارية. المصدر: WA DOL، المستندات المعتمدة لرخصة CDL."},"35":{"q":"لإثبات الوجود القانوني للحصول على رخصة CDL في ولاية واشنطن، يجب على مقدم الطلب تقديم أي مما يلي؟","options":["مستند واحد معتمد فيدرالياً مثل جواز سفر أمريكي، أو شهادة ميلاد، أو بطاقة إقامة دائمة (أصلية، وليست نسخة مصورة)","أي فاتورتي خدمات","بيان موثّق بالجنسية","بطاقة تسجيل ناخب فقط"],"explanation":"تتطلب ولاية واشنطن مستنداً أصلياً واحداً مقبولاً يثبت الجنسية الأمريكية أو الإقامة الدائمة القانونية، مثل جواز سفر أمريكي، أو شهادة ميلاد صادرة عن جهة حكومية، أو بطاقة إقامة دائمة؛ ولا تُقبل النسخ المصورة. المصدر: WA DOL، المستندات المعتمدة لرخصة CDL."},"36":{"q":"أصبح تدريب السائق المبتدئ (ELDT) إلزامياً في ولاية واشنطن للمتقدمين الذين يحصلون على تصريح CLP في أو بعد أي تاريخ؟","options":["7 فبراير 2022","1 يناير 2020","1 سبتمبر 2021","1 يوليو 2023"],"explanation":"تتطلب قواعد ELDT الفيدرالية، المطبقة في ولاية واشنطن، التدريب من مزوّد مسجّل للمتقدمين الذين يحصلون على تصريح CLP في أو بعد 7 فبراير 2022. المصدر: FMCSA تدريب السائق المبتدئ؛ WA DOL، متطلبات تدريب CDL."},"37":{"q":"بموجب قواعد ELDT في ولاية واشنطن، يجب على السائق الساعي للحصول على أي اعتماد إكمال التدريب من مزوّد مدرج في سجل مزودي التدريب التابع لـ FMCSA قبل الاختبار؟","options":["رخصة CDL من الفئة A أو الفئة B لأول مرة، أو تصديق P أو S أو H لأول مرة","فقط تصديق T (المزدوجة/الثلاثية)","فقط تصديق N (الصهريج)","تجديد رخصة CDL قائمة دون تغيير الفئة"],"explanation":"تنطبق قواعد ELDT على المتقدمين للحصول على رخصة CDL من الفئة A والفئة B لأول مرة (وترقيات B إلى A) وعلى المتقدمين للحصول على تصديق الركاب (P) وحافلة المدرسة (S) والمواد الخطرة (H) لأول مرة؛ ويجب أن يكون المزوّد مدرجاً في سجل مزودي التدريب التابع لـ FMCSA. المصدر: FMCSA انطباق ELDT."},"38":{"q":"عند التقدم للحصول على رخصة CDL في ولاية واشنطن، تعني فئة التصديق الذاتي الطبي 'غير المستثنى بين الولايات' (Non-Excepted Interstate) أن السائق:","options":["يعمل في التجارة بين الولايات ويجب أن يحافظ على شهادة فاحص طبي DOT سارية","يعمل فقط داخل ولاية واشنطن وهو معفى من جميع المتطلبات الطبية","يعمل في التجارة بين الولايات لكنه معفى من الشهادة الطبية","يقود فقط على ملكية خاصة ولا يحتاج إلى شهادة"],"explanation":"من بين فئات التصديق الذاتي الأربع، تعني 'غير المستثنى بين الولايات' أن السائق يعمل عبر حدود الولايات ويجب أن يحمل ويحافظ على شهادة فاحص طبي DOT سارية. المصدر: فئات التصديق الذاتي الطبي لـ FMCSA؛ WA DOL، الحصول على رخصة CDL."},"39":{"q":"أي مما يلي يُعد إحدى فئات التصديق الذاتي الطبي الأربع لرخصة CDL التي يجب على مقدم الطلب في ولاية واشنطن الاختيار من بينها؟","options":["المستثنى داخل الولاية (Excepted Intrastate)","المؤقت بين الولايات (Provisional Interstate)","المشروط داخل الولاية (Conditional Intrastate)","المقيّد بين الولايات (Restricted Interstate)"],"explanation":"فئات التصديق الذاتي الأربع لـ FMCSA المستخدمة في ولاية واشنطن هي: غير المستثنى بين الولايات، والمستثنى بين الولايات، وغير المستثنى داخل الولاية، والمستثنى داخل الولاية. المصدر: FMCSA التصديق الذاتي الطبي؛ WA DOL، الحصول على رخصة CDL."},"40":{"q":"في ولاية واشنطن، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده للشخص قانونياً تشغيل مركبة تجارية آلية (CMV)؟","options":["0.04","0.08","0.02","0.10"],"explanation":"يجعل قانون ولاية واشنطن (ودليل CDL لولاية واشنطن، الذي يتبع 49 CFR 383.51/392.5) تشغيل مركبة CMV بتركيز BAC قدره 0.04 أو أكثر غير قانوني — أي نصف حد الـ 0.08 للسائقين غير التجاريين. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51."},"41":{"q":"بموجب قانون الموافقة الضمنية في ولاية واشنطن، يُعتبر السائق بحمله رخصة CDL وتشغيله مركبة أنه قد وافق على فعل ماذا إذا كان لدى ضابط إنفاذ القانون أسباب معقولة للاشتباه في القيادة تحت تأثير مسكر؟","options":["الخضوع لاختبار النفس أو الدم للكحول أو المخدرات","دفع كفالة نقدية ثابتة على جانب الطريق","تسليم رخصة CDL بشكل دائم في الحال","إكمال صف تثقيف عن الكحول لمدة 12 ساعة أولاً"],"explanation":"يعني قانون الموافقة الضمنية في ولاية واشنطن (RCW 46.20.308) أن أي شخص يقود في الولاية قد وافق على الاختبار الكيميائي (النفس أو الدم) عندما يكون لدى الضابط أسباب معقولة للاشتباه في القيادة تحت تأثير مسكر. المصدر: RCW 46.20.308؛ دليل CDL لإدارة DOL في ولاية واشنطن."},"42":{"q":"أُدين حامل رخصة CDL في ولاية واشنطن بأول قيادة تحت تأثير مسكر (DUI) أثناء قيادة مركبة تجارية غير حاملة للوحات إرشادية. ما هي مدة عدم الأهلية لهذه المخالفة الكبرى الأولى؟","options":["سنة واحدة","3 سنوات","60 يوماً","6 أشهر"],"explanation":"تؤدي أول مخالفة كبرى (بما في ذلك القيادة تحت تأثير مسكر، أو BAC بنسبة 0.04 فأكثر، أو رفض الاختبار) إلى عدم أهلية رخصة CDL لمدة سنة واحدة. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 1."},"43":{"q":"في ولاية واشنطن، كم تبلغ مدة عدم أهلية رخصة CDL لأول مخالفة كبرى (مثل القيادة تحت تأثير مسكر أو BAC بنسبة 0.04 فأكثر) إذا كان السائق ينقل مواد خطرة حاملة للوحات إرشادية في ذلك الوقت؟","options":["3 سنوات","سنة واحدة","5 سنوات","120 يوماً"],"explanation":"ترفع أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة حاملة للوحات إرشادية مدة عدم الأهلية من سنة واحدة إلى 3 سنوات. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 1."},"44":{"q":"ما هي مدة عدم أهلية رخصة CDL في ولاية واشنطن لثاني مخالفة كبرى (على سبيل المثال، ثاني قيادة تحت تأثير مسكر أو ثاني إدانة بـ BAC بنسبة 0.04 فأكثر)؟","options":["مدى الحياة (الحياة)","10 سنوات","5 سنوات","3 سنوات"],"explanation":"تؤدي ثاني مخالفة كبرى إلى عدم أهلية رخصة CDL مدى الحياة؛ وتشير ولاية واشنطن إلى أنه لا يمكنك إعادة التأهل من عدم الأهلية مدى الحياة. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 1."},"45":{"q":"يرفض حامل رخصة CDL في ولاية واشنطن الخضوع لاختبار النفس أو الدم عند طلبه قانونياً من قبل ضابط أثناء تشغيل مركبة غير حاملة للوحات إرشادية. ما هي مدة عدم الأهلية لهذا الرفض الأول؟","options":["سنة واحدة","90 يوماً","3 سنوات","60 يوماً"],"explanation":"يُعامَل رفض الاختبار الكيميائي كمخالفة كبرى، مما يؤدي إلى عدم أهلية رخصة CDL لمدة سنة واحدة عند الرفض الأول (3 سنوات إذا كانت حاملة للوحات إرشادية للمواد الخطرة). المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 1."},"46":{"q":"في ولاية واشنطن، يُعد رفض اختبار النفس أو الدم مخالفة كبرى تُحتسب ضمن عدم الأهلية مدى الحياة. رفض اختبار يتبعه لاحقاً إدانة منفصلة بالقيادة تحت تأثير مسكر سيؤدي إلى أي عدم أهلية؟","options":["عدم الأهلية مدى الحياة (مخالفتان كبريان)","عدم أهلية لمدة سنة واحدة فقط في المجموع","عدم أهلية لمدة 120 يوماً","لا عدم أهلية إضافية بعد الأولى"],"explanation":"كل من رفض الاختبار والقيادة تحت تأثير مسكر مخالفتان كبريان؛ وتؤدي مخالفتان كبريان من حادثتين منفصلتين إلى عدم أهلية رخصة CDL مدى الحياة. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 1."},"47":{"q":"كم عدد المخالفات المرورية الخطيرة خلال فترة 3 سنوات (في حوادث منفصلة) التي تُحدث أقصر مدة عدم أهلية لرخصة CDL بسبب المخالفات الخطيرة في ولاية واشنطن؟","options":["مخالفتان خطيرتان","3 مخالفات خطيرة","مخالفة خطيرة واحدة","4 مخالفات خطيرة"],"explanation":"تُحدث مخالفتان مروريتان خطيرتان ناشئتان عن حادثتين منفصلتين خلال 3 سنوات عدم أهلية لمدة 60 يوماً؛ ولا تؤدي المخالفة الخطيرة الأولى المفردة وحدها إلى عدم الأهلية. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 2."},"48":{"q":"ما هي مدة عدم أهلية رخصة CDL في ولاية واشنطن لمخالفتين مروريتين خطيرتين ارتُكبتا في حادثتين منفصلتين خلال فترة 3 سنوات؟","options":["60 يوماً","120 يوماً","30 يوماً","90 يوماً"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات (حادثتان منفصلتان) إلى عدم أهلية رخصة CDL لمدة 60 يوماً. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 2."},"49":{"q":"ما هي مدة عدم أهلية رخصة CDL في ولاية واشنطن لثلاث مخالفات مرورية خطيرة ارتُكبت في حوادث منفصلة خلال فترة 3 سنوات؟","options":["120 يوماً","60 يوماً","سنة واحدة","180 يوماً"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات (حوادث منفصلة) إلى عدم أهلية رخصة CDL لمدة 120 يوماً. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 2."},"50":{"q":"كم يجب أن تتجاوز سرعة حامل رخصة CDL في ولاية واشنطن حد السرعة المعلن ليُحرَّر له مخالفة تُحتسب كـ 'مخالفة مرورية خطيرة'؟","options":["15 ميلاً في الساعة أو أكثر فوق الحد","10 أميال في الساعة أو أكثر فوق الحد","20 ميلاً في الساعة أو أكثر فوق الحد","25 ميلاً في الساعة أو أكثر فوق الحد"],"explanation":"يُدرج تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق الحد المعلن كمخالفة مرورية خطيرة لأغراض رخصة CDL في ولاية واشنطن. المصدر: صفحة المخالفات المرورية الخطيرة لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 2."},"51":{"q":"أي مما يلي يُصنّف كـ 'مخالفة مرورية خطيرة' لحامل رخصة CDL في ولاية واشنطن؟","options":["الاقتراب بشكل مفرط من المركبة الأمامية (السير اللصيق)","الوقوف في منطقة ممنوع الوقوف فيها","ضوء لوحة ترخيص محترق","عدم عرض ملصق التسجيل"],"explanation":"يُدرج الاقتراب بشكل مفرط على قائمة المخالفات المرورية الخطيرة في ولاية واشنطن (إلى جانب القيادة المتهورة، وتغيير المسار غير السليم، وتجاوز السرعة بـ 15 فأكثر، والمراسلة النصية/استخدام الهاتف في مركبة CMV). أما مخالفات المعدات والوقوف فليست كذلك. المصدر: صفحة المخالفات المرورية الخطيرة لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51."},"52":{"q":"بموجب قاعدة ولاية واشنطن، كيف تُصنّف المراسلة النصية أثناء قيادة مركبة تجارية آلية لأغراض عدم أهلية رخصة CDL؟","options":["مخالفة مرورية خطيرة","مخالفة كبرى","مخالفة أمر بإخراج المركبة من الخدمة","مخالفة معدات غير قابلة للإبلاغ"],"explanation":"تُعد المراسلة النصية أثناء قيادة مركبة CMV (واستخدام هاتف محمول باليد أثناء قيادة مركبة CMV) مخالفة مرورية خطيرة، لذا فإن مخالفتين خلال 3 سنوات تؤديان إلى عدم أهلية لمدة 60 يوماً. المصدر: صفحة المخالفات المرورية الخطيرة لإدارة DOL في ولاية واشنطن؛ FMCSA 392.80/392.82."},"53":{"q":"تحظر القواعد الفيدرالية المعتمدة في ولاية واشنطن على سائق المركبة التجارية الآلية استخدام هاتف محمول باليد أثناء القيادة. ما هو الحد الأقصى التقريبي للغرامة المدنية على السائق لمخالفة هذا القيد الخاص بالهاتف المحمول باليد/المراسلة النصية؟","options":["حتى نحو $2,750","حتى نحو $250","حتى نحو $500","حتى نحو $1,000"],"explanation":"يحمل القيد الفيدرالي على استخدام الهاتف المحمول باليد والمراسلة النصية من قبل سائقي مركبات CMV (FMCSA 392.80/392.82)، المطبق في ولاية واشنطن، غرامات مدنية على السائق تصل إلى نحو $2,750. المصدر: FMCSA 392.82؛ دليل CDL لإدارة DOL في ولاية واشنطن."},"54":{"q":"ما هي المدة الدنيا لعدم أهلية رخصة CDL في ولاية واشنطن لأول إدانة بمخالفة معبر السكة الحديدية مع الطريق السريع أثناء تشغيل مركبة CMV؟","options":["60 يوماً","30 يوماً","120 يوماً","سنة واحدة"],"explanation":"تؤدي أول مخالفة لمعبر السكة الحديدية مع الطريق السريع في مركبة CMV إلى عدم أهلية رخصة CDL لمدة لا تقل عن 60 يوماً. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 3."},"55":{"q":"ما هي المدة الدنيا لعدم أهلية رخصة CDL في ولاية واشنطن لثاني مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات؟","options":["120 يوماً","60 يوماً","سنة واحدة","180 يوماً"],"explanation":"تؤدي ثاني مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال 3 سنوات إلى عدم أهلية رخصة CDL لمدة لا تقل عن 120 يوماً. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 3."},"56":{"q":"ما هي المدة الدنيا لعدم أهلية رخصة CDL في ولاية واشنطن لثالث مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات؟","options":["سنة واحدة","120 يوماً","60 يوماً","3 سنوات"],"explanation":"تؤدي ثالث مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال 3 سنوات إلى عدم أهلية رخصة CDL لمدة لا تقل عن سنة واحدة. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 3."},"57":{"q":"ما هي مدة عدم الأهلية في ولاية واشنطن لأول مخالفة لأمر بإخراج المركبة من الخدمة (OOS) أثناء تشغيل مركبة CMV غير ناقلة للمواد الخطرة؟","options":["لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة","لا تقل عن 60 يوماً ولا تزيد عن 120 يوماً","لا تقل عن 30 يوماً ولا تزيد عن 90 يوماً","عدم الأهلية مدى الحياة"],"explanation":"تؤدي أول مخالفة لأمر OOS إلى عدم أهلية رخصة CDL لمدة لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة لمركبة غير ناقلة للمواد الخطرة. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 4."},"58":{"q":"يرتكب سائق في ولاية واشنطن أول مخالفة لأمر بإخراج المركبة من الخدمة أثناء نقل مواد خطرة حاملة للوحات إرشادية أو حمل 16 راكباً أو أكثر. ما هو نطاق عدم الأهلية؟","options":["لا تقل عن 180 يوماً ولا تزيد عن سنتين","لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة","لا تقل عن 60 يوماً ولا تزيد عن 120 يوماً","لا تقل عن سنة واحدة ولا تزيد عن 5 سنوات"],"explanation":"تؤدي أول مخالفة لأمر OOS أثناء نقل مواد خطرة حاملة للوحات إرشادية أو حمل 16 راكباً فأكثر إلى عدم أهلية رخصة CDL لمدة لا تقل عن 180 يوماً ولا تزيد عن سنتين. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 4."},"59":{"q":"ما هي مدة عدم الأهلية في ولاية واشنطن لثاني مخالفة لأمر بإخراج المركبة من الخدمة (غير ناقلة للمواد الخطرة) خلال فترة 10 سنوات، ناشئة عن حوادث منفصلة؟","options":["لا تقل عن سنتين ولا تزيد عن 5 سنوات","لا تقل عن 180 يوماً ولا تزيد عن سنة واحدة","لا تقل عن سنة واحدة ولا تزيد عن 3 سنوات","عدم الأهلية مدى الحياة"],"explanation":"تؤدي ثاني مخالفة لأمر OOS (غير ناقلة للمواد الخطرة) في حوادث منفصلة خلال 10 سنوات إلى عدم أهلية رخصة CDL لمدة لا تقل عن سنتين ولا تزيد عن 5 سنوات. المصدر: صفحة عدم أهلية CDL لإدارة DOL في ولاية واشنطن؛ 49 CFR 383.51 الجدول 4."},"60":{"q":"في واشنطن، ما هو الحد الأقصى للسرعة المسموح بها للمركبة التي يزيد وزنها الإجمالي عن 10,000 رطل (أو أي مركبة مركّبة) على الطريق السريع، حتى في الأماكن التي يجوز فيها للسيارات أن تسير بسرعة أعلى بشكل قانوني؟","options":["55 ميلاً في الساعة","60 ميلاً في الساعة","65 ميلاً في الساعة","70 ميلاً في الساعة"],"explanation":"تحدد واشنطن سرعة المركبات التي يزيد وزنها الإجمالي عن 10,000 رطل وجميع المركبات المركّبة (باستثناء مركبات النقل الآلية) بحد أقصى قدره 60 ميلاً في الساعة، بغض النظر عن وجود حد أعلى معلن للسيارات. المصدر: RCW 46.61.410."},"61":{"q":"على طريق سريع محدود الوصول في واشنطن يضم ثلاثة مسارات أو أكثر في اتجاهك، أين لا يُسمح بقيادة الشاحنة أو المركبة المركّبة التي يزيد وزنها عن 10,000 رطل (إلا عند الاستعداد لانعطاف قانوني إلى اليسار)؟","options":["المسار الأقصى يميناً","أي مسار أوسط","المسار الأيسر","مسار المركبات عالية الإشغال (HOV)"],"explanation":"لا يجوز قيادة أي مركبة تجر مقطورة ولا أي مركبة أو مركبة مركّبة يزيد وزنها عن 10,000 رطل في المسار الأيسر من طريق محدود الوصول يضم ثلاثة مسارات أو أكثر في اتجاه واحد، إلا للاستعداد لانعطاف قانوني إلى اليسار. ولا يُحتسب مسار المركبات عالية الإشغال (HOV) على أنه المسار الأيسر. المصدر: RCW 46.61.100."},"62":{"q":"عند الاقتراب من مزلقان سكة حديد عند مستوى الطريق في واشنطن، يجب على سائق الحافلة المدرسية أو مركبة المواد الخطرة التي تحمل لافتات تحذيرية أن يتوقف ضمن كم قدماً من أقرب قضيب سكة؟","options":["ضمن 50 قدماً ولكن ليس أقل من 15 قدماً","ضمن 75 قدماً ولكن ليس أقل من 25 قدماً","ضمن 40 قدماً ولكن ليس أقل من 10 أقدام","ضمن 100 قدم ولكن ليس أقل من 30 قدماً"],"explanation":"تشترط واشنطن على سائق الحافلة المدرسية/حافلة الركاب، أو المركبة التجارية الناقلة للركاب، أو صهريج شحن المواد الخطرة أن يتوقف قبل خط التوقف، أو خلاف ذلك ضمن 50 قدماً ولكن ليس أقل من 15 قدماً من أقرب قضيب سكة. المصدر: RCW 46.61.350."},"63":{"q":"بعد التوقف عند مزلقان سكة حديد، ماذا يشترط قانون واشنطن على سائق الحافلة أو مركبة المواد الخطرة التي تحمل لافتات تحذيرية أثناء عبور القضبان؟","options":["العبور بترس لا يتطلب أي تغيير في التروس أثناء التواجد على القضبان، وعدم تغيير التروس أثناء العبور","خفض الترس إلى أدنى ترس عند منتصف القضبان","تعشيق قفل الفرق (التفاضلي) قبل العبور","العبور فقط بعد إطلاق البوق ثلاث مرات على القضبان"],"explanation":"ينص قانون واشنطن على أنه يجب على السائق العبور فقط بترس لا يتطلب تغيير التروس أثناء اجتياز المزلقان، ولا يجوز له تغيير التروس أثناء عبور القضبان. المصدر: RCW 46.61.350."},"64":{"q":"بموجب قانون \"التزحزح جانباً\" (Move Over) في واشنطن، تُعرّف \"منطقة الطوارئ أو منطقة العمل\" بأنها المسارات المجاورة من الطريق التي تمتد إلى أي مسافة قبل وبعد مركبة طوارئ أو مركبة عمل متوقفة تعرض إشارات تحذيرية؟","options":["100 قدم","150 قدماً","200 قدم","300 قدم"],"explanation":"تُعرّف واشنطن منطقة الطوارئ أو منطقة العمل بأنها المسارات المجاورة على امتداد 200 قدم قبل وبعد مركبة طوارئ مرخّصة متوقفة، أو شاحنة قطر، أو مركبة شرطة، أو مركبة مرافق، أو مركبة صيانة طرق تستخدم إشاراتها التحذيرية. المصدر: RCW 46.61.212."},"65":{"q":"على طريق سريع في واشنطن يضم أقل من أربعة مسارات، إذا تعذّر على السائق تغيير المسار بأمان للابتعاد عن مركبة طوارئ/عمل متوقفة، فيجب على السائق خفض السرعة إلى ما لا يقل عن مقدار معيّن دون الحد الأقصى المعلن للسرعة (حيث يكون الحد 60 ميلاً في الساعة أو أقل)؟","options":["5 أميال في الساعة دون الحد المعلن","10 أميال في الساعة دون الحد المعلن","15 ميلاً في الساعة دون الحد المعلن","20 ميلاً في الساعة دون الحد المعلن"],"explanation":"عندما يكون تغيير المسار غير آمن، يشترط قانون \"التزحزح جانباً\" في واشنطن خفض السرعة إلى ما لا يقل عن 10 أميال في الساعة دون الحد المعلن؛ وحيث يتجاوز الحد المعلن 60 ميلاً في الساعة، يجب على السائق بدلاً من ذلك خفض السرعة إلى ما لا يزيد عن 50 ميلاً في الساعة. المصدر: RCW 46.61.212."},"66":{"q":"عند مواجهة حافلة مدرسية متوقفة تعرض أضواء حمراء وامضة بينما تسير أنت في الاتجاه المعاكس، على أي طريق في واشنطن لا يُطلب منك التوقف؟","options":["طريق سريع غير مقسوم بمسارين","طريق سريع مقسوم إلى طرق منفصلة بفاصل أوسط أو حاجز","أي شارع مدينة بسرعة معلنة قدرها 25 ميلاً في الساعة","طريق بمسارين مع مسار انعطاف أوسط ثنائي الاتجاه إلى اليسار"],"explanation":"على طريق سريع مقسوم إلى طرق منفصلة (وفقاً لـ RCW 46.61.150)، أو طريق يضم ثلاثة مسارات معلّمة أو أكثر، لا يلزم السائق الذي يواجه حافلة مدرسية تسير في الاتجاه المعاكس أن يتوقف. أما على الطرق غير المقسومة بمسارين فيجب عليك التوقف. المصدر: RCW 46.61.370."},"67":{"q":"بالإضافة إلى استثناء الطريق المقسوم، على أي نوع آخر من الطرق في واشنطن يجوز لك المتابعة بتجاوز حافلة مدرسية متوقفة قادمة من الاتجاه المعاكس (تسير في الاتجاه المعاكس) دون التوقف؟","options":["طريق يضم ثلاثة مسارات مرورية معلّمة أو أكثر","أي طريق معلن بسرعة 45 ميلاً في الساعة أو أعلى","طريق بأكتاف مرصوفة لا يقل عرضها عن 8 أقدام","طريق بمسار انعطاف أوسط واحد فقط"],"explanation":"يضيف قانون الحافلات المدرسية في واشنطن أن السائقين الذين يواجهون حافلة تسير في الاتجاه المعاكس على طريق سريع يضم ثلاثة مسارات مرورية معلّمة أو أكثر لا يلزمهم التوقف. المصدر: RCW 46.61.370."},"68":{"q":"يتوقف سائق شاحنة في واشنطن على كتف طريق ثنائي المسار ثنائي الاتجاه. بعد تشغيل أضواء التحذير الرباعية، خلال كم دقيقة يجب وضع أجهزة التحذير المطلوبة (المثلثات)؟","options":["5 دقائق","10 دقائق","15 دقيقة","30 دقيقة"],"explanation":"يجب على المركبة التجارية المتوقفة على الطريق أو الكتف وضع أجهزة التحذير من الطوارئ خلال 10 دقائق، بعد تفعيل أضواء التحذير أولاً. المصدر: دليل CDL لواشنطن؛ 49 CFR 392.22 (المعتمد في واشنطن)."},"69":{"q":"على طريق ثنائي المسار ثنائي الاتجاه في واشنطن، أين يجب وضع المثلثات العاكسة الثلاثة لمركبة تجارية متوقفة؟","options":["جميع المثلثات الثلاثة خلف المركبة على بعد 10 و50 و100 قدم","ضمن 10 أقدام على جهة المرور، و100 قدم إلى الخلف، و100 قدم إلى الأمام","على بعد 10 و100 و200 قدم، جميعها نحو المرور القادم","واحد على السقف واثنان على بعد 50 قدماً أماماً وخلفاً"],"explanation":"على طريق ثنائي الاتجاه، ضع مثلثاً واحداً ضمن 10 أقدام من المركبة على جهة المرور، وواحداً على بعد نحو 100 قدم خلفها، وواحداً على بعد نحو 100 قدم أمامها، بحيث يتم تحذير المرور القادم من كلا الاتجاهين. المصدر: دليل CDL لواشنطن؛ 49 CFR 392.22."},"70":{"q":"على طريق مقسوم أو أحادي الاتجاه في واشنطن، أين يجب وضع مثلثات التحذير الثلاثة لمركبة تجارية متوقفة؟","options":["على بعد 10 و100 و200 قدم نحو المرور القادم خلف المركبة","على بعد 10 و50 و100 قدم نحو المرور القادم","واحد في الأمام واثنان على بعد 100 قدم إلى الخلف","جميع المثلثات الثلاثة على بعد 200 قدم خلف المركبة"],"explanation":"على طريق مقسوم أو أحادي الاتجاه، ضع المثلثات نحو المرور القادم على بعد 10 أقدام و100 قدم و200 قدم من المركبة. المصدر: دليل CDL لواشنطن؛ 49 CFR 392.22."},"71":{"q":"تشترط واشنطن على المركبات والمركبات المركّبة التي يزيد وزنها الإجمالي المقنّن عن 10,000 رطل حمل سلاسل إطارات على مسارات الممرات الجبلية المحددة خلال أي فترة من كل عام؟","options":["من 1 أكتوبر إلى 1 مارس","من 1 نوفمبر إلى 1 أبريل","من 1 ديسمبر إلى 31 مارس","من 15 نوفمبر إلى 15 مارس"],"explanation":"من 1 نوفمبر إلى 1 أبريل، يجب على المركبات والمركبات المركّبة التي يزيد وزنها الإجمالي المقنّن عن 10,000 رطل حمل سلاسل على مسارات السلاسل المحددة (مثل I-90، وUS 2 ممر ستيفنز، وUS 12 ممر وايت)، بغض النظر عن الظروف الحالية. المصدر: متطلبات سلاسل المركبات التجارية لـ WSDOT؛ WAC 204-24-050."},"72":{"q":"كم عدد سلاسل الإطارات الإضافية التي يجب على المركبة التجارية في واشنطن التي يزيد وزنها الإجمالي المقنّن عن 10,000 رطل حملها على مسارات السلاسل المحددة خلال موسم حمل السلاسل؟","options":["سلسلة إضافية واحدة على الأقل","سلسلتان إضافيتان على الأقل","أربع سلاسل إضافية على الأقل","لا حاجة لأي إضافية إذا كانت إطارات الدفع مزوّدة بالسلاسل بالفعل"],"explanation":"تشترط واشنطن على هذه المركبات حمل ما لا يقل عن سلسلتي إطارات إضافيتين خلال الفترة من 1 نوفمبر إلى 1 أبريل بحيث يمكن استبدال سلسلة مكسورة أو سلسلة محور إضافي. المصدر: متطلبات السلاسل لـ WSDOT؛ WAC 204-24-050."},"73":{"q":"على طريق متعدد المسارات في واشنطن، ماذا يقول قانون الولاية بشأن مركبة أبطأ تشغل المسار الأيسر باستمرار؟","options":["يُسمح بذلك إذا كانت المركبة تسير بالحد الأقصى للسرعة","تُعد مخالفة مرورية القيادة باستمرار في المسار الأيسر عندما يعيق ذلك حركة المرور الأخرى","يُسمح بذلك فقط للمركبات التي يقل وزنها عن 10,000 رطل","يُسمح بذلك إذا كان المسار الأيمن مشغولاً بالشاحنات"],"explanation":"يجعل قانون \"البقاء يميناً\" في واشنطن القيادة باستمرار في المسار الأيسر من طريق متعدد المسارات مخالفة مرورية عندما يؤدي ذلك إلى إعاقة تدفق حركة المرور الأخرى. المصدر: RCW 46.61.100."},"74":{"q":"عقوبة التجاوز غير القانوني لحافلة مدرسية متوقفة في واشنطن تعرض أضواءها الحمراء ولوحة التوقف موصوفة في القانون بأنها:","options":["غرامة ثابتة قدرها $250 يجوز للمحكمة تخفيضها","ضعف العقوبة الأساسية، التي لا يجوز التنازل عنها أو تخفيضها أو تعليقها","إنذار خطي عند المخالفة الأولى","تعليق الرخصة فقط، دون أي عقوبة مالية"],"explanation":"يُفرض على السائق الذي يتجاوز بصورة غير قانونية حافلة مدرسية متوقفة عقوبة مالية تساوي ضعف العقوبة الأساسية بموجب RCW 46.63.110، ولا يجوز التنازل عنها أو تخفيضها أو تعليقها. المصدر: RCW 46.61.370."},"75":{"q":"عندما تعلن شرطة ولاية واشنطن (Washington State Patrol) عن \"وجوب استخدام السلاسل\" للمركبات التي يزيد وزنها عن 10,000 رطل، هل تستوفي الإطارات المسننة هذا الشرط؟","options":["نعم، تُحتسب الإطارات المسننة كسلاسل","نعم، ولكن فقط على محور الدفع","لا؛ يجب تركيب السلاسل حتى فوق الإطارات المسننة","المركبات ذات الدفع الرباعي فقط هي المعفاة"],"explanation":"لا تستوفي الإطارات المسننة شرط السلاسل المعلن في واشنطن؛ ويجب على السائقين تركيب السلاسل (فوق الإطارات المسننة إن وُجدت) للمتابعة بعد نقطة تركيب السلاسل المعلنة. المصدر: متطلبات السلاسل الشتوية لـ WSDOT/WSP."},"76":{"q":"في واشنطن، يُطلب عموماً تصريح واحد للحمولة الزائدة الحجم/الوزن بمجرد أن تتجاوز المركبة أو الحمولة أياً من حدود الأبعاد القانونية التالية؟","options":["عرض 8 أقدام و6 بوصات، أو ارتفاع 14 قدماً، أو حدود الطول المعمول بها","عرض 10 أقدام، أو ارتفاع 13 قدماً و6 بوصات، أو طول 48 قدماً","عرض 9 أقدام، أو ارتفاع 15 قدماً، أو طول 60 قدماً","عرض 8 أقدام، أو ارتفاع 12 قدماً، أو طول 35 قدماً"],"explanation":"الحدود القانونية في واشنطن هي عموماً عرض 8 أقدام و6 بوصات وارتفاع 14 قدماً؛ وتجاوز العرض أو الارتفاع أو حدود الطول المعمول بها يتطلب تصريح حمولة زائدة الحجم من WSDOT. المصدر: تصاريح الحمولة الزائدة الحجم/الوزن من خدمات المركبات التجارية لـ WSDOT."},"77":{"q":"أي من الطرق السريعة الجبلية يُعد مساراً محدداً للسلاسل/الجر في واشنطن حيث تُطبّق متطلبات سلاسل المركبات التجارية بشكل شائع؟","options":["I-90 عبر ممر سنوكوالمي (Snoqualmie Pass)","I-5 عبر وسط مدينة سياتل","I-405 حول بلفيو (Bellevue)","جسر SR 520 العائم"],"explanation":"يُعد I-90 عبر ممر سنوكوالمي (من نورث بيند إلى إلينسبرغ) مساراً رئيسياً محدداً للسلاسل، إلى جانب US 2 ممر ستيفنز وUS 12 ممر وايت؛ أما الطرق السريعة الحضرية مثل I-5 وI-405 وSR 520 فليست مسارات سلاسل جبلية. المصدر: متطلبات سلاسل الممرات الجبلية لـ WSDOT."},"78":{"q":"عادةً ما يُنشأ منحدر هروب الشاحنات الجامحة على منحدر شديد في واشنطن لإيقاف مركبة ثقيلة عن طريق:","options":["فراش من الحصى السائب أو الرمل الناعم، أحياناً على منحدر صاعد، يزيد المقاومة كلما توغلت أكثر","شبكة من حاجز فولاذي ممدودة عبر المسار","مزلق مرصوف منحدر يتيح للشاحنة الانزلاق حتى التوقف","حوض مملوء بالماء يطفّي الإطارات"],"explanation":"تستخدم منحدرات الهروب في واشنطن حصى سائباً أو رملاً ناعماً، أحياناً مع منحدر صاعد؛ وتزداد المقاومة كلما توغلت الشاحنة أكثر، مما يساعد على إيقافها. المصدر: دليل CDL لواشنطن، القيادة الجبلية / منحدرات الهروب."},"79":{"q":"بموجب قانون \"التزحزح جانباً\" في واشنطن على طريق سريع يضم أربعة مسارات أو أكثر، فإن الواجب الأول للسائق عند الاقتراب من مركبة طوارئ/عمل متوقفة بأضواء وامضة هو:","options":["التوقف تماماً في المسار حتى تمر المركبة","المتابعة بحذر، وخفض السرعة، وتغيير المسار للابتعاد عنها إذا كان ذلك آمناً","إطلاق البوق والحفاظ على السرعة المعلنة","الانتقال إلى الكتف والتجاوز من اليمين"],"explanation":"على الطرق السريعة التي تضم أربعة مسارات أو أكثر، يجب على السائقين المتابعة بحذر، وخفض السرعة، وإفساح الطريق بالتحرك مساراً واحداً بعيداً عن المنطقة عندما يكون ذلك آمناً؛ ولا يخفضون السرعة إلى السرعة المنخفضة المطلوبة إلا إذا كان تغيير المسار غير آمن. المصدر: RCW 46.61.212."},"80":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في واشنطن؟","options":["دائرة الترخيص في ولاية واشنطن (Washington State Department of Licensing - DOL)","شرطة ولاية واشنطن (WSP)","دائرة النقل في ولاية واشنطن (WSDOT)","الإدارة الفيدرالية لسلامة شاحنات النقل (FMCSA)"],"explanation":"في واشنطن، تصدر دائرة الترخيص (DOL) رخص CDL وتدير اختباراتها. المصدر: WA DOL، 'الحصول على رخصة قيادة تجارية (CDL).'"},"81":{"q":"أين يمكن لمتقدم رخصة CDL في واشنطن إجراء اختبار المهارات المطلوب؟","options":["لدى فاحص تابع لـ DOL أو فاحص طرف ثالث مرخّص من DOL (TPE)","فقط في قسم المركبات التجارية بشرطة ولاية واشنطن","فقط عبر الإنترنت من خلال موقع DOL","في أي مدرسة من سجل مزوّدي التدريب التابع لـ FMCSA حسب اختيارك"],"explanation":"يُجرى اختبار مهارات CDL في واشنطن إما بواسطة فاحص تابع لـ DOL أو بواسطة فاحص طرف ثالث مرخّص من DOL (TPE). المصدر: WA DOL، 'اختبار مهارات CDL.'"},"82":{"q":"من كم جزء يتكوّن اختبار مهارات CDL في واشنطن؟","options":["ثلاثة: فحص المركبة (قبل الرحلة)، والتحكم الأساسي بالمركبة، واختبار القيادة على الطريق","اثنان: اختبار كتابي واختبار قيادة على الطريق","أربعة: كتابي، وفحص النظر، وفحص المركبة، واختبار القيادة على الطريق","اختبار قيادة واحد مجمّع على الطريق يشمل كل شيء"],"explanation":"يتكوّن اختبار مهارات CDL في واشنطن من ثلاثة أجزاء تُجرى بالتسلسل: فحص المركبة (قبل الرحلة)، ومهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: WA DOL، 'اختبار مهارات CDL.'"},"83":{"q":"ما مدة صلاحية تصريح المتعلّم التجاري (CLP) في واشنطن اعتباراً من تاريخ إصداره؟","options":["180 يوماً","30 يوماً","سنة واحدة","60 يوماً"],"explanation":"تصريح CLP في واشنطن صالح لمدة 180 يوماً من تاريخ إصداره. المصدر: WA DOL، 'تصريح المتعلّم التجاري (CLP).'"},"84":{"q":"بعد إصدار تصريح CLP في واشنطن، كم يجب على حامله الانتظار قبل إجراء اختبار مهارات CDL؟","options":["14 يوماً تقويمياً","30 يوماً تقويمياً","7 أيام تقويمية","لا يُطلب أي فترة انتظار"],"explanation":"تشترط واشنطن فترة انتظار قدرها 14 يوماً تقويمياً بعد إصدار تصريح CLP أصلي أو مُرقّى قبل أن يتمكن حامله من إجراء اختبار المهارات، بما يتوافق مع القاعدة الفيدرالية لـ CLP. المصدر: WA DOL، 'تصريح المتعلّم التجاري (CLP)' / 'اختبار مهارات CDL.'"},"85":{"q":"قبل إجراء اختبار مهارات CDL في واشنطن، يجب على المتقدم لأول مرة للفئة A أو الفئة B إكمال أي شرط؟","options":["تدريب السائقين المبتدئين (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA","تدريب مهني لمدة أربع سنوات موثّق لدى DOL","دورة قيادة دفاعية معتمدة من شرطة ولاية واشنطن","ندوة للوقاية من غضب الطريق تقدمها WSDOT"],"explanation":"منذ 7 فبراير 2022، يجب على المتقدمين لأول مرة للفئة A/B إكمال تدريب ELDT من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل الاختبار، ولا يمكن لواشنطن إجراء الاختبار حتى يتم التحقق من الإكمال. المصدر: قاعدة ELDT لـ FMCSA؛ WA DOL، 'اختبار مهارات CDL.'"},"86":{"q":"من كم فئة من فئات التصديق الذاتي يجب على متقدم رخصة CDL في واشنطن الاختيار عند تحديد نوع القيادة التي يقوم بها؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"هناك أربع فئات للتصديق الذاتي: بين الولايات غير المستثناة، وبين الولايات المستثناة، وداخل الولاية غير المستثناة، وداخل الولاية المستثناة. المصدر: WA DOL، 'الشهادات الطبية والتصديق الذاتي'؛ 49 CFR 383.71."},"87":{"q":"أي فئة من فئات التصديق الذاتي في واشنطن لا تتطلب من السائق وجود شهادة فاحص طبي في الملف؟","options":["داخل الولاية المستثناة","بين الولايات غير المستثناة","بين الولايات المستثناة","داخل الولاية غير المستثناة"],"explanation":"ثلاث من الفئات الأربع تتطلب شهادة فاحص طبي؛ وحدهم سائقو فئة داخل الولاية المستثناة 'لا تُطلب منهم أي مستندات.' المصدر: WA DOL، 'الشهادات الطبية والتصديق الذاتي.'"},"88":{"q":"بموجب القواعد الحالية في واشنطن/الفيدرالية، كيف تصل عادةً شهادة الفاحص الطبي لـ DOT الخاصة بالسائق إلى DOL؟","options":["يرفعها الفاحص الطبي إلى السجل الوطني، الذي ينقلها بدوره إلى DOL","يرسل السائق دائماً نسخة ورقية بالبريد إلى FMCSA في واشنطن العاصمة","يرسلها صاحب العمل بالفاكس إلى شرطة ولاية واشنطن","تُنشأ الشهادة تلقائياً عند إصدار تصريح CLP"],"explanation":"يرفع الفاحص الطبي المعتمد الشهادة إلى السجل الوطني لـ FMCSA، وتُنقل النتيجة إلى DOL لتحديث سجل السائق. المصدر: WA DOL، 'الشهادات الطبية والتصديق الذاتي.'"},"89":{"q":"بعد أن تستلم DOL المستندات الطبية لرخصة CDL الخاصة بالسائق، كم يستغرق عموماً تحديث سجل السائق؟","options":["7 إلى 10 أيام عمل","1 إلى 2 يوم عمل","30 إلى 45 يوم عمل","في يوم العمل نفسه"],"explanation":"تذكر DOL أن الأمر قد يستغرق من 7 إلى 10 أيام عمل لتحديث السجل بعد استلام المستندات الطبية. المصدر: WA DOL، 'الشهادات الطبية والتصديق الذاتي.'"},"90":{"q":"أي دليل دراسة توجّه دائرة الترخيص (DOL) في واشنطن متقدمي رخصة CDL إلى استخدامه للتحضير لاختبارات المعرفة؟","options":["دليل السائق التجاري لواشنطن (Washington Commercial Driver Guide)","دليل السائق لواشنطن (غير التجاري)","كتيّب الامتثال للمواد الخطرة من FMCSA","دليل سائقي الشاحنات السنوي لواشنطن"],"explanation":"توجّه DOL متقدمي رخصة CDL إلى دراسة دليل السائق التجاري لواشنطن، الذي تقول إنه يحتوي على جميع المعلومات اللازمة لاجتياز الاختبار. المصدر: WA DOL، 'اختبار معرفة CDL.'"},"91":{"q":"بأي لغات تقدم دائرة الترخيص (DOL) في واشنطن اختبار معرفة CDL؟","options":["الإنجليزية والإسبانية والروسية والصربية الكرواتية","الإنجليزية فقط","الإنجليزية والإسبانية فقط","أي لغة، مع مترجم فوري يوفّره المتقدم"],"explanation":"تقدم واشنطن اختبار معرفة CDL باللغات الإنجليزية والإسبانية والروسية والصربية الكرواتية، ولا يُسمح بالمترجمين الفوريين للغات. المصدر: WA DOL، 'اختبار معرفة CDL.'"},"92":{"q":"تغطي رسوم اختبار معرفة CDL في واشنطن محاولة واحدة لكل اختبار معرفة يُجرى ضمن أي فترة زمنية بعد دفعها؟","options":["90 يوماً","30 يوماً","180 يوماً","سنة واحدة"],"explanation":"تغطي رسوم اختبار المعرفة محاولة واحدة لكل اختبار معرفة يُجرى ضمن 90 يوماً من استلامها. المصدر: WA DOL، 'اختبار معرفة CDL.'"},"93":{"q":"أي مستندات يجب على المتقدم في واشنطن إحضارها للتقدم بطلب تصريح CLP؟","options":["رخصة قيادة سارية من واشنطن، وإثبات رقم الضمان الاجتماعي، وإثبات الجنسية الأمريكية أو الإقامة الدائمة القانونية","شهادة ميلاد فقط","جواز سفر وفاتورتي خدمات","تسجيل مركبة وإثبات تأمين"],"explanation":"للتقدم بطلب تصريح CLP، تشترط DOL رخصة قيادة سارية من واشنطن، ورقم الضمان الاجتماعي، وإثبات الجنسية الأمريكية أو الإقامة الدائمة القانونية. المصدر: WA DOL، 'تصريح المتعلّم التجاري (CLP).'"},"94":{"q":"قبل الخضوع للاختبار للحصول على تظهير المواد الخطرة (H) في واشنطن، يجب على المتقدم إكمال أي نوع من تدريب ELDT؟","options":["تدريب نظري (معرفي) من مزوّد في سجل مزوّدي التدريب التابع لـ FMCSA، يُؤخذ قبل اختبار معرفة H","دورة كاملة خلف عجلة القيادة في الميدان وعلى الطريق","لا تدريب على الإطلاق، فقط التحقق من الخلفية","تدريب على الطريق بإشراف شرطة ولاية واشنطن"],"explanation":"بالنسبة لتظهير المواد الخطرة (H)، يكون تدريب ELDT نظرياً فقط ويجب إكماله مع مزوّد في سجل مزوّدي التدريب قبل إجراء اختبار معرفة H الخاص بالولاية. المصدر: قاعدة ELDT لـ FMCSA؛ سجل مزوّدي التدريب لـ FMCSA، 'قابلية تطبيق ELDT.'"},"95":{"q":"كيف تُنظَّم دورة تجديد رخصة CDL القياسية غير المحسّنة في واشنطن؟","options":["يجب تجديدها كل 6 سنوات","يجب تجديدها كل 4 سنوات","يجب تجديدها كل 10 سنوات","لا تنتهي صلاحيتها أبداً بمجرد إصدارها"],"explanation":"تُصدَر رخصة CDL القياسية في واشنطن على دورة مدتها 6 سنوات. المصدر: WA DOL، 'تجديد رخصة CDL.'"},"96":{"q":"قبل كم يمكن للسائق في واشنطن تجديد رخصة CDL قبل انتهاء صلاحيتها؟","options":["حتى سنة واحدة قبل انتهاء صلاحيتها","حتى 6 أشهر قبل انتهاء صلاحيتها","فقط في تاريخ انتهاء الصلاحية بالضبط","حتى 90 يوماً قبل انتهاء صلاحيتها"],"explanation":"تتيح DOL تجديد رخصة CDL حتى سنة واحدة قبل انتهاء صلاحية الرخصة. المصدر: WA DOL، 'تجديد رخصة CDL.'"},"97":{"q":"ماذا يحدث إذا كانت رخصة CDL في واشنطن منتهية الصلاحية لأكثر من 8 سنوات؟","options":["لا يمكن للسائق التجديد ويجب أن يبدأ عملية CDL من جديد","لا يزال بإمكان السائق التجديد عبر الإنترنت مع رسوم تأخير بسيطة","تُعاد الرخصة تلقائياً بعد فحص النظر","يجوز للسائق الاستمرار في القيادة على البطاقة المنتهية لمدة سنة إضافية"],"explanation":"إذا كانت رخصة CDL في واشنطن منتهية الصلاحية لأكثر من 8 سنوات، فلا يمكن تجديدها ويجب على السائق أن يبدأ عملية الترخيص من جديد. المصدر: WA DOL، 'تجديد رخصة CDL.'"},"98":{"q":"كم مرة يمكن تجديد تصريح CLP في واشنطن، وبأي شرط؟","options":["مرة واحدة، إذا جُدّد خلال 30 يوماً من انتهاء صلاحيته، مما يمدده 180 يوماً إضافية","مرات غير محدودة، طالما استمر الحامل في الدراسة","مرتين في السنة التقويمية بغض النظر عن التوقيت","لا يمكن تجديده أبداً؛ يجب إصدار تصريح جديد"],"explanation":"يمكن تجديد تصريح CLP في واشنطن مرة واحدة فقط، خلال 30 يوماً من انتهاء صلاحيته، مما يمدده 180 يوماً إضافية. المصدر: WA DOL، 'تصريح المتعلّم التجاري (CLP).'"},"99":{"q":"في واشنطن، أي أحداث متعلقة برخصة CDL تتطلب تدريب السائقين المبتدئين (ELDT) من مزوّد في سجل مزوّدي التدريب؟","options":["الحصول على أول رخصة CDL من الفئة A أو الفئة B، وترقية الفئة B إلى الفئة A، والحصول على أول تظهير H أو P أو S","فقط الحصول على أول رخصة CDL من الفئة C","فقط تجديد رخصة CDL قائمة","كل إعادة لاختبار المعرفة بعد الرسوب"],"explanation":"ينطبق تدريب ELDT على المتقدمين لأول مرة للفئة A أو الفئة B، وترقيات الفئة B إلى الفئة A، وأول تظهير للمواد الخطرة (H) أو الركاب (P) أو الحافلة المدرسية (S)؛ وتتحقق واشنطن من الإكمال قبل الاختبار. المصدر: سجل مزوّدي التدريب لـ FMCSA، 'قابلية تطبيق ELDT.'"}}};
